// === MICRO ARCADE bundle (auto-generated by build.js — do not edit) ===
(function(){
"use strict";
var __games = [];

// ---- js/core/palette.js ----
// レトロカラーパレット（CRT/ゲームボーイ風）。色数を絞って雰囲気を統一する。
const PALETTES = {
  GREEN: {
    name: 'GREEN CRT',
    bg:   '#0b1a0b', // 背景（暗緑）
    dark: '#10300f', // 影
    dim:  '#1f5d1d', // 弱
    mid:  '#39ff14', // 主役の蛍光グリーン
    fg:   '#9dff7a', // 明
    hi:   '#e8ffe0', // ハイライト
    warn: '#ffd23f', // 警告/アクセント
    bad:  '#ff5b5b', // 敵/失敗
  },
  AMBER: {
    name: 'AMBER',
    bg:   '#1a0f00',
    dark: '#2b1900',
    dim:  '#7a4a00',
    mid:  '#ffb000',
    fg:   '#ffcf63',
    hi:   '#fff0c8',
    warn: '#7af0ff',
    bad:  '#ff5b5b',
  },
};

// 現在のテーマ（メニューから切替可能）
const theme = { current: PALETTES.GREEN };

function P() { return theme.current; }


// ---- js/core/audio.js ----
// 矩形波の短いBEEP音。80年代マイコン風のSE。
// WebAudioはユーザー操作後でないと鳴らせないため、最初の入力でresume()する。
class Audio {
  constructor() {
    this.ctx = null;
    this.enabled = true;
  }

  // 初回のユーザー操作で呼ぶ
  unlock() {
    if (!this.ctx) {
      const AC = window.AudioContext || window.webkitAudioContext;
      if (AC) this.ctx = new AC();
    }
    if (this.ctx && this.ctx.state === 'suspended') this.ctx.resume();
  }

  // freq: 周波数(Hz), dur: 長さ(秒), type: 'square'|'sine'|'triangle'|'sawtooth'
  beep(freq = 440, dur = 0.08, type = 'square', vol = 0.15) {
    if (!this.enabled || !this.ctx) return;
    const t0 = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();
    osc.type = type;
    osc.frequency.setValueAtTime(freq, t0);
    gain.gain.setValueAtTime(vol, t0);
    gain.gain.exponentialRampToValueAtTime(0.0001, t0 + dur);
    osc.connect(gain).connect(this.ctx.destination);
    osc.start(t0);
    osc.stop(t0 + dur);
  }

  // 連続した音階（メロディ/効果音シーケンス）
  sequence(notes) {
    if (!this.enabled || !this.ctx) return;
    let t = 0;
    for (const n of notes) {
      setTimeout(() => this.beep(n.freq, n.dur || 0.08, n.type || 'square', n.vol || 0.15), t * 1000);
      t += (n.gap != null ? n.gap : (n.dur || 0.08));
    }
  }

  // よく使うSE
  move()    { this.beep(220, 0.04, 'square', 0.08); }
  pick()    { this.beep(880, 0.07, 'square', 0.14); }
  good()    { this.sequence([{ freq: 660 }, { freq: 880 }, { freq: 1320 }]); }
  bad()     { this.beep(120, 0.25, 'sawtooth', 0.18); }
  select()  { this.beep(520, 0.05, 'square', 0.12); }
}


// ---- js/core/storage.js ----
// ハイスコア等のローカル保存。localStorageの薄いラッパ。
const PREFIX = 'microarcade.';

const Storage = {
  getHigh(gameId) {
    const v = localStorage.getItem(PREFIX + 'high.' + gameId);
    return v ? parseInt(v, 10) : 0;
  },
  // 新記録なら保存してtrueを返す
  setHigh(gameId, score) {
    const cur = this.getHigh(gameId);
    if (score > cur) {
      localStorage.setItem(PREFIX + 'high.' + gameId, String(score));
      return true;
    }
    return false;
  },
  get(key, def = null) {
    const v = localStorage.getItem(PREFIX + key);
    return v == null ? def : v;
  },
  set(key, val) {
    localStorage.setItem(PREFIX + key, String(val));
  },
};


// ---- js/core/engine.js ----
// MICRO ARCADE エンジン。論理解像度を固定し、スクロールなしで画面にフィットさせる。
// 各ゲームは Scene を継承して enter/update/render/onInput を実装する。

// 論理解像度（全ゲーム共通の座標系）。実際の表示はこれを拡大縮小する。
const W = 360;
const H = 640;

// シーン基底クラス。これが「ゲーム実装の契約」。
class Scene {
  constructor(engine) {
    this.engine = engine;
  }
  enter() {}                 // シーン開始時の初期化
  exit() {}                  // シーン終了時の後始末
  update(dt) {}              // 毎フレームのロジック（dt: 秒）
  render(ctx) {}             // 毎フレームの描画
  // action: 'up'|'down'|'left'|'right'|'tap'|'confirm'|'back'
  // data: tapの場合 {x,y}（論理座標）
  onInput(action, data) {}
}

class Engine {
  constructor(canvas) {
    this.canvas = canvas;
    this.ctx = canvas.getContext('2d');
    this.audio = new Audio();
    this.storage = Storage;
    this.scene = null;
    this.last = 0;
    this.scale = 1;
    this.offsetX = 0;
    this.offsetY = 0;
    // 全ゲーム共通の「メニューへ戻る」ボタン（左上）。各ゲームは左上HUDを x>=52 から描く。
    this.backBtn = { x: 6, y: 8, w: 42, h: 36 };
    // 押しっぱなし状態（LANDER等の連続操作用）。論理座標。update内で毎フレーム参照できる。
    this.pointer = { down: false, x: 0, y: 0 };
    this._resize = this._resize.bind(this);
    this._loop = this._loop.bind(this);
    this._setupInput();
    window.addEventListener('resize', this._resize);
    this._resize();
  }

  // 画面サイズに合わせてキャンバスを拡大（アスペクト比維持・スクロールなし）
  _resize() {
    const dpr = window.devicePixelRatio || 1;
    const vw = window.innerWidth;
    const vh = window.innerHeight;
    this.scale = Math.min(vw / W, vh / H);
    const cssW = Math.floor(W * this.scale);
    const cssH = Math.floor(H * this.scale);
    this.canvas.style.width = cssW + 'px';
    this.canvas.style.height = cssH + 'px';
    this.canvas.width = Math.floor(W * this.scale * dpr);
    this.canvas.height = Math.floor(H * this.scale * dpr);
    this.ctx.setTransform(this.scale * dpr, 0, 0, this.scale * dpr, 0, 0);
    this.ctx.imageSmoothingEnabled = false; // ドット絵をクッキリ
    this.offsetX = (vw - cssW) / 2;
    this.offsetY = (vh - cssH) / 2;
  }

  changeScene(scene) {
    if (this.scene && this.scene.exit) this.scene.exit();
    this.scene = scene;
    if (scene.enter) scene.enter();
  }

  start(scene) {
    this.changeScene(scene);
    this.last = performance.now();
    requestAnimationFrame(this._loop);
  }

  _loop(now) {
    let dt = (now - this.last) / 1000;
    if (dt > 0.1) dt = 0.1; // タブ復帰時の暴走防止
    this.last = now;
    const ctx = this.ctx;
    // 背景クリア
    ctx.fillStyle = P().bg;
    ctx.fillRect(0, 0, W, H);
    if (this.scene) {
      // 1ゲームの例外でループ全体（＝アプリ）が停止しないよう保護する
      try {
        this.scene.update(dt);
        this.scene.render(ctx);
        if (!this.scene.isRoot) this._drawBack(); // メニュー以外はBACKボタンを上に重ねる
      } catch (e) {
        console.error('[scene error]', e);
      }
    }
    requestAnimationFrame(this._loop); // 例外があっても次フレームは必ず予約する
  }

  // ---- 入力 ----
  _setupInput() {
    const dispatch = (action, data) => {
      this.audio.unlock();
      // BACKボタンのタップはゲームに渡さず、メニューへ戻す（メニュー画面では無効）
      if (action === 'tap' && data && this.scene && !this.scene.isRoot && this._inBack(data)) {
        this.audio.select();
        if (this.toMenu) this.toMenu();
        return;
      }
      if (this.scene && this.scene.onInput) this.scene.onInput(action, data);
    };

    // キーボード
    window.addEventListener('keydown', (e) => {
      const k = e.key;
      if (k === 'ArrowUp' || k === 'w') { dispatch('up'); e.preventDefault(); }
      else if (k === 'ArrowDown' || k === 's') { dispatch('down'); e.preventDefault(); }
      else if (k === 'ArrowLeft' || k === 'a') { dispatch('left'); e.preventDefault(); }
      else if (k === 'ArrowRight' || k === 'd') { dispatch('right'); e.preventDefault(); }
      else if (k === 'Enter' || k === ' ') { dispatch('confirm'); e.preventDefault(); }
      else if (k === 'Escape' || k === 'Backspace') { dispatch('back'); e.preventDefault(); }
    });

    // タッチ／マウス（スワイプ判定＋タップ）
    const SWIPE = 24; // スワイプとみなす最小移動量(px CSS)
    let sx = 0, sy = 0, st = 0, moved = false;
    const toLogical = (clientX, clientY) => {
      const r = this.canvas.getBoundingClientRect();
      return {
        x: (clientX - r.left) / this.scale,
        y: (clientY - r.top) / this.scale,
      };
    };
    const setPointer = (clientX, clientY, isDown) => {
      const lp = toLogical(clientX, clientY);
      this.pointer.x = lp.x; this.pointer.y = lp.y;
      if (isDown != null) this.pointer.down = isDown;
    };
    const onStart = (x, y) => { sx = x; sy = y; st = performance.now(); moved = false; setPointer(x, y, true); };
    const onMove = (x, y) => { setPointer(x, y, null); };
    const onEnd = (x, y) => {
      setPointer(x, y, false);
      const dx = x - sx, dy = y - sy;
      const adx = Math.abs(dx), ady = Math.abs(dy);
      if (adx < SWIPE && ady < SWIPE) {
        dispatch('tap', toLogical(x, y)); // タップ
      } else if (adx > ady) {
        dispatch(dx > 0 ? 'right' : 'left');
      } else {
        dispatch(dy > 0 ? 'down' : 'up');
      }
    };

    const c = this.canvas;
    c.addEventListener('touchstart', (e) => {
      const t = e.changedTouches[0]; onStart(t.clientX, t.clientY);
      e.preventDefault();
    }, { passive: false });
    c.addEventListener('touchmove', (e) => {
      const t = e.changedTouches[0]; onMove(t.clientX, t.clientY);
      e.preventDefault();
    }, { passive: false });
    c.addEventListener('touchend', (e) => {
      const t = e.changedTouches[0]; onEnd(t.clientX, t.clientY);
      e.preventDefault();
    }, { passive: false });

    // マウス（PC確認用）
    let down = false;
    c.addEventListener('mousedown', (e) => { down = true; onStart(e.clientX, e.clientY); });
    c.addEventListener('mousemove', (e) => { if (down) onMove(e.clientX, e.clientY); });
    c.addEventListener('mouseup', (e) => { if (down) onEnd(e.clientX, e.clientY); down = false; });
  }

  // タップ座標がBACKボタン内か
  _inBack(data) {
    const b = this.backBtn;
    return data.x >= b.x && data.x <= b.x + b.w && data.y >= b.y && data.y <= b.y + b.h;
  }

  // BACKボタン描画（左上・全ゲーム共通）
  _drawBack() {
    const p = P();
    const b = this.backBtn;
    this.rect(b.x, b.y, b.w, b.h, p.dark);
    this.stroke(b.x, b.y, b.w, b.h, p.dim, 2);
    this.text('‹', b.x + b.w / 2, b.y + 4, 26, p.fg, 'center');
  }

  // ---- 描画ヘルパー（各ゲームから利用）----

  // ビットマップ風テキスト。align: 'left'|'center'|'right'
  text(str, x, y, size = 16, color = null, align = 'left') {
    const ctx = this.ctx;
    ctx.fillStyle = color || P().mid;
    ctx.font = `${size}px "DotGothic16", monospace`;
    ctx.textAlign = align;
    ctx.textBaseline = 'top';
    ctx.fillText(str, x, y);
  }

  // 角丸なしの矩形（塗り）
  rect(x, y, w, h, color) {
    this.ctx.fillStyle = color;
    this.ctx.fillRect(x, y, w, h);
  }

  // 枠線
  stroke(x, y, w, h, color, lw = 2) {
    const ctx = this.ctx;
    ctx.strokeStyle = color;
    ctx.lineWidth = lw;
    ctx.strokeRect(x, y, w, h);
  }
}


// ---- js/menu.js ----
// タイトル＆ゲーム選択メニュー。8本を2列グリッドで1画面に収める（スクロールなし）。

const COLS = 2;
const MARGIN = 16;
const GAP = 12;
const TILE_W = (W - MARGIN * 2 - GAP) / COLS;  // 158
const TILE_H = 96;
const TOP = 100;
const PITCH = TILE_H + 12;

class MenuScene extends Scene {
  constructor(engine, games) {
    super(engine);
    this.games = games;       // [{ meta, Game }]
    this.sel = 0;
    this.t = 0;
    this.isRoot = true;       // 最上位＝BACKボタン非表示
  }

  enter() {
    this.tiles = this._layout();
    this.themeIndex = this.games.length;
  }

  // 各タイル／テーマ行のヒット領域を計算
  _layout() {
    const tiles = [];
    this.games.forEach((g, i) => {
      const col = i % COLS, row = Math.floor(i / COLS);
      tiles.push({
        index: i,
        x: MARGIN + col * (TILE_W + GAP),
        y: TOP + row * PITCH,
        w: TILE_W, h: TILE_H,
      });
    });
    const rows = Math.ceil(this.games.length / COLS);
    this.themeRect = { x: MARGIN, y: TOP + rows * PITCH, w: W - MARGIN * 2, h: 34 };
    return tiles;
  }

  onInput(action, data) {
    const max = this.games.length; // = テーマ行のindex
    if (action === 'right') { this.sel = Math.min(this.sel + 1, max); this.engine.audio.select(); }
    else if (action === 'left') { this.sel = Math.max(this.sel - 1, 0); this.engine.audio.select(); }
    else if (action === 'down') { this.sel = Math.min(this.sel + COLS, max); this.engine.audio.select(); }
    else if (action === 'up') { this.sel = Math.max(this.sel - COLS, 0); this.engine.audio.select(); }
    else if (action === 'confirm') { this._activate(this.sel); }
    else if (action === 'tap') {
      for (const tile of this.tiles) {
        if (this._hit(tile, data)) { this._activate(tile.index); return; }
      }
      if (this._hit(this.themeRect, data)) { this._activate(this.themeIndex); }
    }
  }

  _hit(r, d) { return d.x >= r.x && d.x <= r.x + r.w && d.y >= r.y && d.y <= r.y + r.h; }

  _activate(i) {
    if (i < this.games.length) {
      this.engine.audio.good();
      this.engine.startGame(this.games[i]);
    } else {
      theme.current = theme.current === PALETTES.GREEN ? PALETTES.AMBER : PALETTES.GREEN;
      this.engine.audio.select();
    }
  }

  update(dt) { this.t += dt; }

  render(ctx) {
    const p = P();
    // タイトル
    this.engine.text('MICRO ARCADE', W / 2, 36, 30, p.mid, 'center');
    if (Math.floor(this.t * 2) % 2 === 0)
      this.engine.text('▼ SELECT GAME ▼', W / 2, 74, 12, p.dim, 'center');

    // ゲームタイル
    this.games.forEach((g, i) => {
      const tile = this.tiles[i];
      const on = this.sel === i;
      const cx = tile.x + tile.w / 2;
      this.engine.rect(tile.x, tile.y, tile.w, tile.h, on ? p.dark : p.bg);
      this.engine.stroke(tile.x, tile.y, tile.w, tile.h, on ? p.mid : p.dim, on ? 2 : 1);
      const hi = this.engine.storage.getHigh(g.meta.id);
      this.engine.text(g.meta.glyph || '?', cx, tile.y + 10, 30, on ? p.hi : p.mid, 'center');
      this.engine.text(g.meta.title, cx, tile.y + 50, 14, on ? p.hi : p.fg, 'center');
      this.engine.text('HI ' + hi, cx, tile.y + 72, 11, p.warn, 'center');
    });

    // テーマ切替
    const tr = this.themeRect;
    const ton = this.sel === this.themeIndex;
    if (ton) { this.engine.rect(tr.x, tr.y, tr.w, tr.h, p.dark); this.engine.stroke(tr.x, tr.y, tr.w, tr.h, p.mid, 2); }
    this.engine.text((ton ? '> ' : '') + 'THEME: ' + p.name, W / 2, tr.y + 9, 14, ton ? p.hi : p.mid, 'center');

    this.engine.text('TAP / SWIPE / ARROWS', W / 2, H - 24, 11, p.dim, 'center');
  }
}


// ---- js/games/rogue.js ----
(function(){
// 1-BIT HERO : 1画面ミニ・ローグライク
// @を動かして鍵Kを取り、出口Dへ。敵Eに触れると死亡。1プレイ数十秒、死んだら即リトライ。
// ★このファイルは「ゲーム実装の手本」。他ゲームも同じ形（meta + Game extends Scene）で作る。

const meta = {
  id: 'rogue',
  title: '1-BIT HERO',
  desc: '鍵を取り出口へ。敵を避けろ',
  glyph: '@',
};

const COLS = 9;
const ROWS = 12;
const CELL = 40;                 // 360 / 9
const GRID_Y = 96;               // グリッド開始Y（上にHUD）
const GRID_X = 0;

class Game extends Scene {
  enter() {
    this.score = 0;
    this.level = 1;
    this.high = this.engine.storage.getHigh(meta.id);
    this.dead = false;
    this.msg = 'SWIPE TO MOVE';
    this._build();
  }

  // レベル生成。到達可能性をBFSで保証する。
  _build() {
    const enemyCount = Math.min(1 + Math.floor(this.level / 2), 6);
    let tries = 0;
    do {
      tries++;
      this.walls = [];
      for (let y = 0; y < ROWS; y++) {
        this.walls[y] = [];
        for (let x = 0; x < COLS; x++) {
          // 外周は壁、内側はランダム
          const edge = (x === 0 || y === 0 || x === COLS - 1 || y === ROWS - 1);
          this.walls[y][x] = edge ? true : Math.random() < 0.20;
        }
      }
      this.player = { x: 1, y: ROWS - 2 };
      this.door = { x: COLS - 2, y: 1 };
      this.key = this._randFloor([this.player, this.door]);
      this.walls[this.player.y][this.player.x] = false;
      this.walls[this.door.y][this.door.x] = false;
      if (this.key) this.walls[this.key.y][this.key.x] = false;
    } while ((!this.key || !this._reachable(this.player, [this.key, this.door])) && tries < 40);

    // 敵配置（プレイヤーから離れた床）
    this.enemies = [];
    for (let i = 0; i < enemyCount; i++) {
      const e = this._randFloor([this.player, this.door, this.key, ...this.enemies], 4);
      if (e) this.enemies.push(e);
    }
    this.hasKey = false;
  }

  _randFloor(avoid = [], minDist = 0) {
    for (let t = 0; t < 100; t++) {
      const x = 1 + Math.floor(Math.random() * (COLS - 2));
      const y = 1 + Math.floor(Math.random() * (ROWS - 2));
      if (this.walls[y][x]) continue;
      let ok = true;
      for (const a of avoid) {
        if (!a) continue;
        if (a.x === x && a.y === y) { ok = false; break; }
        if (minDist && Math.abs(a.x - x) + Math.abs(a.y - y) < minDist) { ok = false; break; }
      }
      if (ok) return { x, y };
    }
    return null;
  }

  // startから targets 全てに到達できるか
  _reachable(start, targets) {
    const seen = new Set();
    const q = [start];
    seen.add(start.x + ',' + start.y);
    while (q.length) {
      const c = q.shift();
      for (const [dx, dy] of [[0,-1],[0,1],[-1,0],[1,0]]) {
        const nx = c.x + dx, ny = c.y + dy;
        if (nx < 0 || ny < 0 || nx >= COLS || ny >= ROWS) continue;
        if (this.walls[ny][nx]) continue;
        const k = nx + ',' + ny;
        if (seen.has(k)) continue;
        seen.add(k); q.push({ x: nx, y: ny });
      }
    }
    return targets.every(t => t && seen.has(t.x + ',' + t.y));
  }

  onInput(action) {
    if (this.dead) {
      if (action === 'tap' || action === 'confirm' || action === 'back') {
        if (action === 'back') return this.engine.toMenu();
        this.enter(); // リトライ
      }
      return;
    }
    if (action === 'back') return this.engine.toMenu();
    let dx = 0, dy = 0;
    if (action === 'up') dy = -1;
    else if (action === 'down') dy = 1;
    else if (action === 'left') dx = -1;
    else if (action === 'right') dx = 1;
    else return;
    this._step(dx, dy);
  }

  _step(dx, dy) {
    const nx = this.player.x + dx, ny = this.player.y + dy;
    if (this.walls[ny][nx]) { this.engine.audio.bad(); return; }
    this.player.x = nx; this.player.y = ny;
    this.engine.audio.move();

    // 鍵取得
    if (this.key && this.player.x === this.key.x && this.player.y === this.key.y) {
      this.hasKey = true; this.key = null; this.msg = 'GOT KEY! GO TO D';
      this.engine.audio.pick();
    }
    // 出口
    if (this.player.x === this.door.x && this.player.y === this.door.y) {
      if (this.hasKey) {
        this.score += 10 * this.level; this.level++;
        this.engine.audio.good(); this.msg = 'LEVEL ' + this.level;
        this._build(); return;
      } else { this.msg = 'NEED KEY!'; }
    }
    // 敵移動：検知範囲内ならプレイヤーを追跡、範囲外はランダム徘徊
    const detectRange = 4 + Math.floor(this.level / 3); // レベルが上がるほど検知範囲が広がる
    for (const e of this.enemies) {
      const dist = Math.abs(this.player.x - e.x) + Math.abs(this.player.y - e.y);
      if (dist <= detectRange) {
        // 追跡モード：X優先で1マス近づく
        const ex = e.x + Math.sign(this.player.x - e.x);
        const ey = e.y + Math.sign(this.player.y - e.y);
        if (!this.walls[e.y][ex] && ex !== e.x) e.x = ex;
        else if (!this.walls[ey][e.x] && ey !== e.y) e.y = ey;
      } else {
        // 徘徊モード：ランダムな直交方向に1マス移動（25%で停止）
        if (Math.random() < 0.25) continue; // 止まる
        const dirs = [[0,-1],[0,1],[-1,0],[1,0]];
        // シャッフル
        for (let i = dirs.length - 1; i > 0; i--) {
          const j = Math.floor(Math.random() * (i + 1));
          [dirs[i], dirs[j]] = [dirs[j], dirs[i]];
        }
        for (const [ddx, ddy] of dirs) {
          const nx = e.x + ddx, ny = e.y + ddy;
          if (nx >= 0 && ny >= 0 && nx < COLS && ny < ROWS && !this.walls[ny][nx]) {
            e.x = nx; e.y = ny; break;
          }
        }
      }
    }
    this._checkDeath();
  }

  _checkDeath() {
    for (const e of this.enemies) {
      if (e.x === this.player.x && e.y === this.player.y) {
        this.dead = true;
        this.engine.audio.bad();
        if (this.engine.storage.setHigh(meta.id, this.score)) this.high = this.score;
        this.msg = 'YOU DIED';
        return;
      }
    }
  }

  render(ctx) {
    const p = P();
    // HUD（左上はBACKボタンが x:6..48 を占有するため x>=52 から描く）
    this.engine.text('1-BIT HERO', 52, 14, 18, p.fg, 'left');
    this.engine.text('LV ' + this.level, W - 12, 14, 16, p.fg, 'right');
    this.engine.text('SCORE ' + this.score, 52, 44, 14, p.mid, 'left');
    this.engine.text('HI ' + this.high, W - 12, 44, 14, p.dim, 'right');

    // グリッド
    for (let y = 0; y < ROWS; y++) {
      for (let x = 0; x < COLS; x++) {
        const px = GRID_X + x * CELL, py = GRID_Y + y * CELL;
        if (this.walls[y][x]) {
          this.engine.rect(px + 2, py + 2, CELL - 4, CELL - 4, p.dark);
          this.engine.text('#', px + CELL / 2, py + 8, 22, p.dim, 'center');
        }
      }
    }
    const glyph = (gx, gy, ch, color) =>
      this.engine.text(ch, GRID_X + gx * CELL + CELL / 2, GRID_Y + gy * CELL + 6, 26, color, 'center');

    if (this.key) glyph(this.key.x, this.key.y, 'K', p.warn);
    glyph(this.door.x, this.door.y, 'D', this.hasKey ? p.fg : p.dim);
    for (const e of this.enemies) glyph(e.x, e.y, 'E', p.bad);
    glyph(this.player.x, this.player.y, '@', p.hi);

    // フッターメッセージ
    this.engine.text(this.msg, W / 2, H - 56, 16, p.fg, 'center');

    if (this.dead) {
      this.engine.rect(0, H / 2 - 70, W, 140, p.dark);
      this.engine.text('YOU DIED', W / 2, H / 2 - 50, 32, p.bad, 'center');
      this.engine.text('SCORE ' + this.score, W / 2, H / 2 - 6, 18, p.fg, 'center');
      this.engine.text('TAP TO RETRY', W / 2, H / 2 + 28, 14, p.mid, 'center');
    }
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/binary.js ----
(function(){
// BINARY : 2進数タイムアタック
// 目標の10進数を6ビットで作れ！タップでビットを切り替え、一致したらクリア。
// タイマーが尽きる前にできるだけ多くの目標をクリアせよ。

const meta = {
  id: 'binary',
  title: 'BINARY',
  desc: '目標の数を2進数で作れ',
  glyph: '01',
};

// ---- 定数 ----
const BITS       = 6;                    // ビット数（最大63）
const PLACE_VAL  = [32, 16, 8, 4, 2, 1]; // 左から右へ

const INIT_TIME  = 16;                   // 初期タイマー（秒）— より余裕を持たせる
const ADD_TIME   = 5;                    // 正解時に追加する秒数（増量）
const TIME_CAP   = 30;                   // タイマー上限（秒）— 連続正解でも30秒まで

// HUDとレイアウト
const HUD_H      = 90;                   // HUD高さ
const TARGET_Y   = 98;                   // "TARGET" ラベル Y
const TARGET_NUM_Y = 122;                // 目標数字 Y
const EQUALS_Y   = 230;                  // "= XX" 表示 Y
const BITS_Y     = 280;                  // ビットボックス行 Y
const TIMER_BAR_Y = 560;                 // タイマーバー Y
const TIMER_BAR_H = 18;                  // タイマーバー高さ

// ビットボックス: 6個を横幅360にフィット。左右マージンを最小にする。
const BOX_W      = 52;
const BOX_H      = 72;
const BOX_GAP    = 4;
const BOX_ROW_W  = BOX_W * BITS + BOX_GAP * (BITS - 1); // 52*6 + 4*5 = 332
const BOX_X0     = Math.round((W - BOX_ROW_W) / 2);     // 14

// ---- ユーティリティ ----
function randTarget(exclude) {
  // 1..63 からexcludeを除いてランダムに選ぶ
  let v;
  do { v = 1 + Math.floor(Math.random() * 63); } while (v === exclude);
  return v;
}

function bitsToDecimal(bits) {
  let n = 0;
  for (let i = 0; i < BITS; i++) n += bits[i] * PLACE_VAL[i];
  return n;
}

// ---- ゲームクラス ----
class Game extends Scene {
  enter() {
    this.score    = 0;
    this.level    = 1;
    this.high     = this.engine.storage.getHigh(meta.id);
    this.over     = false;
    this.timer    = INIT_TIME;
    this.bits     = new Array(BITS).fill(0);  // 全ビット0
    this.target   = randTarget(-1);           // 最初の目標
    this.cursor   = 0;                        // キーボード用カーソル（左右で移動）
    this.flash    = 0;                        // 正解フラッシュ残り時間（秒）
  }

  // ---- ロジック ----
  update(dt) {
    if (this.over) return;

    // フラッシュカウントダウン
    if (this.flash > 0) this.flash -= dt;

    // タイマーカウントダウン
    this.timer -= dt;
    if (this.timer <= 0) {
      this.timer = 0;
      this._gameOver();
    }
  }

  _toggleBit(i) {
    this.bits[i] ^= 1;
    this.engine.audio.beep(this.bits[i] ? 880 : 440, 0.06, 'square', 0.18);
    this._checkMatch();
  }

  _checkMatch() {
    if (bitsToDecimal(this.bits) === this.target) {
      this.engine.audio.good();
      this.score += this.level;
      this.level++;
      // タイマー追加（上限あり）
      this.timer = Math.min(this.timer + ADD_TIME, TIME_CAP);
      // フラッシュ演出
      this.flash = 0.35;
      // 新しい目標、ビットをリセット
      this.target = randTarget(this.target);
      this.bits.fill(0);
      // ハイスコア更新
      if (this.engine.storage.setHigh(meta.id, this.score)) {
        this.high = this.score;
      }
    }
  }

  _gameOver() {
    this.over = true;
    this.engine.audio.bad();
    if (this.engine.storage.setHigh(meta.id, this.score)) {
      this.high = this.score;
    }
  }

  // ---- 入力 ----
  onInput(action, data) {
    if (this.over) {
      if (action === 'back') return this.engine.toMenu();
      if (action === 'tap' || action === 'confirm') return this.enter();
      return;
    }
    if (action === 'back') return this.engine.toMenu();

    if (action === 'tap') {
      // どのビットボックスをタップしたか判定
      const tx = data.x;
      const ty = data.y;
      for (let i = 0; i < BITS; i++) {
        const bx = BOX_X0 + i * (BOX_W + BOX_GAP);
        const by = BITS_Y;
        if (tx >= bx && tx <= bx + BOX_W && ty >= by && ty <= by + BOX_H) {
          this._toggleBit(i);
          return;
        }
      }
      return;
    }

    // キーボード: 左右でカーソル移動、confirm/up/downでトグル
    if (action === 'left') {
      this.cursor = (this.cursor - 1 + BITS) % BITS;
      this.engine.audio.move();
      return;
    }
    if (action === 'right') {
      this.cursor = (this.cursor + 1) % BITS;
      this.engine.audio.move();
      return;
    }
    if (action === 'confirm' || action === 'up' || action === 'down') {
      this._toggleBit(this.cursor);
      return;
    }
  }

  // ---- 描画 ----
  render(ctx) {
    const p = P();

    // ---------- HUD ----------
    this.engine.text('BINARY', 52, 12, 20, p.fg, 'left');  // BACKボタン(~x48)の右から開始
    this.engine.text('LV ' + this.level, W - 12, 12, 16, p.fg, 'right');
    this.engine.text('SCORE ' + this.score, 52, 42, 14, p.mid, 'left');
    this.engine.text('HI ' + this.high, W - 12, 42, 14, p.dim, 'right');

    // HUD区切り線
    this.engine.rect(0, HUD_H - 2, W, 2, p.dark);

    // ---------- 目標表示 ----------
    this.engine.text('TARGET', W / 2, TARGET_Y, 14, p.dim, 'center');

    // 正解フラッシュ: 目標数字をhi色で強調
    const targetColor = (this.flash > 0) ? p.hi : p.warn;
    this.engine.text('' + this.target, W / 2, TARGET_NUM_Y, 64, targetColor, 'center');

    // ---------- ビットボックス ----------
    const currentVal = bitsToDecimal(this.bits);

    for (let i = 0; i < BITS; i++) {
      const bx = BOX_X0 + i * (BOX_W + BOX_GAP);
      const by = BITS_Y;
      const isOn = this.bits[i] === 1;
      const isCursor = (i === this.cursor);

      // ボックス背景
      const boxBg = isOn ? p.dim : p.dark;
      this.engine.rect(bx, by, BOX_W, BOX_H, boxBg);

      // カーソル枠（キーボード用）
      const borderColor = isCursor ? p.fg : (isOn ? p.mid : p.dim);
      const borderWidth = isCursor ? 3 : 2;
      this.engine.stroke(bx, by, BOX_W, BOX_H, borderColor, borderWidth);

      // ビット値（0 or 1）
      const bitColor = isOn ? p.hi : p.dim;
      this.engine.text('' + this.bits[i], bx + BOX_W / 2, by + 12, 28, bitColor, 'center');

      // 桁の重み（小さく下に）
      this.engine.text('' + PLACE_VAL[i], bx + BOX_W / 2, by + BOX_H - 20, 12, p.dim, 'center');
    }

    // ---------- 現在値 = XX ----------
    const eqColor = (currentVal === this.target) ? p.hi : p.fg;
    this.engine.text('= ' + currentVal, W / 2, EQUALS_Y, 30, eqColor, 'center');

    // 一致ヒント矢印
    if (currentVal === this.target && !this.over) {
      this.engine.text('OK!', W / 2, EQUALS_Y + 36, 16, p.hi, 'center');
    }

    // ---------- タイマーバー ----------
    const ratio = this.timer / INIT_TIME;       // 0..1 以上になる場合もあるのでclamp
    const clampedRatio = Math.min(1, Math.max(0, ratio));
    const barMaxW = W - 24;                     // 左右12pxマージン

    // バー背景
    this.engine.rect(12, TIMER_BAR_Y, barMaxW, TIMER_BAR_H, p.dark);

    // バー本体（残り時間に応じて色を変える）
    let barColor = p.mid;
    if (clampedRatio < 0.25) barColor = p.bad;
    else if (clampedRatio < 0.5) barColor = p.warn;
    const barW = Math.round(barMaxW * clampedRatio);
    if (barW > 0) this.engine.rect(12, TIMER_BAR_Y, barW, TIMER_BAR_H, barColor);

    // バー枠線
    this.engine.stroke(12, TIMER_BAR_Y, barMaxW, TIMER_BAR_H, p.dim, 1);

    // タイマー数値
    const timerLabel = this.timer.toFixed(1);
    this.engine.text(timerLabel, W / 2, TIMER_BAR_Y - 22, 16, barColor, 'center');

    // ---------- ゲームオーバーオーバーレイ ----------
    if (this.over) {
      // 半透明背景（bg色で塗りつぶし）
      this.engine.rect(0, H / 2 - 90, W, 180, p.dark);
      this.engine.stroke(12, H / 2 - 90, W - 24, 180, p.dim, 2);

      this.engine.text('GAME OVER', W / 2, H / 2 - 68, 32, p.bad, 'center');
      this.engine.text('SCORE ' + this.score, W / 2, H / 2 - 24, 20, p.fg, 'center');
      if (this.score === this.high && this.score > 0) {
        this.engine.text('NEW RECORD!', W / 2, H / 2 + 10, 16, p.warn, 'center');
      }
      this.engine.text('TAP TO RETRY', W / 2, H / 2 + 42, 14, p.mid, 'center');
    }
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/hack.js ----
(function(){
// HACK : コードブレーカー × リアクションスピード
// グリッドから「DECRYPT」ターゲットを見つけてタップせよ。
// 全10ラウンド固定。タイムアウトなし。反応速度でスコアを競う。
// 速くタップするほど高得点。誤タップは減点なし（時間ロスで自然にスコアが下がる）。

const meta = {
  id: 'hack',
  title: 'HACK',
  desc: '一致コードを素早くタップ',
  glyph: '#',
};

// ---- レイアウト定数 ----
const COLS        = 4;           // グリッド列数
const ROWS        = 5;           // グリッド行数（20セル固定）
const CELL_W      = 84;          // セル幅  (360 / 4 = 90 → 余白込みで84)
const CELL_H      = 60;          // セル高さ
const GRID_X      = 12;          // グリッド左端
const GRID_Y      = 210;         // グリッド上端（HUDの下）
const CELL_GAP_X  = 6;           // 横間隔
const CELL_GAP_Y  = 6;           // 縦間隔

// ---- ゲームパラメータ ----
const TOTAL_ROUNDS  = 10;        // 全ラウンド数（固定）
const FLASH_DUR     = 0.22;      // フラッシュ持続秒
const SCORE_MAX     = 1000;      // 1ラウンドの最高得点
const SCORE_MIN     = 50;        // 1ラウンドの最低得点（どんなに遅くても）
// 反応時間スコア計算: score = max(SCORE_MIN, SCORE_MAX - elapsed * SCORE_DECAY)
// 例) 0秒→1000点、5秒→500点、10秒以上→50点
const SCORE_DECAY   = 95;        // 1秒あたりの減点量
const FLASH_GAIN_DUR = 0.7;      // "+NNN" 表示の持続秒

// 16進コード生成に使う文字
const HEX_CHARS = '0123456789ABCDEF';

// バックグラウンドに流す片仮名ノイズ文字（ハッカー演出）
const NOISE_CHARS = 'アイウエオカキクケコサシスセソタチツテトナニヌネノハヒフヘホ0123456789ABCDEF';
const NOISE_COUNT = 30;

// ランダム 2文字 hex コード
function randCode() {
  return HEX_CHARS[Math.floor(Math.random() * 16)] +
         HEX_CHARS[Math.floor(Math.random() * 16)];
}

class Game extends Scene {
  enter() {
    this.score      = 0;           // 累計スコア
    this.round      = 0;           // 現在ラウンド（0始まり、TOTAL_ROUNDSで終了）
    this.high       = this.engine.storage.getHigh(meta.id);
    this.over       = false;       // リザルト画面フラグ
    this.elapsed    = 0;           // 現在ラウンドの経過時間（秒）

    // フラッシュ状態 { idx, t, good }
    this.flash      = null;

    // "+NNN" 得点フラッシュ { text, t }
    this.gainFlash  = null;

    // ノイズ粒子
    this._initNoise();

    // 最初のラウンド開始
    this._newRound();
  }

  // ---- ノイズ粒子初期化 ----
  _initNoise() {
    this.noise = [];
    for (let i = 0; i < NOISE_COUNT; i++) {
      this.noise.push(this._makeNoisePart());
    }
  }

  _makeNoisePart() {
    return {
      x: Math.random() * W,
      y: Math.random() * H,
      ch: NOISE_CHARS[Math.floor(Math.random() * NOISE_CHARS.length)],
      speed: 18 + Math.random() * 40,   // px/s
      age: Math.random() * 4,
    };
  }

  // ---- グリッド生成（ターゲットがグリッド内に必ず1つ） ----
  _newRound() {
    // 全セルにユニークコードを割り当てる（ターゲット重複を防ぐため）
    const total = COLS * ROWS;
    const used = new Set();
    const codes = [];
    while (codes.length < total) {
      const c = randCode();
      if (!used.has(c)) { used.add(c); codes.push(c); }
    }

    // ターゲットはコード一覧からランダムに1つ選ぶ
    const targetIdx = Math.floor(Math.random() * total);
    this.target = codes[targetIdx];

    // セルオブジェクト生成（x,y,w,h,code）
    this.cells = [];
    for (let row = 0; row < ROWS; row++) {
      for (let col = 0; col < COLS; col++) {
        const idx = row * COLS + col;
        const cx = GRID_X + col * (CELL_W + CELL_GAP_X);
        const cy = GRID_Y + row * (CELL_H + CELL_GAP_Y);
        this.cells.push({
          x: cx, y: cy, w: CELL_W, h: CELL_H,
          code: codes[idx],
        });
      }
    }

    // 経過タイマーをリセット
    this.elapsed = 0;

    // タイピング演出: ターゲット表示を1文字ずつ
    this._typeLen   = 0;
    this._typeTimer = 0;
    this._typeDone  = false;
  }

  // ---- update ----
  update(dt) {
    if (this.over) return;

    // 現在ラウンドの経過時間（タイムアウトなし、スコア計算用）
    this.elapsed += dt;

    // フラッシュ
    if (this.flash) {
      this.flash.t -= dt;
      if (this.flash.t <= 0) this.flash = null;
    }

    // 得点フラッシュ
    if (this.gainFlash) {
      this.gainFlash.t -= dt;
      if (this.gainFlash.t <= 0) this.gainFlash = null;
    }

    // ノイズアニメーション（下方向スクロール）
    for (const part of this.noise) {
      part.y += part.speed * dt;
      part.age += dt;
      if (part.y > H + 20) {
        part.y = -20;
        part.x = Math.random() * W;
        part.ch = NOISE_CHARS[Math.floor(Math.random() * NOISE_CHARS.length)];
      }
      // 約5秒ごとに文字を変える
      if (part.age > 5) {
        part.age = 0;
        part.ch = NOISE_CHARS[Math.floor(Math.random() * NOISE_CHARS.length)];
      }
    }

    // タイピング演出（1文字 0.06s）
    if (!this._typeDone) {
      this._typeTimer += dt;
      const targetLen = ('DECRYPT > ' + this.target).length;
      this._typeLen = Math.min(Math.floor(this._typeTimer / 0.06), targetLen);
      if (this._typeLen >= targetLen) this._typeDone = true;
    }
  }

  // ---- onInput ----
  onInput(action, data) {
    if (this.over) {
      if (action === 'back') return this.engine.toMenu();
      if (action === 'tap' || action === 'confirm') { this.enter(); }
      return;
    }
    if (action === 'back') return this.engine.toMenu();

    if (action === 'tap' && data) {
      this._handleTap(data.x, data.y);
    }
  }

  _handleTap(tx, ty) {
    // どのセルがタップされたか
    const idx = this.cells.findIndex(
      c => tx >= c.x && tx < c.x + c.w && ty >= c.y && ty < c.y + c.h
    );
    if (idx < 0) return; // セル外

    const cell = this.cells[idx];
    if (cell.code === this.target) {
      // 正解 — 反応時間でスコア計算
      const gain = Math.max(SCORE_MIN, Math.round(SCORE_MAX - this.elapsed * SCORE_DECAY));
      this.score += gain;
      this.flash = { idx, t: FLASH_DUR, good: true };
      this.gainFlash = { text: '+' + gain, t: FLASH_GAIN_DUR };
      this.engine.audio.good();

      // ハイスコア更新
      if (this.engine.storage.setHigh(meta.id, this.score)) {
        this.high = this.score;
      }

      this.round++;
      if (this.round >= TOTAL_ROUNDS) {
        // 全ラウンド終了 → リザルト
        this._showResults();
      } else {
        // 次ラウンドへ
        this._newRound();
      }
    } else {
      // 不正解 — ゲーム終了なし。赤フラッシュのみ（経過時間は止まらない）
      this.flash = { idx, t: FLASH_DUR, good: false };
      this.engine.audio.bad();
    }
  }

  _showResults() {
    this.over = true;
    // 最終スコアでハイスコア更新（正解時にも更新しているが念のため）
    if (this.engine.storage.setHigh(meta.id, this.score)) {
      this.high = this.score;
    }
  }

  // ---- render ----
  render(ctx) {
    const p = P();

    // ---- ノイズ背景（dimカラー、グリッドの下に描画）----
    for (const n of this.noise) {
      const inGrid = n.x >= GRID_X && n.x < GRID_X + COLS * (CELL_W + CELL_GAP_X) &&
                     n.y >= GRID_Y && n.y < GRID_Y + ROWS * (CELL_H + CELL_GAP_Y);
      ctx.globalAlpha = inGrid ? 0.07 : 0.18;
      this.engine.text(n.ch, n.x, n.y, 12, p.dim, 'center');
      ctx.globalAlpha = 1.0;
    }

    // ---- HUD ----
    // タイトルバー（BACKボタンは x:6..48 なので HACK タイトルは x>=52 から）
    this.engine.rect(0, 0, W, 44, p.dark);
    this.engine.text('HACK', 52, 10, 22, p.fg, 'left');   // BACKボタン右側から開始
    this.engine.text('HI ' + this.high, W - 14, 10, 16, p.dim, 'right');

    // スコア行
    this.engine.text('SCORE', 52, 52, 13, p.dim, 'left');
    this.engine.text(String(this.score), 52, 68, 26, p.mid, 'left');

    // ラウンド進捗（右側）
    const roundDisp = Math.min(this.round + 1, TOTAL_ROUNDS);
    this.engine.text('ROUND ' + roundDisp + ' / ' + TOTAL_ROUNDS, W - 14, 52, 13, p.dim, 'right');

    // 経過時間（右側。反応速度の参考表示）
    const elapsedLabel = this.elapsed.toFixed(1) + 's';
    this.engine.text(elapsedLabel, W - 14, 68, 20, p.fg, 'right');

    // ---- DECRYPT ターゲット ----
    this.engine.rect(0, 145, W, 56, p.dark);
    this.engine.stroke(0, 145, W, 56, p.dim, 1);
    const fullLabel = 'DECRYPT > ' + this.target;
    const showLabel = this._typeDone ? fullLabel : fullLabel.slice(0, this._typeLen);
    // カーソル点滅（タイピング中）
    const cursor = (!this._typeDone && Math.floor(Date.now() / 250) % 2 === 0) ? '_' : '';
    this.engine.text(showLabel + cursor, W / 2, 157, 24, p.hi, 'center');

    // ---- グリッドセル ----
    for (let i = 0; i < this.cells.length; i++) {
      const c = this.cells[i];
      const isFlash = this.flash && this.flash.idx === i;

      let bgColor = p.dark;
      let textColor = p.fg;
      let borderColor = p.dim;

      if (isFlash) {
        if (this.flash.good) {
          bgColor = p.mid;
          textColor = p.bg;
          borderColor = p.hi;
        } else {
          bgColor = p.bad;
          textColor = p.hi;
          borderColor = p.bad;
        }
      }

      this.engine.rect(c.x, c.y, c.w, c.h, bgColor);
      this.engine.stroke(c.x, c.y, c.w, c.h, borderColor, 1);
      this.engine.text(c.code, c.x + c.w / 2, c.y + c.h / 2 - 12, 22, textColor, 'center');
    }

    // ---- "+NNN" 得点フラッシュ（グリッド上部に表示）----
    if (this.gainFlash) {
      const alpha = Math.min(1, this.gainFlash.t / FLASH_GAIN_DUR * 2);
      ctx.globalAlpha = alpha;
      this.engine.text(this.gainFlash.text, W / 2, GRID_Y - 30, 28, p.warn, 'center');
      ctx.globalAlpha = 1.0;
    }

    // ---- リザルトオーバーレイ ----
    if (this.over) {
      // 半透明の暗幕
      ctx.globalAlpha = 0.88;
      this.engine.rect(0, 0, W, H, p.bg);
      ctx.globalAlpha = 1.0;

      // ボックス
      const bx = 24, by = H / 2 - 140, bw = W - 48, bh = 280;
      this.engine.rect(bx, by, bw, bh, p.dark);
      this.engine.stroke(bx, by, bw, bh, p.mid, 2);

      this.engine.text('MISSION COMPLETE', W / 2, by + 18, 20, p.mid, 'center');
      this.engine.text('TOTAL SCORE', W / 2, by + 60, 14, p.dim, 'center');
      this.engine.text(String(this.score), W / 2, by + 78, 48, p.hi, 'center');

      // ハイスコア表示
      if (this.score >= this.high && this.score > 0) {
        this.engine.text('NEW RECORD!', W / 2, by + 140, 18, p.warn, 'center');
      } else {
        this.engine.text('HI  ' + this.high, W / 2, by + 140, 16, p.dim, 'center');
      }

      // スコア解説（最高・達成ラウンド）
      this.engine.text(TOTAL_ROUNDS + ' ROUNDS CLEARED', W / 2, by + 170, 14, p.fg, 'center');
      this.engine.text('MAX ' + (SCORE_MAX * TOTAL_ROUNDS) + ' PTS POSSIBLE', W / 2, by + 192, 12, p.dim, 'center');

      this.engine.text('TAP TO RETRY', W / 2, by + 236, 15, p.mid, 'center');
    }
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/snake.js ----
(function(){
// SNAKE : CRTグリーンの定番スネークゲーム
// スワイプで方向操作。食べ物を食べて成長、壁か自分の体に当たったらゲームオーバー。

const meta = {
  id: 'snake',
  title: 'SNAKE',
  desc: 'CRTグリーンの定番スネーク',
  glyph: '~',
};

// ---- グリッド設定 ----
// COLS=12, ROWS=16, CELL=30 → プレイエリア 360x480
// HUD: 0〜95px, プレイエリア: 96〜575px（480px）, フッター: 576〜639px（64px）
const COLS = 12;
const ROWS = 16;
const CELL = 30;
const GRID_X = 0;
const GRID_Y = 96;

// ---- ゲームパラメータ ----
const STEP_INIT = 0.22;    // 初期ステップ間隔（秒）：ゆっくりスタート
const STEP_FLOOR = 0.10;   // 最高速度（秒）：速くなりすぎない上限
const SPEED_UP = 0.004;    // 食べるたびに間隔を縮める量（緩やかに加速）

class Game extends Scene {
  enter() {
    this.score = 0;
    this.high = this.engine.storage.getHigh(meta.id);
    this.dead = false;

    // スネーク初期化：中央付近から右向きに3マス
    const startX = Math.floor(COLS / 2);
    const startY = Math.floor(ROWS / 2);
    // bodyは頭から尻尾の順（インデックス0が頭）
    this.body = [
      { x: startX,     y: startY },
      { x: startX - 1, y: startY },
      { x: startX - 2, y: startY },
    ];
    this.dir = { x: 1, y: 0 };  // 右向きで開始

    // 入力バッファ（最大2手先まで）：素早いスワイプを取りこぼさない
    this.dirBuffer = [];

    // ステップタイマー（最初の入力があるまで動かない猶予）
    this.stepInterval = STEP_INIT;
    this.stepTimer = 0;
    this.waitingForFirst = true; // 最初の入力待ち猶予フラグ

    // 食べ物を配置
    this.food = this._spawnFood();
  }

  // ---- 空きセルにランダムに食べ物を置く ----
  _spawnFood() {
    // スネークが占有しているセルのセットを作成
    const occupied = new Set(this.body.map(s => s.x + ',' + s.y));
    const candidates = [];
    for (let y = 0; y < ROWS; y++) {
      for (let x = 0; x < COLS; x++) {
        if (!occupied.has(x + ',' + y)) candidates.push({ x, y });
      }
    }
    if (candidates.length === 0) return null; // 盤面が満杯（クリア）
    return candidates[Math.floor(Math.random() * candidates.length)];
  }

  // ---- 入力処理 ----
  onInput(action, data) {
    // ゲームオーバー中
    if (this.dead) {
      if (action === 'back') return this.engine.toMenu();
      if (action === 'tap' || action === 'confirm') return this.enter();
      return;
    }
    if (action === 'back') return this.engine.toMenu();

    // 方向入力をバッファに積む（バッファは最大2個まで：素早い連続スワイプに対応）
    let nd = null;
    if (action === 'up')    nd = { x: 0,  y: -1 };
    else if (action === 'down')  nd = { x: 0,  y: 1  };
    else if (action === 'left')  nd = { x: -1, y: 0  };
    else if (action === 'right') nd = { x: 1,  y: 0  };

    if (nd && this.dirBuffer.length < 2) {
      // バッファの末尾（次に適用される方向）に対して直逆でないか事前チェック
      const prev = this.dirBuffer.length > 0
        ? this.dirBuffer[this.dirBuffer.length - 1]
        : this.dir;
      const isReverse = (nd.x !== 0 && nd.x === -prev.x) ||
                        (nd.y !== 0 && nd.y === -prev.y);
      if (!isReverse) {
        this.dirBuffer.push(nd);
        if (this.waitingForFirst) this.waitingForFirst = false; // 猶予終了
      }
    }
  }

  // ---- 毎フレーム更新 ----
  update(dt) {
    if (this.dead) return;
    // 最初の入力待ち中はタイマーを進めない（プレイヤーが準備できるまで待機）
    if (this.waitingForFirst) return;

    this.stepTimer += dt;
    if (this.stepTimer >= this.stepInterval) {
      this.stepTimer -= this.stepInterval;
      this._step();
    }
  }

  // ---- 1ステップ進める ----
  _step() {
    // バッファから次の方向を適用（直逆はバッファ投入時に除外済み）
    if (this.dirBuffer.length > 0) {
      this.dir = this.dirBuffer.shift();
    }

    // 新しい頭の位置を計算
    const head = this.body[0];
    const nx = head.x + this.dir.x;
    const ny = head.y + this.dir.y;

    // 壁衝突判定
    if (nx < 0 || ny < 0 || nx >= COLS || ny >= ROWS) {
      this._die();
      return;
    }

    // 自己衝突判定（尻尾は移動後に消えるので除外して判定）
    // 尻尾以外のセルと衝突したら死亡
    for (let i = 0; i < this.body.length - 1; i++) {
      if (this.body[i].x === nx && this.body[i].y === ny) {
        this._die();
        return;
      }
    }

    // 食べ物判定
    const ate = this.food && nx === this.food.x && ny === this.food.y;

    // スネークを前進させる：先頭に追加
    this.body.unshift({ x: nx, y: ny });

    if (ate) {
      // 成長：尻尾を消さない
      this.score += 1;
      this.engine.audio.pick();
      // 速度アップ（下限あり）
      this.stepInterval = Math.max(STEP_FLOOR, this.stepInterval - SPEED_UP);
      // 新しい食べ物を配置
      this.food = this._spawnFood();
      // ハイスコア更新チェック
      if (this.engine.storage.setHigh(meta.id, this.score)) {
        this.high = this.score;
      }
    } else {
      // 通常移動：尻尾を削除
      this.body.pop();
    }
  }

  // ---- 死亡処理 ----
  _die() {
    this.dead = true;
    this.engine.audio.bad();
    if (this.engine.storage.setHigh(meta.id, this.score)) {
      this.high = this.score;
    }
  }

  // ---- 描画 ----
  render(ctx) {
    const p = P();

    // ---- HUD（左上はBACKボタンが x:6..48 を占有するため x>=52 から描く）----
    this.engine.text('SNAKE', 52, 12, 20, p.fg, 'left');
    this.engine.text('HI ' + this.high, W - 12, 12, 14, p.dim, 'right');
    this.engine.text('SCORE', 52, 44, 13, p.dim, 'left');
    this.engine.text(String(this.score), 52, 62, 22, p.mid, 'left');

    // ---- プレイフィールドの背景 ----
    this.engine.rect(GRID_X, GRID_Y, COLS * CELL, ROWS * CELL, p.dark);

    // ---- グリッドドット（薄い格子点） ----
    ctx.fillStyle = p.dim;
    for (let y = 1; y < ROWS; y++) {
      for (let x = 1; x < COLS; x++) {
        const px = GRID_X + x * CELL;
        const py = GRID_Y + y * CELL;
        ctx.fillRect(px - 1, py - 1, 2, 2);
      }
    }

    // ---- 食べ物 ----
    if (this.food) {
      const fx = GRID_X + this.food.x * CELL;
      const fy = GRID_Y + this.food.y * CELL;
      // 食べ物：明るい黄色で塗り、内側に小さい正方形
      this.engine.rect(fx + 4, fy + 4, CELL - 8, CELL - 8, p.warn);
      this.engine.rect(fx + 8, fy + 8, CELL - 16, CELL - 16, p.hi);
    }

    // ---- スネーク本体 ----
    for (let i = this.body.length - 1; i >= 0; i--) {
      const seg = this.body[i];
      const px = GRID_X + seg.x * CELL;
      const py = GRID_Y + seg.y * CELL;

      if (i === 0) {
        // 頭：ハイライトカラー + やや大きめ
        this.engine.rect(px + 1, py + 1, CELL - 2, CELL - 2, p.hi);
        // 頭の目（進行方向に応じて表示）
        ctx.fillStyle = p.dark;
        const eyeSize = 4;
        if (this.dir.x === 1) {
          // 右向き：右側に目
          ctx.fillRect(px + CELL - 8, py + 5,   eyeSize, eyeSize);
          ctx.fillRect(px + CELL - 8, py + CELL - 9, eyeSize, eyeSize);
        } else if (this.dir.x === -1) {
          // 左向き：左側に目
          ctx.fillRect(px + 4, py + 5,   eyeSize, eyeSize);
          ctx.fillRect(px + 4, py + CELL - 9, eyeSize, eyeSize);
        } else if (this.dir.y === -1) {
          // 上向き：上側に目
          ctx.fillRect(px + 5,        py + 4, eyeSize, eyeSize);
          ctx.fillRect(px + CELL - 9, py + 4, eyeSize, eyeSize);
        } else {
          // 下向き：下側に目
          ctx.fillRect(px + 5,        py + CELL - 8, eyeSize, eyeSize);
          ctx.fillRect(px + CELL - 9, py + CELL - 8, eyeSize, eyeSize);
        }
      } else {
        // 胴体：末尾に近いほど暗く
        const ratio = i / (this.body.length - 1); // 0(首)→1(尻尾)
        // 首に近い→p.fg、尻尾に近い→p.mid
        const color = ratio < 0.5 ? p.fg : p.mid;
        const pad = 2 + Math.floor(ratio * 3); // 尻尾ほど細く
        this.engine.rect(px + pad, py + pad, CELL - pad * 2, CELL - pad * 2, color);
      }
    }

    // ---- フィールドの枠線 ----
    this.engine.stroke(GRID_X, GRID_Y, COLS * CELL, ROWS * CELL, p.dim, 2);

    // ---- フッター：操作ヒント ----
    if (!this.dead) {
      this.engine.text('SWIPE TO STEER', W / 2, GRID_Y + ROWS * CELL + 16, 13, p.dim, 'center');
    }

    // ---- ゲームオーバーオーバーレイ ----
    if (this.dead) {
      // 半透明の暗いオーバーレイ
      ctx.fillStyle = p.dark;
      ctx.globalAlpha = 0.88;
      ctx.fillRect(0, H / 2 - 90, W, 180);
      ctx.globalAlpha = 1.0;

      this.engine.stroke(16, H / 2 - 90, W - 32, 180, p.dim, 2);
      this.engine.text('GAME OVER', W / 2, H / 2 - 72, 28, p.bad, 'center');
      this.engine.text('SCORE  ' + this.score, W / 2, H / 2 - 30, 20, p.fg, 'center');
      if (this.score > 0 && this.score === this.high) {
        this.engine.text('NEW BEST!', W / 2, H / 2 + 4, 16, p.warn, 'center');
      }
      this.engine.text('TAP TO RETRY', W / 2, H / 2 + 36, 16, p.mid, 'center');
      this.engine.text('BACK = MENU', W / 2, H / 2 + 62, 13, p.dim, 'center');
    }
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/beeper.js ----
(function(){
// BEEPER : サイモン風記憶ゲーム
// 光る順番を記憶してパッドを同じ順番でタップ。ラウンドが進むほど長くなる。
// フレームレート非依存の update(dt) ステートマシンで再生アニメを制御する。

const meta = {
  id: 'beeper',
  title: 'BEEPER',
  desc: '光る順番を記憶して再現',
  glyph: '♪',
};

// ---- パッド定義 ----
// 2×2 グリッド。各パッドに固有の色と音程を割り当てる。
const PAD_SIZE  = 130;  // パッドの一辺の長さ (px)
const PAD_GAP   = 14;   // パッド間の隙間 (px)
const PAD_LEFT  = (W - PAD_SIZE * 2 - PAD_GAP) / 2; // グリッド左端 X
const PAD_TOP   = 180;  // グリッド上端 Y（HUDの下）

// パッド 0=左上, 1=右上, 2=左下, 3=右下
const PADS = [
  { col: 0, row: 0, freq: 330 },   // 左上: E4 寄り
  { col: 1, row: 0, freq: 415 },   // 右上: Ab4 寄り
  { col: 0, row: 1, freq: 494 },   // 左下: B4 寄り
  { col: 1, row: 1, freq: 622 },   // 右下: Eb5 寄り
];

// パッドの明暗に使うパレットインデックス（パッド番号→明色・暗色）
// パレットから 4 色選ぶ：mid, warn, bad, fg
const PAD_BRIGHT = ['mid', 'warn', 'bad', 'fg'];   // 点灯時
const PAD_DIM    = ['dark', 'dark', 'dark', 'dark']; // 消灯時 (どれも dark)

// パッド座標を計算する
function padRect(i) {
  const { col, row } = PADS[i];
  const x = PAD_LEFT + col * (PAD_SIZE + PAD_GAP);
  const y = PAD_TOP  + row * (PAD_SIZE + PAD_GAP);
  return { x, y, w: PAD_SIZE, h: PAD_SIZE };
}

// タップ座標がどのパッドに当たるか。当たらなければ -1
function hitPad(tx, ty) {
  for (let i = 0; i < 4; i++) {
    const { x, y, w, h } = padRect(i);
    if (tx >= x && tx <= x + w && ty >= y && ty <= y + h) return i;
  }
  return -1;
}

// ---- ゲーム内部の状態定数 ----
const STATE_SHOW    = 'SHOW';   // コンピュータが再生中
const STATE_INPUT   = 'INPUT';  // プレイヤーが入力中
const STATE_PAUSE   = 'PAUSE';  // ラウンド正解後のブリーフポーズ
const STATE_OVER    = 'OVER';   // ゲームオーバー

// 再生タイミング定数 (秒)
const BASE_LIT  = 0.45;   // 点灯時間 (長くなるほど速くなるが最低0.22)
const BASE_GAP  = 0.20;   // 消灯時間（パッド間のスキマ）
const MIN_LIT   = 0.22;
const PAUSE_DUR = 0.70;   // ラウンド成功後の待機時間

class Game extends Scene {
  enter() {
    const p = P();
    this.high   = this.engine.storage.getHigh(meta.id);
    this.round  = 1;   // スコア = 完了したラウンド数
    this.seq    = [];  // ランダム配列（インデックス: 0-3）
    this.lit    = -1;  // 現在点灯中のパッドインデックス（-1=消灯）
    this.litTimer = 0; // 現在の点灯/消灯タイマー

    // プレイヤー入力フィードバック用（短く点灯させる）
    this.inputLit    = -1; // プレイヤータップで光るパッド
    this.inputTimer  = 0;

    this._startRound();
  }

  // ラウンド開始: シーケンスに1ステップ追加して再生開始
  _startRound() {
    this.seq.push(Math.floor(Math.random() * 4));
    this.state      = STATE_SHOW;
    this.showIdx    = 0;  // 次に再生するシーケンスインデックス
    this.litPhase   = 'off'; // 'on' | 'off' の2フェーズで制御
    this.litTimer   = BASE_GAP; // 最初に少し間を置いてから点灯
    this.lit        = -1;
    this.inputIdx   = 0;  // プレイヤーが次に入力すべきシーケンスインデックス
    this.status     = 'WATCH';
  }

  // 速度係数: ラウンドが進むほど速くなる（最低 MIN_LIT まで）
  _litDur() {
    const factor = Math.max(0.5, 1.0 - (this.seq.length - 1) * 0.03);
    return Math.max(MIN_LIT, BASE_LIT * factor);
  }

  update(dt) {
    // プレイヤータップのフィードバック点灯を消す
    if (this.inputTimer > 0) {
      this.inputTimer -= dt;
      if (this.inputTimer <= 0) this.inputLit = -1;
    }

    if (this.state === STATE_SHOW) {
      this.litTimer -= dt;
      if (this.litTimer <= 0) {
        if (this.litPhase === 'off') {
          // 消灯フェーズ終了 → 次のパッドを点灯
          if (this.showIdx >= this.seq.length) {
            // 全ステップ再生完了 → 入力フェーズへ
            this.state   = STATE_INPUT;
            this.status  = 'REPEAT';
            this.lit     = -1;
          } else {
            // 次パッドを点灯
            const padIdx = this.seq[this.showIdx];
            this.lit      = padIdx;
            this.litPhase = 'on';
            this.litTimer = this._litDur();
            this.engine.audio.beep(PADS[padIdx].freq, this._litDur() * 0.85, 'square', 0.3);
          }
        } else {
          // 点灯フェーズ終了 → 消灯してから次へ
          this.lit      = -1;
          this.litPhase = 'off';
          this.litTimer = BASE_GAP;
          this.showIdx++;
        }
      }
    } else if (this.state === STATE_PAUSE) {
      this.litTimer -= dt;
      if (this.litTimer <= 0) {
        this.round++;
        this._startRound();
      }
    }
  }

  onInput(action, data) {
    if (this.state === STATE_OVER) {
      if (action === 'back') return this.engine.toMenu();
      if (action === 'tap' || action === 'confirm') return this.enter();
      return;
    }
    if (action === 'back') return this.engine.toMenu();

    if (action === 'tap' && this.state === STATE_INPUT) {
      const i = hitPad(data.x, data.y);
      if (i < 0) return; // パッド外タップは無視

      // タップフィードバック: 短く点灯 + 音
      this.inputLit   = i;
      this.inputTimer = 0.18;
      this.engine.audio.beep(PADS[i].freq, 0.15, 'square', 0.3);

      if (i === this.seq[this.inputIdx]) {
        // 正解タップ
        this.inputIdx++;
        if (this.inputIdx >= this.seq.length) {
          // シーケンス全入力完了
          this.engine.audio.good();
          if (this.engine.storage.setHigh(meta.id, this.round)) this.high = this.round;
          this.state    = STATE_PAUSE;
          this.litTimer = PAUSE_DUR;
          this.status   = 'NICE!';
        }
      } else {
        // 不正解
        this.engine.audio.bad();
        // ハイスコア保存（round - 1 が完了ラウンド数）
        const score = this.round - 1;
        if (this.engine.storage.setHigh(meta.id, score)) this.high = score;
        this.state  = STATE_OVER;
        this.status = 'MISS!';
      }
    }
  }

  render(ctx) {
    const p = P();
    const e = this.engine;

    // ---- HUD ----
    e.text('BEEPER', W / 2, 14, 20, p.fg, 'center');
    e.text('ROUND ' + this.round, 54, 14, 15, p.mid, 'left'); // 左上BACKボタンを避ける
    e.text('HI ' + this.high, W - 14, 14, 15, p.dim, 'right');

    // ---- ステータスライン（HUD直下）----
    e.text(this.status, W / 2, 50, 16, p.warn, 'center');

    // ---- パッド描画 ----
    for (let i = 0; i < 4; i++) {
      const { x, y, w, h } = padRect(i);
      const isLit = (i === this.lit) || (i === this.inputLit);
      const dimKey    = PAD_DIM[i];
      const brightKey = PAD_BRIGHT[i];

      if (isLit) {
        // 点灯: 明るい塗り + 白枠
        e.rect(x, y, w, h, p[brightKey]);
        e.stroke(x, y, w, h, p.hi, 3);
      } else {
        // 消灯: 暗い塗り + dim枠
        e.rect(x, y, w, h, p.dark);
        e.stroke(x, y, w, h, p.dim, 2);
      }

      // パッド内アイコン（音符）
      const iconColor = isLit ? p.bg : p.dim;
      e.text('♪', x + w / 2, y + h / 2 - 14, 28, iconColor, 'center');
    }

    // ---- シーケンス長インジケーター ----
    // 現在のシーケンス長を小さいドットで表示
    const dotY = PAD_TOP + PAD_SIZE * 2 + PAD_GAP + 20;
    const dotR = 5;
    const dotSpacing = 14;
    const totalDots = this.seq.length;
    const startX = W / 2 - ((totalDots - 1) * dotSpacing) / 2;
    for (let d = 0; d < totalDots; d++) {
      const dx = startX + d * dotSpacing;
      // 入力フェーズでは入力済みドットを明るく
      let dotColor;
      if (this.state === STATE_INPUT && d < this.inputIdx) {
        dotColor = p.mid;
      } else {
        dotColor = p.dim;
      }
      ctx.fillStyle = dotColor;
      ctx.beginPath();
      ctx.arc(dx, dotY, dotR, 0, Math.PI * 2);
      ctx.fill();
    }

    // ---- ゲームオーバーオーバーレイ ----
    if (this.state === STATE_OVER) {
      const score = this.round - 1;
      const oy = H / 2 - 80;
      e.rect(0, oy, W, 200, p.dark);
      e.stroke(0, oy, W, 200, p.bad, 3);
      e.text('GAME OVER', W / 2, oy + 18, 30, p.bad, 'center');
      e.text('SCORE: ' + score + ' ROUNDS', W / 2, oy + 66, 18, p.fg, 'center');
      e.text('HI: ' + this.high, W / 2, oy + 96, 16, p.dim, 'center');
      e.text('TAP TO RETRY', W / 2, oy + 138, 15, p.mid, 'center');
    }
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/dodge.js ----
(function(){
// DODGE : Missile evasion game (Itano Circus style)
// Pilot a fixed-wing F-14 fighter and dodge homing missiles from the right.
// Missiles make wide sweeping loops (low turn rate) leaving long white contrails.

const meta = {
  id: 'dodge',
  title: 'DODGE',
  desc: 'Evade the missile barrage',
  glyph: '>',
};

// ---- Constants ----
const PLAY_LEFT   = 0;
const PLAY_RIGHT  = W;
const PLAY_TOP    = 72;         // below HUD
const PLAY_BOTTOM = H - 20;

// Fighter follow speed for drag (px/s)
const FIGHTER_FOLLOW = 420;
// Keyboard movement speed (px/s)
const KEY_SPEED = 200;
// Fighter max X (left 2/3 area)
const FIGHTER_MAX_X = W * 0.62;
// Hit radius (fighter) — small ship, forgiving hitbox
const HIT_R = 7;
// Missile tip hit radius
const MISSILE_R = 5;

// Trail length — very long so loops fill the screen with white contrails
const TRAIL_MAX = 1800;

// Out-of-bounds frames before deletion
const OOB_FRAMES = 5;

// ---- Difficulty caps (plateau after ramp) ----
const CAP_SPEED      = 165;   // px/s max missile speed
const CAP_TURN_RATE  = 1.0;   // rad/s max (keeps loops wide)
const CAP_VOLLEY     = 4;     // max missiles per volley
const MIN_INTERVAL   = 0.9;   // s minimum spawn interval

// ---- Lull system ----
const LULL_EVERY     = 13.5;  // s between lulls (within active spawning)
const LULL_DUR       = 2.5;   // s duration of lull
const LULL_MSG_DUR   = 1.8;   // s to show "WAVE CLEAR" text

// ---- Chaff/Flare constants ----
const FLARE_START    = 3;     // initial chaff count
const FLARE_REGEN_T  = 25;    // s between chaff regeneration
const FLARE_MAX      = 5;     // max storable chaff

// Chaff decoy behavior
const CHAFF_LIFETIME     = 3.0;   // s chaff stays active redirecting all missiles
const CHAFF_EXPLODE_R    = 110;   // px — blast radius at end-of-life (generous)
const CHAFF_DEPLOY_DIST  = 130;   // px ahead/right of ship (toward missile origin)
const CHAFF_FLY_DIST     = 80;    // px the chaff visually flies out before settling

// ---- Valkyrie constants ----
const VALKYRIE_CHARGE_TIME = 20;   // s to fill energy gauge from 0
const VALKYRIE_DURATION    = 9.5;  // s of Valkyrie mode (increased from 5.5s)
const VALKYRIE_AUTO_LIMIT  = 22;   // max missiles auto-destroyed per activation
const VALKYRIE_BEAM_SPD    = 600;  // px/s beam travel
const VALKYRIE_SHOOT_CD    = 0.18; // s between auto-shots

// ---- On-screen button rects (logical coords) ----
const BTN_FLARE = { x: 8, y: H - 70, w: 58, h: 52 };
const BTN_VALKYRIE = { x: W - 66, y: H - 70, w: 58, h: 52 };

// ---- Parallax starfield layer config ----
const STAR_LAYERS = [
  { count: 80, speed:  18, size: 0.6, alpha: 0.25 },
  { count: 50, speed:  45, size: 1.0, alpha: 0.40 },
  { count: 30, speed:  90, size: 1.5, alpha: 0.60 },
  { count: 15, speed: 160, size: 2.2, alpha: 0.85 },
];

// ---- Utility ----
function clamp(v, lo, hi) {
  return v < lo ? lo : v > hi ? hi : v;
}

function angleDiff(to, from) {
  let d = to - from;
  while (d > Math.PI) d -= 2 * Math.PI;
  while (d < -Math.PI) d += 2 * Math.PI;
  return d;
}

function inRect(px, py, r) {
  return px >= r.x && px <= r.x + r.w && py >= r.y && py <= r.y + r.h;
}

// ---- Parallax Star ----
class Star {
  constructor(layer) {
    this.layer = layer;
    this.reset(Math.random() * W);
  }
  reset(x) {
    this.x = x;
    this.y = PLAY_TOP + Math.random() * (PLAY_BOTTOM - PLAY_TOP);
  }
  update(dt) {
    this.x -= this.layer.speed * dt;
    if (this.x < -2) this.reset(W + 2);
  }
}

// ---- Missile ----
class Missile {
  constructor(x, y, angle, speed, turnRate, homingBudget) {
    this.x = x;
    this.y = y;
    this.angle = angle;
    this.speed = speed;
    this.turnRate = turnRate;

    this.homingBudget = homingBudget;
    this.homingUsed   = 0;
    this.homing       = true;

    this.disengageTime = 0;
    this.selfDestruct  = Math.random() < 0.4;
    this.exploding     = false;
    this.explodeTimer  = 0;
    this.explodeDur    = 0.5;

    this.trail = [];
    this.age   = 0;
    this.dead  = false;
    this._oob  = 0;
  }

  update(dt, targetX, targetY) {
    if (this.dead) return;
    this.age += dt;

    if (this.homing) {
      this.homingUsed += dt;
      const dx      = targetX - this.x;
      const dy      = targetY - this.y;
      const desired = Math.atan2(dy, dx);
      const diff    = angleDiff(desired, this.angle);
      const maxTurn = this.turnRate * dt;
      this.angle   += clamp(diff, -maxTurn, maxTurn);
      if (this.homingUsed >= this.homingBudget) {
        this.homing        = false;
        this.disengageTime = 0;
      }
    } else {
      this.disengageTime += dt;
      if (this.selfDestruct && this.disengageTime >= 1.5 && !this.exploding) {
        this.exploding    = true;
        this.explodeTimer = 0;
      }
      if (this.exploding) {
        this.explodeTimer += dt;
        if (this.explodeTimer >= this.explodeDur) {
          this.dead = true;
          return;
        }
        this._recordTrail();
        return;
      }
    }

    this.x += Math.cos(this.angle) * this.speed * dt;
    this.y += Math.sin(this.angle) * this.speed * dt;
    this._recordTrail();

    const margin = this.homing ? 80 : 30;
    if (
      this.x < -margin || this.x > W + margin ||
      this.y < PLAY_TOP - margin || this.y > PLAY_BOTTOM + margin
    ) {
      this._oob++;
      if (this._oob > OOB_FRAMES) this.dead = true;
    } else {
      this._oob = 0;
    }
  }

  _recordTrail() {
    this.trail.push({ x: this.x, y: this.y });
    if (this.trail.length > TRAIL_MAX) this.trail.shift();
  }
}

// ---- Auto-fire beam (Valkyrie mode) ----
class Beam {
  constructor(x, y, tx, ty) {
    this.x  = x;
    this.y  = y;
    const dx = tx - x;
    const dy = ty - y;
    const d  = Math.sqrt(dx * dx + dy * dy) || 1;
    this.vx = (dx / d) * VALKYRIE_BEAM_SPD;
    this.vy = (dy / d) * VALKYRIE_BEAM_SPD;
    this.angle = Math.atan2(dy, dx);
    this.dead  = false;
    this.age   = 0;
    this.trail = [{ x, y }];
  }
  update(dt) {
    if (this.dead) return;
    this.age += dt;
    this.x   += this.vx * dt;
    this.y   += this.vy * dt;
    this.trail.push({ x: this.x, y: this.y });
    if (this.trail.length > 10) this.trail.shift();
    if (this.age > 1.2 || this.x < -20 || this.x > W + 20 || this.y < PLAY_TOP - 20 || this.y > PLAY_BOTTOM + 20) {
      this.dead = true;
    }
  }
}

// ---- Hit spark effect ----
class Spark {
  constructor(x, y) {
    this.x   = x;
    this.y   = y;
    this.t   = 0;
    this.dur = 0.35;
    this.dead = false;
  }
  update(dt) {
    this.t += dt;
    if (this.t >= this.dur) this.dead = true;
  }
}

// ---- Main Game Class ----
class Game extends Scene {
  enter() {
    // Fighter position
    this.fx = 80;
    this.fy = (PLAY_TOP + PLAY_BOTTOM) / 2;

    // Missiles
    this.missiles = [];

    // Parallax starfield
    this.starLayers = STAR_LAYERS.map(layerCfg => {
      const stars = [];
      for (let i = 0; i < layerCfg.count; i++) {
        stars.push(new Star(layerCfg));
      }
      return { cfg: layerCfg, stars };
    });

    // Score / time
    this.elapsed = 0;
    this.score   = 0;
    this.high    = this.engine.storage.getHigh(meta.id) || 0;

    // Spawn management
    this.spawnTimer    = 1.2;   // brief delay before first volley
    this.spawnInterval = 1.8;
    this.volleyCount   = 1;

    // Lull system — tracks time spent actively spawning
    this.activeSpawnTime = 0;   // cumulative time outside lulls
    this.inLull          = false;
    this.lullTimer       = 0;
    this.lullMsgTimer    = 0;

    // Explosion effect (fighter death)
    this.explosion = null;

    // Game over flag
    this.dead = false;

    // Life system
    this.lives   = 5;
    this._invuln = 0;

    // Keyboard input state
    this.keyDir = { x: 0, y: 0 };

    // Engine flame animation
    this.flameTick = 0;

    // ---- CHAFF/FLARE system ----
    this.flares    = FLARE_START;
    this.flareRegenTimer = 0;     // timer for slow regen
    // Active chaff decoy: { x, y, t, lifetime, sparks: [{angle,dist,t}] }
    this.chaff = null;
    // Chaff end-of-life explosion flash: { x, y, t, dur }
    this.chaffExplode = null;

    // ---- VALKYRIE system ----
    this.energy       = 0;        // 0..1 normalized
    this.valkyrieMode = false;
    this.valkyrieTimer = 0;       // time remaining in Valkyrie mode
    this.valkyrieKills = 0;       // missiles destroyed this activation
    this.valkyrieShootTimer = 0;  // cooldown between auto-shots
    this.beams  = [];             // active Beam instances
    this.sparks = [];             // hit spark VFX
  }

  onInput(action, data) {
    if (this.dead) {
      if (action === 'back')    { this.engine.toMenu(); return; }
      if (action === 'tap') {
        // don't retry if tapped on a button area (though game is over, be safe)
        this.enter(); return;
      }
      if (action === 'confirm') { this.enter(); return; }
      return;
    }
    if (action === 'back') { this.engine.toMenu(); return; }

    if (action === 'up')    { this.keyDir.y = -1; }
    if (action === 'down')  { this.keyDir.y =  1; }
    if (action === 'left')  { this.keyDir.x = -1; }
    if (action === 'right') { this.keyDir.x =  1; }

    // 'confirm' (Space/Enter) => deploy flare
    if (action === 'confirm') {
      this._deployFlare();
      return;
    }

    // 'tap' => check on-screen buttons
    if (action === 'tap' && data) {
      const { x, y } = data;
      if (inRect(x, y, BTN_FLARE)) {
        this._deployFlare();
        return;
      }
      if (inRect(x, y, BTN_VALKYRIE)) {
        this._activateValkyrie();
        return;
      }
      // Normal tap elsewhere — not used for anything in this game
    }
  }

  update(dt) {
    if (this.dead) {
      if (this.explosion) {
        this.explosion.t += dt;
        if (this.explosion.t > this.explosion.dur) this.explosion = null;
      }
      return;
    }

    this.elapsed   += dt;
    this.score      = Math.floor(this.elapsed * 100);
    this.flameTick += dt;

    // ---- Fighter movement ----
    const ptr = this.engine.pointer;

    if (ptr.down) {
      // Only follow pointer when NOT pressing a button
      const overFlare    = inRect(ptr.x, ptr.y, BTN_FLARE);
      const overValkyrie = inRect(ptr.x, ptr.y, BTN_VALKYRIE);
      if (!overFlare && !overValkyrie) {
        const tdx  = ptr.x - this.fx;
        const tdy  = ptr.y - this.fy;
        const dist = Math.sqrt(tdx * tdx + tdy * tdy);
        if (dist > 1) {
          const step = Math.min(FIGHTER_FOLLOW * dt, dist);
          this.fx += (tdx / dist) * step;
          this.fy += (tdy / dist) * step;
        }
      }
    } else {
      if (this.keyDir.x !== 0 || this.keyDir.y !== 0) {
        const klen = Math.sqrt(this.keyDir.x ** 2 + this.keyDir.y ** 2);
        this.fx += (this.keyDir.x / klen) * KEY_SPEED * dt;
        this.fy += (this.keyDir.y / klen) * KEY_SPEED * dt;
      }
    }
    this.keyDir.x = 0;
    this.keyDir.y = 0;

    this.fx = clamp(this.fx, PLAY_LEFT + 20, FIGHTER_MAX_X);
    this.fy = clamp(this.fy, PLAY_TOP + 16, PLAY_BOTTOM - 16);

    // ---- Parallax starfield update ----
    for (const layer of this.starLayers) {
      for (const s of layer.stars) s.update(dt);
    }

    // ---- Lull management ----
    if (this.inLull) {
      this.lullTimer    -= dt;
      this.lullMsgTimer -= dt;
      if (this.lullTimer <= 0) {
        this.inLull = false;
        this.lullTimer = 0;
      }
    }

    // ---- Missile spawn ----
    if (!this.inLull) {
      this.activeSpawnTime += dt;
      this.spawnTimer -= dt;
      if (this.spawnTimer <= 0) {
        this._spawnVolley();
        const t = this.elapsed;
        // Capped escalation
        this.spawnInterval = Math.max(MIN_INTERVAL, 1.8 - t * 0.020);
        this.volleyCount   = Math.min(CAP_VOLLEY, 1 + Math.floor(t / 8));
        this.spawnTimer    = this.spawnInterval;
      }

      // Trigger lull every LULL_EVERY seconds of active spawning
      if (this.activeSpawnTime >= LULL_EVERY) {
        this.activeSpawnTime = 0;
        this.inLull          = true;
        this.lullTimer       = LULL_DUR;
        this.lullMsgTimer    = LULL_MSG_DUR;
      }
    }

    // ---- Chaff decoy update ----
    if (this.chaff) {
      this.chaff.t += dt;
      // Animate spark particles on the chaff
      for (const sp of this.chaff.sparks) sp.t += dt;

      if (this.chaff.t >= this.chaff.lifetime) {
        // Chaff explodes — destroy missiles within generous radius
        const cx = this.chaff.x, cy = this.chaff.y;
        for (const m of this.missiles) {
          if (m.dead) continue;
          const dx = m.x - cx, dy = m.y - cy;
          if (Math.sqrt(dx * dx + dy * dy) <= CHAFF_EXPLODE_R) {
            m.dead = true;
            this.sparks.push(new Spark(m.x, m.y));
          }
        }
        // Leave a brief explosion flash, then clear chaff
        this.chaff.exploding = true;
        this.chaff.explodeT  = 0;
        this.chaff.explodeDur = 0.5;
        // We store it as chaffExplode so chaff homing stops immediately
        this.chaffExplode = { x: cx, y: cy, t: 0, dur: 0.5 };
        this.chaff = null;
      }
    }
    if (this.chaffExplode) {
      this.chaffExplode.t += dt;
      if (this.chaffExplode.t >= this.chaffExplode.dur) this.chaffExplode = null;
    }

    // ---- Missile update — home toward chaff if active, else toward player ----
    const missileTargetX = this.chaff ? this.chaff.x : this.fx;
    const missileTargetY = this.chaff ? this.chaff.y : this.fy;
    for (const m of this.missiles) {
      m.update(dt, missileTargetX, missileTargetY);
    }
    this.missiles = this.missiles.filter(m => !m.dead);

    // ---- Chaff regen (1 per FLARE_REGEN_T s, up to max) ----
    if (this.flares < FLARE_MAX) {
      this.flareRegenTimer += dt;
      if (this.flareRegenTimer >= FLARE_REGEN_T) {
        this.flareRegenTimer -= FLARE_REGEN_T;
        this.flares = Math.min(FLARE_MAX, this.flares + 1);
      }
    } else {
      this.flareRegenTimer = 0;
    }

    // ---- Energy charge (charges even in Valkyrie mode for recharge after) ----
    if (!this.valkyrieMode) {
      this.energy = clamp(this.energy + dt / VALKYRIE_CHARGE_TIME, 0, 1);
    }

    // ---- Valkyrie mode update ----
    if (this.valkyrieMode) {
      this.valkyrieTimer -= dt;
      // Drain energy proportionally to duration
      this.energy = clamp(this.energy - dt / VALKYRIE_DURATION, 0, 1);

      if (this.valkyrieTimer <= 0 || this.valkyrieKills >= VALKYRIE_AUTO_LIMIT || this.energy <= 0) {
        this.valkyrieMode  = false;
        this.valkyrieTimer = 0;
        this.energy        = 0;
        // Start recharging fresh
      }

      // Auto-fire: find nearest live missile and shoot it
      if (this.valkyrieMode && this.valkyrieKills < VALKYRIE_AUTO_LIMIT) {
        this.valkyrieShootTimer -= dt;
        if (this.valkyrieShootTimer <= 0) {
          this.valkyrieShootTimer = VALKYRIE_SHOOT_CD;
          const target = this._nearestMissile();
          if (target) {
            this.beams.push(new Beam(this.fx, this.fy, target.x, target.y));
          }
        }
      }
    }

    // ---- Beam update + beam-missile collision ----
    for (const b of this.beams) {
      b.update(dt);
      if (b.dead) continue;
      for (const m of this.missiles) {
        if (m.dead || m.exploding) continue;
        const dx = b.x - m.x;
        const dy = b.y - m.y;
        if (Math.sqrt(dx * dx + dy * dy) < MISSILE_R + 4) {
          m.dead = true;
          b.dead = true;
          this.sparks.push(new Spark(m.x, m.y));
          if (this.valkyrieMode) this.valkyrieKills++;
          break;
        }
      }
    }
    this.beams  = this.beams.filter(b => !b.dead);
    this.sparks.forEach(s => s.update(dt));
    this.sparks = this.sparks.filter(s => !s.dead);

    // ---- Invuln countdown ----
    if (this._invuln > 0) this._invuln = Math.max(0, this._invuln - dt);

    // ---- Collision detection (skip if invuln or in Valkyrie — Valkyrie has slight shield feel) ----
    if (this._invuln <= 0 && !this.valkyrieMode) {
      for (const m of this.missiles) {
        if (m.dead || m.exploding) continue;
        const dx   = m.x - this.fx;
        const dy   = m.y - this.fy;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < HIT_R + MISSILE_R) {
          m.dead = true;
          this.lives -= 1;
          if (this.lives <= 0) {
            this._gameOver(m.x, m.y);
            return;
          }
          this._invuln = 1.0;
          this.engine.audio.bad();
          this.hitFx = { x: this.fx, y: this.fy, t: 0, dur: 0.4 };
          break;
        }
      }
    }
    if (this.hitFx) {
      this.hitFx.t += dt;
      if (this.hitFx.t > this.hitFx.dur) this.hitFx = null;
    }
  }

  _nearestMissile() {
    let best = null;
    let bestDist = Infinity;
    for (const m of this.missiles) {
      if (m.dead || m.exploding) continue;
      const dx = m.x - this.fx;
      const dy = m.y - this.fy;
      const d  = dx * dx + dy * dy;
      if (d < bestDist) { bestDist = d; best = m; }
    }
    return best;
  }

  _deployFlare() {
    if (this.flares <= 0) return;
    if (this.chaff) return;  // already a chaff active
    this.flares--;
    this.flareRegenTimer = 0;  // reset regen timer on use

    // Launch chaff to the right/ahead of the ship (toward missile origin),
    // clamped to the play area.
    const cx = clamp(this.fx + CHAFF_DEPLOY_DIST, PLAY_LEFT + 20, PLAY_RIGHT - 20);
    const cy = clamp(this.fy + (Math.random() - 0.5) * 60, PLAY_TOP + 20, PLAY_BOTTOM - 20);

    // Generate spark particles for the chaff visual
    const sparks = [];
    for (let i = 0; i < 12; i++) {
      sparks.push({
        angle: Math.random() * Math.PI * 2,
        dist:  10 + Math.random() * 20,
        speed: 0.8 + Math.random() * 0.6,  // rotation speed multiplier
        t:     Math.random() * Math.PI * 2, // phase offset for flicker
      });
    }

    this.chaff = {
      x:        cx,
      y:        cy,
      t:        0,
      lifetime: CHAFF_LIFETIME,
      sparks,
    };

    try { this.engine.audio.bad(); } catch (_) {}
  }

  _activateValkyrie() {
    if (this.energy < 1.0) return;   // not fully charged
    if (this.valkyrieMode) return;    // already active
    this.valkyrieMode    = true;
    this.valkyrieTimer   = VALKYRIE_DURATION;
    this.valkyrieKills   = 0;
    this.valkyrieShootTimer = 0;
    // Energy will drain in update
  }

  _spawnVolley() {
    const t = this.elapsed;
    // Capped speed
    const baseSpeed    = Math.min(CAP_SPEED, 90 + t * 1.5);
    // Capped turn rate
    const baseTurnRate = Math.min(CAP_TURN_RATE, 0.55 + t * 0.012);
    // Homing budget still capped at 6s
    const baseHomingBudget = clamp(2.0 + t * 0.06, 2.0, 6.0);

    const count = this.volleyCount;
    for (let i = 0; i < count; i++) {
      const sy          = PLAY_TOP + 30 + Math.random() * (PLAY_BOTTOM - PLAY_TOP - 60);
      const angleSpread = (Math.random() - 0.5) * (Math.PI / 3);
      const initAngle   = Math.PI + angleSpread;
      const speed       = clamp(baseSpeed    * (0.8 + Math.random() * 0.5), 60, CAP_SPEED);
      const turnRate    = clamp(baseTurnRate * (0.6 + Math.random() * 0.8), 0.3, CAP_TURN_RATE);
      const homingBudget = baseHomingBudget * (0.7 + Math.random() * 0.6);

      this.missiles.push(
        new Missile(W + 10, sy, initAngle, speed, turnRate, homingBudget)
      );
    }
  }

  _gameOver(ex, ey) {
    this.dead = true;
    this.engine.audio.bad();
    this.explosion = { x: ex, y: ey, t: 0, dur: 1.2 };

    if (this.engine.storage.setHigh(meta.id, this.score)) {
      this.high = this.score;
    } else {
      this.high = this.engine.storage.getHigh(meta.id) || this.high;
    }
  }

  render(ctx) {
    const p = P();

    // ---- Play area background ----
    this.engine.rect(0, PLAY_TOP, W, PLAY_BOTTOM - PLAY_TOP, p.dark);

    // ---- Parallax starfield ----
    this._drawStars(ctx, p);

    // ---- Missiles (contrails + warheads) ----
    for (const m of this.missiles) {
      this._drawMissile(ctx, m, p);
    }

    // ---- Valkyrie beams ----
    if (this.beams.length > 0) {
      this._drawBeams(ctx, p);
    }

    // ---- Spark hit effects ----
    for (const s of this.sparks) {
      this._drawSpark(ctx, s, p);
    }

    // ---- Chaff decoy + chaff explosion flash ----
    if (this.chaff) {
      this._drawChaff(ctx, this.chaff, p);
    }
    if (this.chaffExplode) {
      this._drawChaffExplosion(ctx, this.chaffExplode, p);
    }

    // ---- Fighter ----
    const blink = this._invuln > 0 && (Math.floor(this._invuln * 12) % 2 === 0);
    if ((!this.dead && !blink) || (this.explosion && this.explosion.t < 0.15)) {
      if (this.valkyrieMode) {
        this._drawFighterValkyrie(ctx, this.fx, this.fy, p);
      } else {
        this._drawFighter(ctx, this.fx, this.fy, p);
      }
    }

    // ---- Hit effect ----
    if (this.hitFx) {
      const f = clamp(this.hitFx.t / this.hitFx.dur, 0, 1);
      ctx.save();
      ctx.globalAlpha = clamp(1 - f, 0, 1);
      ctx.strokeStyle = p.bad;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.arc(this.hitFx.x, this.hitFx.y, Math.max(1, 6 + f * 18), 0, Math.PI * 2);
      ctx.stroke();
      ctx.restore();
      ctx.globalAlpha = 1;
    }

    // ---- Death explosion ----
    if (this.explosion) {
      this._drawExplosion(ctx, this.explosion, p);
    }

    // ---- Lull "WAVE CLEAR" indicator ----
    if (this.lullMsgTimer > 0) {
      const alpha = clamp(Math.min(this.lullMsgTimer, LULL_DUR - this.lullTimer) * 2.5, 0, 1);
      const savedA = ctx.globalAlpha;
      ctx.globalAlpha = clamp(alpha * 0.65, 0, 1);
      this.engine.text('-- WAVE CLEAR --', W / 2, PLAY_TOP + 20, 13, p.dim, 'center');
      ctx.globalAlpha = clamp(savedA, 0, 1);
    }

    // ---- HUD ----
    this._drawHUD(ctx, p);

    // ---- On-screen buttons ----
    this._drawButtons(ctx, p);

    // ---- Game over overlay ----
    if (this.dead) {
      this._drawGameOver(ctx, p);
    }
  }

  _drawHUD(ctx, p) {
    // Title + time
    this.engine.text('DODGE', 52, 10, 20, p.fg, 'left');
    const secStr = (this.elapsed).toFixed(1) + 's';
    this.engine.text('TIME ' + secStr, 52, 34, 14, p.mid, 'left');

    // Best (top right)
    const hiSec = (this.high / 100).toFixed(1) + 's';
    this.engine.text('BEST ' + hiSec, W - 8, 10, 14, p.dim, 'right');

    // Lives (small plane icons, top right row 2)
    for (let i = 0; i < this.lives; i++) {
      const lx = W - 12 - i * 13;
      ctx.fillStyle = p.hi;
      ctx.beginPath();
      ctx.moveTo(lx, 30); ctx.lineTo(lx - 9, 34); ctx.lineTo(lx, 38);
      ctx.closePath();
      ctx.fill();
    }

    // Energy bar (bottom center, above buttons)
    const barW = W - 90;  // leave room for buttons on sides
    const barX = 45;
    const barY = H - 80;
    const barH = 6;
    const savedA = ctx.globalAlpha;

    ctx.globalAlpha = 0.5;
    ctx.fillStyle = p.dim;
    ctx.fillRect(barX, barY, barW, barH);

    const fillW = Math.floor(barW * clamp(this.energy, 0, 1));
    if (this.valkyrieMode) {
      // Pulsing gold when active
      const pulse = 0.7 + 0.3 * Math.sin(this.elapsed * 12);
      ctx.globalAlpha = clamp(pulse, 0, 1);
      ctx.fillStyle = p.warn;
    } else if (this.energy >= 1) {
      ctx.globalAlpha = 0.9;
      ctx.fillStyle = p.warn;
    } else {
      ctx.globalAlpha = 0.8;
      ctx.fillStyle = p.mid;
    }
    if (fillW > 0) ctx.fillRect(barX, barY, fillW, barH);

    // Energy label
    ctx.globalAlpha = 0.7;
    const energyLabel = this.valkyrieMode ? 'VLK' : this.energy >= 1 ? 'FULL' : 'NRG';
    this.engine.text(energyLabel, barX + barW / 2, barY - 13, 10, p.mid, 'center');

    ctx.globalAlpha = clamp(savedA, 0, 1);
  }

  _drawButtons(ctx, p) {
    const savedA = ctx.globalAlpha;

    // ---- FLARE button (bottom-left) ----
    const bf = BTN_FLARE;
    const flareAlpha = this.flares > 0 ? 0.85 : 0.30;
    ctx.globalAlpha = flareAlpha;
    ctx.fillStyle = p.dark;
    ctx.fillRect(bf.x, bf.y, bf.w, bf.h);
    ctx.strokeStyle = this.flares > 0 ? p.warn : p.dim;
    ctx.lineWidth = 1.5;
    ctx.strokeRect(bf.x, bf.y, bf.w, bf.h);

    ctx.globalAlpha = flareAlpha;
    this.engine.text('CHF', bf.x + bf.w / 2, bf.y + 6, 12, p.warn, 'center');
    this.engine.text(`x${this.flares}`, bf.x + bf.w / 2, bf.y + 24, 16, p.hi, 'center');

    // Regen progress pip
    if (this.flares < FLARE_MAX) {
      const regenFrac = clamp(this.flareRegenTimer / FLARE_REGEN_T, 0, 1);
      ctx.globalAlpha = 0.5;
      ctx.fillStyle = p.dim;
      ctx.fillRect(bf.x + 4, bf.y + bf.h - 8, bf.w - 8, 4);
      ctx.globalAlpha = 0.8;
      ctx.fillStyle = p.warn;
      ctx.fillRect(bf.x + 4, bf.y + bf.h - 8, Math.floor((bf.w - 8) * regenFrac), 4);
    }

    // ---- VALKYRIE button (bottom-right) ----
    const bv = BTN_VALKYRIE;
    const valkReady  = this.energy >= 1.0 && !this.valkyrieMode;
    const valkActive = this.valkyrieMode;
    const valkAlpha  = (valkReady || valkActive) ? 0.9 : 0.30;

    ctx.globalAlpha = valkAlpha;
    ctx.fillStyle = p.dark;
    ctx.fillRect(bv.x, bv.y, bv.w, bv.h);
    ctx.strokeStyle = valkActive ? p.warn : valkReady ? p.hi : p.dim;
    ctx.lineWidth = valkActive ? 2 : 1.5;
    ctx.strokeRect(bv.x, bv.y, bv.w, bv.h);

    ctx.globalAlpha = valkAlpha;
    const vLabel = valkActive ? 'VLK!' : 'VLK';
    const vColor = valkActive ? p.warn : valkReady ? p.hi : p.dim;
    this.engine.text(vLabel, bv.x + bv.w / 2, bv.y + 6, 12, vColor, 'center');
    const vSub = valkActive
      ? Math.ceil(this.valkyrieTimer) + 's'
      : valkReady ? 'RDY' : '';
    if (vSub) {
      this.engine.text(vSub, bv.x + bv.w / 2, bv.y + 24, 14, vColor, 'center');
    }

    ctx.globalAlpha = clamp(savedA, 0, 1);
    ctx.lineWidth = 1;
  }

  _drawBeams(ctx, p) {
    const savedA   = ctx.globalAlpha;
    const savedCap = ctx.lineCap;
    try {
      ctx.lineCap   = 'round';
      ctx.lineWidth = 2.5;
      for (const b of this.beams) {
        if (!b.trail || b.trail.length < 2) continue;
        for (let i = 1; i < b.trail.length; i++) {
          const prev = b.trail[i - 1];
          const cur  = b.trail[i];
          if (!prev || !cur) continue;
          const frac = i / b.trail.length;
          ctx.globalAlpha = clamp(frac * 0.9, 0, 1);
          ctx.strokeStyle = p.warn;
          ctx.beginPath();
          ctx.moveTo(prev.x, prev.y);
          ctx.lineTo(cur.x, cur.y);
          ctx.stroke();
        }
        // Bright tip
        ctx.globalAlpha = clamp(0.95, 0, 1);
        ctx.fillStyle = p.hi;
        ctx.beginPath();
        ctx.arc(b.x, b.y, 2.5, 0, Math.PI * 2);
        ctx.fill();
      }
    } finally {
      ctx.globalAlpha = clamp(savedA, 0, 1);
      ctx.lineCap     = savedCap;
      ctx.lineWidth   = 1;
    }
  }

  _drawSpark(ctx, s, p) {
    if (!s) return;
    const frac    = clamp(s.t / s.dur, 0, 1);
    const savedA  = ctx.globalAlpha;
    try {
      const r = 2 + frac * 12;
      ctx.globalAlpha = clamp((1 - frac) * 0.9, 0, 1);
      ctx.strokeStyle = p.warn;
      ctx.lineWidth   = 1.5;
      ctx.beginPath();
      ctx.arc(s.x, s.y, Math.max(1, r), 0, Math.PI * 2);
      ctx.stroke();
      ctx.globalAlpha = clamp((1 - frac * 1.5) * 0.8, 0, 1);
      ctx.fillStyle   = p.hi;
      ctx.beginPath();
      ctx.arc(s.x, s.y, Math.max(0.5, r * 0.3), 0, Math.PI * 2);
      ctx.fill();
    } finally {
      ctx.globalAlpha = clamp(savedA, 0, 1);
      ctx.lineWidth   = 1;
    }
  }

  // ---- Chaff decoy: bright sparkling/burning lure, draws all missiles toward it ----
  _drawChaff(ctx, ch, p) {
    if (!ch) return;
    const savedA = ctx.globalAlpha;
    const frac   = clamp(ch.t / ch.lifetime, 0, 1);
    // Flicker intensity: fast sine wave
    const flicker = 0.55 + 0.45 * Math.sin(ch.t * 28);
    try {
      // Faint attraction ring (grows as lifetime ticks down — shows danger zone)
      const ringR = 30 + frac * (CHAFF_EXPLODE_R - 30);
      ctx.globalAlpha = clamp(0.18 + 0.1 * Math.sin(ch.t * 6), 0, 1);
      ctx.strokeStyle = p.warn;
      ctx.lineWidth   = 1;
      ctx.beginPath();
      ctx.arc(ch.x, ch.y, ringR, 0, Math.PI * 2);
      ctx.stroke();

      // Outer glow
      ctx.globalAlpha = clamp(flicker * 0.35, 0, 1);
      ctx.fillStyle   = p.warn;
      ctx.beginPath();
      ctx.arc(ch.x, ch.y, 16, 0, Math.PI * 2);
      ctx.fill();

      // Core bright dot
      ctx.globalAlpha = clamp(flicker * 0.95, 0, 1);
      ctx.fillStyle   = p.hi;
      ctx.beginPath();
      ctx.arc(ch.x, ch.y, 5, 0, Math.PI * 2);
      ctx.fill();

      // Inner hot-orange nucleus
      ctx.globalAlpha = clamp(flicker * 0.8, 0, 1);
      ctx.fillStyle   = p.warn;
      ctx.beginPath();
      ctx.arc(ch.x, ch.y, 3, 0, Math.PI * 2);
      ctx.fill();

      // Spark particles orbiting + drifting
      for (const sp of ch.sparks) {
        const spFrac  = clamp(sp.t / (ch.lifetime * 1.2), 0, 1);
        const spAngle = sp.angle + sp.t * sp.speed * 2.5;
        const spDist  = sp.dist * (0.6 + 0.4 * Math.sin(sp.t * 3 + sp.t));
        const sx = ch.x + Math.cos(spAngle) * spDist;
        const sy = ch.y + Math.sin(spAngle) * spDist;
        ctx.globalAlpha = clamp((1 - spFrac) * flicker * 0.9, 0, 1);
        ctx.fillStyle   = Math.sin(sp.t * 7) > 0 ? p.hi : p.warn;
        ctx.beginPath();
        ctx.arc(sx, sy, 1.5, 0, Math.PI * 2);
        ctx.fill();
      }

      // Countdown pulse ring — urgency indicator
      const pulseR = 8 + Math.sin(ch.t * (6 + frac * 10)) * 6;
      ctx.globalAlpha = clamp(0.5 + frac * 0.4, 0, 1);
      ctx.strokeStyle = frac > 0.7 ? p.bad : p.warn;
      ctx.lineWidth   = 1.5;
      ctx.beginPath();
      ctx.arc(ch.x, ch.y, Math.max(1, pulseR), 0, Math.PI * 2);
      ctx.stroke();

    } finally {
      ctx.globalAlpha = clamp(savedA, 0, 1);
      ctx.lineWidth   = 1;
    }
  }

  // ---- Chaff end-of-life explosion burst ----
  _drawChaffExplosion(ctx, ex, p) {
    if (!ex) return;
    const frac   = clamp(ex.t / ex.dur, 0, 1);
    const savedA = ctx.globalAlpha;
    try {
      // Expanding shockwave ring
      const r1 = CHAFF_EXPLODE_R * frac;
      ctx.globalAlpha = clamp((1 - frac) * 0.9, 0, 1);
      ctx.strokeStyle = p.hi;
      ctx.lineWidth   = 3.5;
      ctx.beginPath();
      ctx.arc(ex.x, ex.y, Math.max(1, r1), 0, Math.PI * 2);
      ctx.stroke();

      // Second ring (warm)
      const r2 = CHAFF_EXPLODE_R * 0.65 * frac;
      ctx.globalAlpha = clamp((1 - frac * 1.5) * 0.75, 0, 1);
      ctx.strokeStyle = p.warn;
      ctx.lineWidth   = 5;
      ctx.beginPath();
      ctx.arc(ex.x, ex.y, Math.max(1, r2), 0, Math.PI * 2);
      ctx.stroke();

      // Central flash
      if (frac < 0.3) {
        ctx.globalAlpha = clamp((0.3 - frac) / 0.3 * 0.7, 0, 1);
        ctx.fillStyle   = p.hi;
        ctx.beginPath();
        ctx.arc(ex.x, ex.y, 30, 0, Math.PI * 2);
        ctx.fill();
      }
    } finally {
      ctx.globalAlpha = clamp(savedA, 0, 1);
      ctx.lineWidth   = 1;
    }
  }

  // ---- Parallax starfield ----
  _drawStars(ctx, p) {
    const savedAlpha = ctx.globalAlpha;
    try {
      for (const layer of this.starLayers) {
        const { cfg, stars } = layer;
        ctx.fillStyle = p.hi;
        ctx.globalAlpha = clamp(cfg.alpha, 0, 1);
        for (const s of stars) {
          ctx.fillRect(s.x, s.y, cfg.size, cfg.size);
        }
      }
    } finally {
      ctx.globalAlpha = clamp(savedAlpha, 0, 1);
    }
  }

  // ---- Missile draw: long white contrail + oriented warhead ----
  _drawMissile(ctx, m, p) {
    if (!m || m.dead) return;
    const trail = m.trail;
    if (!trail || trail.length < 2) {
      if (!m.exploding) this._drawMissileHead(ctx, m, p);
      return;
    }

    const savedAlpha     = ctx.globalAlpha;
    const savedLineCap   = ctx.lineCap;
    const savedLineJoin  = ctx.lineJoin;
    const savedLineWidth = ctx.lineWidth;

    try {
      ctx.lineCap  = 'round';
      ctx.lineJoin = 'round';

      const len = trail.length;

      let globalFade = 1.0;
      if (!m.homing) {
        globalFade = clamp(1 - m.disengageTime * 0.12, 0.08, 1);
      }
      if (m.exploding) {
        globalFade *= clamp(1 - m.explodeTimer / m.explodeDur, 0, 1) * 0.6;
      }

      ctx.strokeStyle = p.hi;
      ctx.lineWidth   = 1.2;

      for (let i = 1; i < len; i++) {
        const prev = trail[i - 1];
        const cur  = trail[i];
        if (!prev || !cur) continue;
        const frac  = i / len;
        const alpha = clamp((frac * 0.85 + 0.06) * globalFade, 0, 1);
        if (alpha < 0.005) continue;
        ctx.globalAlpha = alpha;
        ctx.beginPath();
        ctx.moveTo(prev.x, prev.y);
        ctx.lineTo(cur.x, cur.y);
        ctx.stroke();
      }

      if (!m.exploding) {
        this._drawMissileHead(ctx, m, p);
      }

      if (m.exploding && trail.length > 0) {
        const ex = trail[trail.length - 1];
        if (ex) {
          this._drawMissileExplosion(ctx, ex.x, ex.y, m.explodeTimer / m.explodeDur, p);
        }
      }

    } finally {
      ctx.globalAlpha = clamp(savedAlpha, 0, 1);
      ctx.lineCap     = savedLineCap;
      ctx.lineJoin    = savedLineJoin;
      ctx.lineWidth   = savedLineWidth;
    }
  }

  _drawMissileHead(ctx, m, p) {
    if (!m) return;
    const savedAlpha = ctx.globalAlpha;
    try {
      ctx.globalAlpha = 1;
      ctx.save();
      ctx.translate(m.x, m.y);
      ctx.rotate(m.angle);

      ctx.fillStyle = p.hi;
      ctx.beginPath();
      ctx.moveTo(10, 0); ctx.lineTo(4, -2); ctx.lineTo(4, 2);
      ctx.closePath(); ctx.fill();

      ctx.fillStyle = p.warn;
      ctx.beginPath(); ctx.rect(-4, -2, 8, 4); ctx.fill();

      ctx.fillStyle = p.hi;
      ctx.beginPath(); ctx.rect(0, -1, 4, 2); ctx.fill();

      ctx.fillStyle = p.warn;
      ctx.beginPath();
      ctx.moveTo(-4, -2); ctx.lineTo(-8, -6); ctx.lineTo(-4, 0);
      ctx.closePath(); ctx.fill();
      ctx.beginPath();
      ctx.moveTo(-4, 2); ctx.lineTo(-8, 6); ctx.lineTo(-4, 0);
      ctx.closePath(); ctx.fill();

      ctx.fillStyle = p.warn;
      ctx.globalAlpha = clamp(0.85, 0, 1);
      ctx.beginPath();
      ctx.moveTo(-4, -1.5); ctx.lineTo(-9, 0); ctx.lineTo(-4, 1.5);
      ctx.closePath(); ctx.fill();

      ctx.restore();
    } finally {
      ctx.globalAlpha = clamp(savedAlpha, 0, 1);
    }
  }

  _drawMissileExplosion(ctx, x, y, frac, p) {
    if (typeof x !== 'number' || typeof y !== 'number') return;
    const r = 3 + frac * 18;
    const savedAlpha = ctx.globalAlpha;
    try {
      ctx.globalAlpha = clamp((1 - frac) * 0.9, 0, 1);
      ctx.strokeStyle = p.warn;
      ctx.lineWidth   = 1.5;
      ctx.beginPath(); ctx.arc(x, y, r, 0, Math.PI * 2); ctx.stroke();
      ctx.globalAlpha = clamp((1 - frac * 2) * 0.8, 0, 1);
      ctx.fillStyle   = p.hi;
      ctx.beginPath(); ctx.arc(x, y, r * 0.45, 0, Math.PI * 2); ctx.fill();
    } finally {
      ctx.globalAlpha = clamp(savedAlpha, 0, 1);
    }
  }

  // ---- Standard F-14 fighter ----
  _drawFighter(ctx, x, y, p) {
    const savedAlpha = ctx.globalAlpha;
    ctx.save();
    ctx.translate(x, y);
    try {
      const WHITE = p.hi, TRIM = p.mid, GLASS = p.dark;

      ctx.fillStyle = WHITE;
      ctx.beginPath();
      ctx.moveTo(9, -3); ctx.lineTo(-4, -16); ctx.lineTo(-8, -15); ctx.lineTo(-2, -3);
      ctx.closePath(); ctx.fill();
      ctx.beginPath();
      ctx.moveTo(9, 3); ctx.lineTo(-4, 16); ctx.lineTo(-8, 15); ctx.lineTo(-2, 3);
      ctx.closePath(); ctx.fill();

      ctx.beginPath();
      ctx.moveTo(-7, -2); ctx.lineTo(-13, -10); ctx.lineTo(-15, -9); ctx.lineTo(-11, -2);
      ctx.closePath(); ctx.fill();
      ctx.beginPath();
      ctx.moveTo(-7, 2); ctx.lineTo(-13, 10); ctx.lineTo(-15, 9); ctx.lineTo(-11, 2);
      ctx.closePath(); ctx.fill();

      ctx.fillStyle = WHITE;
      ctx.beginPath();
      ctx.moveTo(8, -7); ctx.lineTo(-13, -7); ctx.lineTo(-13, 7); ctx.lineTo(8, 7);
      ctx.closePath(); ctx.fill();
      ctx.strokeStyle = TRIM; ctx.lineWidth = 1;
      ctx.strokeRect(-13, -7, 21, 4);
      ctx.strokeRect(-13,  3, 21, 4);

      ctx.fillStyle = WHITE;
      ctx.beginPath();
      ctx.moveTo(19, 0); ctx.lineTo(8, -3); ctx.lineTo(2, -5); ctx.lineTo(-2, -5);
      ctx.lineTo(-2, 5); ctx.lineTo(2, 5); ctx.lineTo(8, 3);
      ctx.closePath(); ctx.fill();
      ctx.strokeStyle = TRIM; ctx.lineWidth = 1;
      ctx.beginPath(); ctx.moveTo(19, 0); ctx.lineTo(2, 0); ctx.stroke();

      ctx.fillStyle = GLASS;
      ctx.beginPath();
      ctx.ellipse(11, 0, 4, 1.8, 0, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = TRIM;
      ctx.beginPath();
      ctx.moveTo(-4, -5); ctx.lineTo(-12, -9); ctx.lineTo(-13, -7); ctx.lineTo(-6, -4);
      ctx.closePath(); ctx.fill();
      ctx.beginPath();
      ctx.moveTo(-4, 5); ctx.lineTo(-12, 9); ctx.lineTo(-13, 7); ctx.lineTo(-6, 4);
      ctx.closePath(); ctx.fill();

      ctx.globalAlpha = clamp(savedAlpha, 0, 1);
      const flameLen = 6 + Math.sin(this.flameTick * 18) * 3;
      for (const ey of [-5, 5]) {
        ctx.fillStyle = p.warn; ctx.globalAlpha = clamp(0.9, 0, 1);
        ctx.beginPath();
        ctx.moveTo(-13, ey - 1.5); ctx.lineTo(-13 - flameLen, ey); ctx.lineTo(-13, ey + 1.5);
        ctx.closePath(); ctx.fill();
        ctx.fillStyle = p.hi; ctx.globalAlpha = clamp(0.75, 0, 1);
        ctx.beginPath();
        ctx.moveTo(-13, ey - 1); ctx.lineTo(-13 - flameLen * 0.55, ey); ctx.lineTo(-13, ey + 1);
        ctx.closePath(); ctx.fill();
      }
    } finally {
      ctx.restore();
      ctx.globalAlpha = clamp(savedAlpha, 0, 1);
    }
  }

  // ---- Valkyrie battroid (humanoid robot) — facing right, gun-arm extends right ----
  // Coordinate system: x+ = right (forward), y+ = down. Robot is ~38px wide, ~44px tall.
  //   HEAD  : small box centered around (6, -18)
  //   TORSO : main rectangle from (-4,-13) to (10,2)
  //   WAIST : narrow link at (0,-2) to (6,2)
  //   HIPS  : box (-2,2) to (8,8)
  //   LEGS  : two rects below hips, slightly angled
  //   GUN ARM (right/forward): extends from shoulder at (10,-10) forward to (26,-10)
  //   LEFT ARM : shorter, behind at (-4,-10) extending back
  //   SHOULDER FINS: swept back decorative plates
  _drawFighterValkyrie(ctx, x, y, p) {
    const savedAlpha = ctx.globalAlpha;
    ctx.save();
    ctx.translate(x, y);
    try {
      const pulse = 0.28 + 0.22 * Math.sin(this.elapsed * 14);

      // --- Aura glow ---
      ctx.globalAlpha = clamp(pulse * 0.55, 0, 1);
      ctx.fillStyle   = p.warn;
      ctx.beginPath();
      ctx.arc(2, -4, 28, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = clamp(pulse * 0.35, 0, 1);
      ctx.fillStyle   = p.hi;
      ctx.beginPath();
      ctx.arc(2, -4, 16, 0, Math.PI * 2);
      ctx.fill();

      ctx.globalAlpha = clamp(savedAlpha, 0, 1);

      // ---- LEGS (draw first so body overlaps) ----
      // Right leg (lower, forward-right in robot space = down-right on screen)
      ctx.fillStyle = p.mid;
      // Thigh right
      ctx.beginPath();
      ctx.moveTo(2, 8); ctx.lineTo(6, 8); ctx.lineTo(8, 18); ctx.lineTo(2, 18);
      ctx.closePath(); ctx.fill();
      // Shin right (slightly wider, knee protrusion)
      ctx.fillStyle = p.fg;
      ctx.beginPath();
      ctx.moveTo(1, 18); ctx.lineTo(8, 18); ctx.lineTo(9, 26); ctx.lineTo(0, 26);
      ctx.closePath(); ctx.fill();
      // Foot right
      ctx.fillStyle = p.mid;
      ctx.fillRect(-2, 24, 13, 4);

      // Left leg (slightly offset, mirrored vertically = up on canvas)
      ctx.fillStyle = p.mid;
      // Thigh left
      ctx.beginPath();
      ctx.moveTo(-4, 8); ctx.lineTo(0, 8); ctx.lineTo(-1, 18); ctx.lineTo(-6, 18);
      ctx.closePath(); ctx.fill();
      // Shin left
      ctx.fillStyle = p.fg;
      ctx.beginPath();
      ctx.moveTo(-7, 18); ctx.lineTo(0, 18); ctx.lineTo(-1, 26); ctx.lineTo(-8, 26);
      ctx.closePath(); ctx.fill();
      // Foot left
      ctx.fillStyle = p.mid;
      ctx.fillRect(-10, 24, 12, 4);

      // ---- HIPS ----
      ctx.fillStyle = p.warn;
      ctx.fillRect(-3, 4, 12, 6);
      // Hip highlight
      ctx.fillStyle = p.hi;
      ctx.fillRect(0, 5, 6, 2);

      // ---- WAIST ----
      ctx.fillStyle = p.mid;
      ctx.fillRect(-1, 1, 9, 5);

      // ---- TORSO (chest) ----
      ctx.fillStyle = p.warn;
      ctx.beginPath();
      // Slightly trapezoidal chest, wider at shoulders
      ctx.moveTo(-3, 1);    // lower-left
      ctx.lineTo(10, 1);    // lower-right
      ctx.lineTo(13, -6);   // upper-right (shoulder)
      ctx.lineTo(8, -14);   // upper-chest right
      ctx.lineTo(-2, -14);  // upper-chest left
      ctx.lineTo(-6, -6);   // upper-left (shoulder)
      ctx.closePath();
      ctx.fill();

      // Chest V-fin / armor plate highlight
      ctx.fillStyle = p.hi;
      ctx.beginPath();
      ctx.moveTo(4, -1); ctx.lineTo(9, -1); ctx.lineTo(11, -8); ctx.lineTo(6, -12); ctx.lineTo(2, -8);
      ctx.closePath(); ctx.fill();

      // Cockpit eye / chest gem — glowing
      const eyePulse = 0.7 + 0.3 * Math.sin(this.elapsed * 18);
      ctx.globalAlpha = clamp(eyePulse, 0, 1);
      ctx.fillStyle   = p.warn;
      ctx.beginPath();
      ctx.ellipse(6, -6, 4, 2.5, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = p.hi;
      ctx.beginPath();
      ctx.ellipse(6, -6, 2.5, 1.2, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = clamp(savedAlpha, 0, 1);

      // ---- SHOULDER FINS (swept-back decorative plates on each shoulder) ----
      ctx.fillStyle = p.mid;
      // Right shoulder fin (top shoulder = negative y)
      ctx.beginPath();
      ctx.moveTo(8, -14); ctx.lineTo(14, -20); ctx.lineTo(6, -20); ctx.lineTo(4, -14);
      ctx.closePath(); ctx.fill();
      // Left shoulder fin
      ctx.beginPath();
      ctx.moveTo(-2, -14); ctx.lineTo(-10, -20); ctx.lineTo(-6, -20); ctx.lineTo(-4, -14);
      ctx.closePath(); ctx.fill();
      // Fin highlights
      ctx.fillStyle = p.fg;
      ctx.beginPath();
      ctx.moveTo(8, -14); ctx.lineTo(12, -18); ctx.lineTo(8, -18); ctx.lineTo(6, -14);
      ctx.closePath(); ctx.fill();

      // ---- LEFT ARM (rear, angled back) ----
      ctx.fillStyle = p.mid;
      ctx.beginPath();
      ctx.moveTo(-3, -12); ctx.lineTo(-7, -12); ctx.lineTo(-14, -6); ctx.lineTo(-11, -4); ctx.lineTo(-5, -8);
      ctx.closePath(); ctx.fill();
      // Fist / hand
      ctx.fillStyle = p.fg;
      ctx.beginPath();
      ctx.moveTo(-14, -6); ctx.lineTo(-18, -8); ctx.lineTo(-19, -4); ctx.lineTo(-14, -3);
      ctx.closePath(); ctx.fill();

      // ---- GUN ARM (right, forward — extends toward missiles) ----
      // Upper arm from shoulder
      ctx.fillStyle = p.mid;
      ctx.beginPath();
      ctx.moveTo(11, -10); ctx.lineTo(11, -14); ctx.lineTo(20, -12); ctx.lineTo(20, -8);
      ctx.closePath(); ctx.fill();
      // Forearm / gun barrel housing
      ctx.fillStyle = p.warn;
      ctx.beginPath();
      ctx.moveTo(20, -13); ctx.lineTo(20, -7); ctx.lineTo(28, -8); ctx.lineTo(28, -12);
      ctx.closePath(); ctx.fill();
      // Gun barrel (twin)
      ctx.fillStyle = p.hi;
      ctx.fillRect(25, -13, 10, 2.5);   // upper barrel
      ctx.fillRect(25, -9,  10, 2.5);   // lower barrel
      // Muzzle flash/glow during auto-fire
      const shooting = this.valkyrieShootTimer < 0.05;
      if (shooting) {
        const mPulse = 0.9;
        ctx.globalAlpha = clamp(mPulse, 0, 1);
        ctx.fillStyle   = p.warn;
        ctx.beginPath();
        ctx.arc(36, -10, 5, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = p.hi;
        ctx.beginPath();
        ctx.arc(36, -10, 2.5, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = clamp(savedAlpha, 0, 1);
      }

      // ---- HEAD ----
      // Neck
      ctx.fillStyle = p.mid;
      ctx.fillRect(2, -17, 5, 4);
      // Head box
      ctx.fillStyle = p.warn;
      ctx.fillRect(-1, -26, 11, 10);
      // Helmet highlight
      ctx.fillStyle = p.hi;
      ctx.fillRect(0, -25, 9, 3);
      // Visor / sensor band (glowing)
      const visorPulse = 0.8 + 0.2 * Math.sin(this.elapsed * 10);
      ctx.globalAlpha = clamp(visorPulse, 0, 1);
      ctx.fillStyle   = p.warn;
      ctx.fillRect(1, -21, 8, 3);
      ctx.fillStyle   = p.hi;
      ctx.fillRect(3, -21, 4, 2);
      ctx.globalAlpha = clamp(savedAlpha, 0, 1);
      // Side antenna
      ctx.fillStyle = p.mid;
      ctx.fillRect(8, -29, 2, 5);
      ctx.fillRect(-2, -27, 2, 4);

      // ---- THRUSTER PACK / BACKPACK (left side of robot = down on canvas) ----
      ctx.fillStyle = p.mid;
      ctx.fillRect(-8, -10, 6, 10);
      // Thruster nozzles
      const flameLen = 10 + Math.sin(this.flameTick * 22) * 5;
      for (const ey of [-7, -1]) {
        ctx.fillStyle   = p.warn;
        ctx.globalAlpha = clamp(1.0, 0, 1);
        ctx.beginPath();
        ctx.moveTo(-8, ey - 2); ctx.lineTo(-8 - flameLen, ey + 1); ctx.lineTo(-8, ey + 2.5);
        ctx.closePath(); ctx.fill();
        ctx.fillStyle   = p.hi;
        ctx.globalAlpha = clamp(0.85, 0, 1);
        ctx.beginPath();
        ctx.moveTo(-8, ey - 1); ctx.lineTo(-8 - flameLen * 0.55, ey + 0.5); ctx.lineTo(-8, ey + 1.5);
        ctx.closePath(); ctx.fill();
      }
      ctx.globalAlpha = clamp(savedAlpha, 0, 1);

    } finally {
      ctx.restore();
      ctx.globalAlpha = clamp(savedAlpha, 0, 1);
    }
  }

  _drawExplosion(ctx, exp, p) {
    const frac = exp.t / exp.dur;
    const r    = 8 + frac * 60;
    const savedAlpha = ctx.globalAlpha;
    try {
      ctx.globalAlpha = clamp((1 - frac) * 0.8, 0, 1);
      ctx.strokeStyle = p.bad;
      ctx.lineWidth   = 3;
      ctx.beginPath();
      ctx.arc(exp.x, exp.y, r, 0, Math.PI * 2);
      ctx.stroke();

      ctx.globalAlpha = clamp((1 - frac * 2) * 0.9, 0, 1);
      ctx.fillStyle   = p.warn;
      ctx.beginPath();
      ctx.arc(exp.x, exp.y, r * 0.5, 0, Math.PI * 2);
      ctx.fill();

      ctx.globalAlpha = clamp((1 - frac * 3) * 1.0, 0, 1);
      ctx.fillStyle   = p.hi;
      ctx.beginPath();
      ctx.arc(exp.x, exp.y, r * 0.2, 0, Math.PI * 2);
      ctx.fill();
    } finally {
      ctx.globalAlpha = clamp(savedAlpha, 0, 1);
      ctx.lineWidth   = 1;
    }
  }

  _drawGameOver(ctx, p) {
    const savedAlpha = ctx.globalAlpha;
    try {
      ctx.globalAlpha = clamp(0.82, 0, 1);
      ctx.fillStyle   = p.dark;
      ctx.fillRect(30, H / 2 - 90, W - 60, 200);
    } finally {
      ctx.globalAlpha = clamp(savedAlpha, 0, 1);
    }
    this.engine.stroke(30, H / 2 - 90, W - 60, 200, p.bad, 2);

    this.engine.text('GAME OVER', W / 2, H / 2 - 72, 30, p.bad, 'center');

    const secStr = (this.elapsed).toFixed(1) + 's';
    this.engine.text('TIME  ' + secStr, W / 2, H / 2 - 28, 20, p.fg, 'center');

    const hiSec = (this.high / 100).toFixed(1) + 's';
    this.engine.text('BEST  ' + hiSec, W / 2, H / 2 + 4, 16, p.dim, 'center');

    const blink = Math.floor(this.elapsed * 3) % 2 === 0;
    if (blink) {
      this.engine.text('TAP TO RETRY', W / 2, H / 2 + 50, 16, p.mid, 'center');
    }
    this.engine.text('‹ BACK to menu', W / 2, H / 2 + 78, 12, p.dim, 'center');
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/meteor.js ----
(function(){
// METEOR : ゆっくり迫る隕石をミサイルで迎撃するストラテジー防衛ゲーム。
// ステージ制：序盤は1個ずつ読んで破壊、徐々に密度が上がりステージ末にボス隕石登場。
// 全都市が破壊されたらゲームオーバー。
// 各都市が発射台。MULTI/POWER/WIDE/SCATTER/RAPIDアイテムで戦力強化。

const meta = {
  id: 'meteor',
  title: 'METEOR',
  desc: '降る隕石を迎撃して街を守れ',
  glyph: '*',
};

// ---- 定数 ----
const CITY_COUNT  = 5;
const CITY_W      = 28;
const CITY_H      = 22;  // 少し高くして山シルエットに
const GROUND_Y    = H - 40;

// ミサイル
const MISSILE_SPD    = 115;  // px/s
const FIRE_COOLDOWN  = 0.55; // 発射間隔（秒）

// 同時飛翔上限（通常）
const MISSILES_CAP_NORMAL = 4;
// RAPID中の同時飛翔上限 = min(launcherSlots * shotsPerCity, 10)
const MISSILES_CAP_RAPID  = 10;

// 爆発 — grow then FADE OUT (alpha, no shrink)
const BLAST_GROW      = 38;   // 通常爆発最大半径
const BLAST_GROW_BIG  = 115;  // ビッグ爆発最大半径
const BLAST_GROW_RATE = 50;   // 拡大速度 px/s
const BLAST_FADE_SEC  = 1.2;  // フェードアウト時間（秒）

// ビッグブラスト残弾
const BIG_CHARGES_MAX  = 3;
const BIG_RECHARGE_SEC = 14;

// 通常ブラストダメージ（パワーアップで増加）
const BLAST_DAMAGE_NORMAL_BASE = 1;
const BLAST_DAMAGE_BIG         = 3;

// ---- 隕石速度 ----
const METEOR_SPD_MIN      = 2;
const METEOR_SPD_MAX      = 5;
const METEOR_SPD_MAX_LATE = 7;

const FAST_CHANCE  = 0.10;
const FAST_SPD_MIN = 14;
const FAST_SPD_MAX = 24;

// 隕石サイズ
const METEOR_R_MIN   = 7;
const METEOR_R_MAX   = 34;
const GIANT_R_THRESH = 22;
const SMALL_R_THRESH = 10;
const LARGE_R_THRESH = 16;

// ボス隕石 — 1.2倍スケール（r≒150-185）、画面幅に収まりつつ迫力を保つ
const BOSS_R_MIN   = 150;  // 縮小（旧230→150）
const BOSS_R_MAX   = 185;  // 縮小（旧255→185）
const BOSS_SPD_MIN = 2.5;  // 速度を大幅増（旧0.7）→ ぐんぐん迫る
const BOSS_SPD_MAX = 3.8;  // 速度を大幅増（旧1.2）
const BOSS_HP_BASE = 16;   // HP削減（旧30→16）
const BOSS_HP_PER_STAGE = 3; // HP増加（旧6→3）

// スコア
const METEOR_SCORE_BASE = 10;
const BOSS_SCORE_BASE   = 250;

// スキャッター特殊弾 弾数上限
const SCATTER_AMMO_PER_PICKUP = 3;

// バフタイマー（秒）— POWER/WIDE/SPEEDバフは有限時間後に消える（FIFOスタック）
const BUFF_DURATION = 18;

// RAPIDバフ（時間制限）
const RAPID_DURATION    = 10; // 秒
const RAPID_SHOTS_CITY  = 2;  // 1都市あたりの同時発射数
const RAPID_COOLDOWN    = 0.28; // RAPIDバフ中の発射間隔短縮

// ---- ステージタイプ ----
const STAGE_TYPES = [
  'NORMAL',
  'FAST',
  'SWARM',
  'TINY',
  'GIANT',
  'CHAOS',
];

// ---- アイテム種別 ----
// 'MULTI'  : launcherSlots +1（最大5）— 持続効果
// 'POWER'  : 撃った都市の通常ダメージ+1 — 一時バフ（有限タイマー）
// 'WIDE'   : 撃った都市の爆発半径+12 — 一時バフ
// 'SCATTER': 3発のスキャッター特殊弾を付与（グローバル弾薬）
// 'RAPID'  : 時間限定 連射強化（1都市2発・上限10、RAPID_DURATIONs）
const ITEM_TYPES = ['MULTI', 'POWER', 'WIDE', 'SCATTER', 'RAPID'];

// ---- HP計算 ----
function calcMeteorHP(r) {
  if (r < SMALL_R_THRESH)  return 1;
  if (r < LARGE_R_THRESH)  return 2;
  if (r < GIANT_R_THRESH)  return 3;
  return 4;
}

// ---- ステージスクリプト生成 ----
function makeStageScript(stage, stageType) {
  const events = [];
  let baseDelay  = Math.max(3.5 - stage * 0.25, 1.1);
  let bossT      = 72 + stage * 4;
  let itemChance = Math.min(0.08 + stage * 0.025, 0.22);

  if (stageType === 'SWARM') { baseDelay *= 0.5; bossT = 55 + stage * 3; }
  if (stageType === 'FAST')  { bossT = 60 + stage * 3; }
  if (stageType === 'CHAOS') { baseDelay *= 0.65; bossT = 58 + stage * 3; }

  let t = 0;
  events.push({ t, type: 'meteor', count: 1, forceSize: null, itemChance });
  t += baseDelay * 2.0;
  events.push({ t, type: 'meteor', count: 1, forceSize: null, itemChance });
  t += baseDelay * 1.8;

  const midGiant = (stageType === 'GIANT');
  const midTiny  = (stageType === 'TINY');
  events.push({ t, type: 'meteor', count: 1, forceSize: midGiant ? 'giant' : (midTiny ? 'tiny' : null), itemChance });
  t += baseDelay * 1.5;

  let waveMax = 2;
  if (stageType === 'SWARM')       waveMax = 5;
  else if (stageType === 'CHAOS')  waveMax = 4;
  else                             waveMax = Math.min(1 + Math.floor(stage / 2), 3);

  events.push({ t, type: 'meteor', count: waveMax, forceSize: midGiant ? 'giant' : (midTiny ? 'tiny' : null), itemChance });
  t += baseDelay * 1.4;
  events.push({ t, type: 'meteor', count: 1, forceSize: null, itemChance });
  t += baseDelay * 1.3;
  events.push({ t, type: 'meteor', count: Math.min(1 + Math.floor(stage / 1.5), 4), forceSize: midGiant ? 'giant' : (midTiny ? 'tiny' : null), itemChance });
  t += baseDelay * 1.2;

  let numLate = Math.min(2 + stage, 6);
  if (stageType === 'SWARM') numLate = Math.min(numLate + 3, 9);
  if (stageType === 'CHAOS') numLate = Math.min(numLate + 2, 7);

  while (t < bossT - 10) {
    const cnt  = Math.min(1 + Math.floor(Math.random() * numLate), numLate);
    const giant = (stageType === 'GIANT') || (stageType === 'CHAOS' && Math.random() < 0.3) || Math.random() < 0.15;
    const tiny  = (stageType === 'TINY') || (Math.random() < 0.05);
    events.push({
      t, type: 'meteor', count: cnt,
      forceSize: giant ? 'giant' : (tiny ? 'tiny' : null),
      itemChance,
    });
    const minGap = stageType === 'SWARM' ? 0.5 : 0.9;
    t += Math.max(baseDelay * (0.85 - stage * 0.04), minGap);
  }

  events.push({ t: bossT, type: 'boss' });
  return events;
}

// ---- 岩石ポリゴン頂点 ----
function makeRockVerts(r, seed) {
  const count = 8 + Math.floor((seed % 4));
  const verts = [];
  for (let i = 0; i < count; i++) {
    const baseAngle = (i / count) * Math.PI * 2;
    const s1 = Math.sin(seed * 31.7 + i * 12.3);
    const s2 = Math.sin(seed * 17.1 + i * 7.9);
    const angleJitter = (s1 * 0.5) / count;
    const angle = baseAngle + angleJitter;
    const rFrac = 0.60 + 0.50 * ((s2 + 1) / 2);
    verts.push({ dx: Math.cos(angle) * r * rFrac, dy: Math.sin(angle) * r * rFrac });
  }
  return verts;
}

// ---- ユニークID ----
let _nextBlastId    = 1;
let _nextMeteorSeed = 1;

// ---- ヘルパー ----
function clamp(v, lo, hi) { return v < lo ? lo : v > hi ? hi : v; }

function stageSpeedMult(stageType) {
  if (stageType === 'FAST')  return 2.8;
  if (stageType === 'SWARM') return 1.4;
  if (stageType === 'TINY')  return 2.2;
  if (stageType === 'CHAOS') return 2.0;
  return 1.0;
}

// ---- 都市X座標（均等配置）----
const CITY_SPACING = (W - CITY_W * CITY_COUNT) / (CITY_COUNT + 1);
const CITY_XS = Array.from({ length: CITY_COUNT }, (_, i) =>
  Math.floor(CITY_SPACING + i * (CITY_W + CITY_SPACING))
);

// ---- 都市のシルエットポリゴン生成（山と街並み）----
// 都市ごとに固定シードで生成、毎フレーム生成しないよう事前作成
function makeCityProfile(idx) {
  // 山のシルエット + 街並みの屋根ライン（W=CITY_W, H=CITY_H）
  // 返り値: [{x,y}] のポリゴン（都市ローカル座標、左下=0,CITY_H、右下=CITY_W,CITY_H）
  const seed = idx * 137 + 29;
  const pts  = [];

  // 地面の左端
  pts.push({ x: 0, y: CITY_H });

  // 左の山稜
  const mh1 = 10 + (seed % 5);       // 山の高さ
  pts.push({ x: 0, y: CITY_H - mh1 });
  pts.push({ x: 4 + (seed % 3), y: CITY_H - mh1 - 3 });

  // 中央ビルA（背の高い）
  const bw1 = 5; const bh1 = 14 + ((seed * 7) % 5);
  const bx1 = 5 + (seed % 3);
  pts.push({ x: bx1, y: CITY_H - mh1 });
  pts.push({ x: bx1, y: CITY_H - bh1 });
  pts.push({ x: bx1 + bw1, y: CITY_H - bh1 });

  // アンテナ塔（細い）
  const tx = bx1 + Math.floor(bw1 / 2);
  pts.push({ x: tx, y: CITY_H - bh1 - 4 });
  pts.push({ x: tx, y: CITY_H - bh1 });

  // 隣の小さいビルB
  const bx2 = bx1 + bw1 + 1;
  const bh2 = 8 + ((seed * 3) % 4);
  pts.push({ x: bx2, y: CITY_H - bh2 });
  pts.push({ x: bx2 + 4, y: CITY_H - bh2 });

  // 右寄りの山稜
  const mh2 = 7 + ((seed * 11) % 5);
  pts.push({ x: CITY_W - 5, y: CITY_H - mh2 });
  pts.push({ x: CITY_W - 2, y: CITY_H - mh2 - 5 });
  pts.push({ x: CITY_W, y: CITY_H - mh2 });

  // 地面右端
  pts.push({ x: CITY_W, y: CITY_H });

  return pts;
}

// 都市プロファイルを事前生成
const CITY_PROFILES = Array.from({ length: CITY_COUNT }, (_, i) => makeCityProfile(i));

// ---- バフスタック管理（FIFOタイマー）----
// city.buffs = { power: [{timer},...], wide: [{timer},...] }
function makeCityBuffs() {
  return { power: [], wide: [] };
}

function updateCityBuffs(buffs, dt) {
  for (const key of ['power', 'wide']) {
    for (let i = buffs[key].length - 1; i >= 0; i--) {
      buffs[key][i].timer -= dt;
      if (buffs[key][i].timer <= 0) buffs[key].splice(i, 1);
    }
  }
}

function cityBuffPower(buffs) {
  return BLAST_DAMAGE_NORMAL_BASE + buffs.power.length;
}

function cityBuffRadiusAdd(buffs) {
  return buffs.wide.length * 12;
}

// ---- コース・ピクセルスペックル爆発（Missile Command 風）----
// フラットな赤雲・XOR合成・月輪リムを廃止し、
// 大きな正方形セル（~8px）を高速カラーサイクルで埋めるスペックルで置換。
// セル色は毎1〜2フレームごとにランダム化されフラッシュ白に見える。
// 円境界は大セルのブロックエッジで自然にガタガタになる（狙い通り）。

// スペックル色セット：ビビッド多色 + 約28%をブラック（ネガティブ）
const _SPECKLE_COLORS = [
  '#ffffff', // 白（最も多く出ることで「フラッシュ白」に見える）
  '#ffffff',
  '#ffffff',
  '#00ff88', // 輝くグリーン
  '#ff00ff', // マゼンタ
  '#00ffff', // シアン
  '#ffff00', // 黄
  '#ff4400', // 赤オレンジ
  '#ff9900', // オレンジ
  '#4466ff', // ブルー
  '#000000', // ブラック（ネガティブ）
  '#000000', // ブラック
  '#000000', // ブラック（全14色中3色 ≒ 21%、白3+ブラック3=43%でコントラスト）
  '#ffffff',
];
const _SPECKLE_COLOR_COUNT = _SPECKLE_COLORS.length; // 14

// セルサイズ（論理px）— 大きいほどブロッキーでレトロらしい
const _CELL = 8;

// 高速シードPRNG（xorshift32相当の整数ハッシュ）
// 引数はすべて整数化済みと仮定。戻り値 0〜1 の float。
function _speckleRand(cx, cy, blastId, tick) {
  // Wang hash 風のビット混合
  let h = (cx * 2246822519) ^ (cy * 3266489917) ^ (blastId * 668265263) ^ (tick * 374761393);
  h = Math.imul(h ^ (h >>> 16), 0x45d9f3b);
  h = Math.imul(h ^ (h >>> 16), 0x45d9f3b);
  h = (h ^ (h >>> 16)) >>> 0;
  return (h & 0xffff) / 0x10000; // 0〜0.9999...
}

// 全爆発をスペックルで描画（source-over のみ、XOR合成なし）
// mainCtx: メインCanvas2Dコンテキスト（論理座標系）
// blasts: アクティブ爆発オブジェクト配列
// frameCount: インクリメントカウンタ（色フリッカー用、1フレームおきに更新）
function drawAllBlastsSpeckle(mainCtx, blasts, frameCount) {
  for (const b of blasts) {
    if (!b) continue;
    const r = Math.max(1, b.r);
    // フェードアウト用アルファ（成長中は1.0、フェード中は線形減衰）
    const alpha = b.growing
      ? 1.0
      : clamp(b.fadeTimer / BLAST_FADE_SEC, 0, 1);
    if (alpha <= 0) continue;

    const bx = b.x;
    const by = b.y;
    const id = b.id | 0;

    // ★全面を1色で塗る。フレームごとに色を高速サイクルさせ、爆発の「全面」が
    //   白・カラフル・黒(ネガ)と明滅する。ドット単位ではなく面全体が点滅する。
    const cidx = (_speckleRand(id, 7, 13, frameCount) * _SPECKLE_COLOR_COUNT) | 0;
    const fillCol = _SPECKLE_COLORS[cidx];

    // グリッドをブラスト中心から±r の矩形に限定（粗いセルで縁をガタガタに）
    const x0 = Math.floor((bx - r) / _CELL);
    const x1 = Math.ceil ((bx + r) / _CELL);
    const y0 = Math.floor((by - r) / _CELL);
    const y1 = Math.ceil ((by + r) / _CELL);

    mainCtx.save();
    mainCtx.globalCompositeOperation = 'source-over';
    mainCtx.globalAlpha = clamp(alpha, 0, 1);
    mainCtx.fillStyle = fillCol;

    for (let gy = y0; gy <= y1; gy++) {
      const cy = gy * _CELL + _CELL * 0.5;
      const dy = cy - by;

      for (let gx = x0; gx <= x1; gx++) {
        const cx = gx * _CELL + _CELL * 0.5;
        const dx = cx - bx;

        // セルごとに半径ジッターでエッジを粗く（綺麗な円にしない）
        const jitter = 0.88 + 0.22 * _speckleRand(gx * 7 + 3, gy * 5 + 1, id, 0);
        const effectiveR = r * jitter;
        if (dx * dx + dy * dy > effectiveR * effectiveR) continue;

        mainCtx.fillRect(gx * _CELL, gy * _CELL, _CELL, _CELL);
      }
    }

    mainCtx.restore();
  }

  // 安全のため compositeOperation / alpha をデフォルトに戻す
  mainCtx.globalCompositeOperation = 'source-over';
  mainCtx.globalAlpha = 1;
}

class Game extends Scene {
  enter() {
    this.score = 0;
    this.high  = this.engine.storage.getHigh(meta.id);
    this.dead  = false;

    this._elapsed    = 0;
    this._frameCount = 0; // フリッカー・アニメーション用フレームカウンタ

    // ステージ
    this._stage         = 0;
    this._stageType     = 'NORMAL';
    this._stageScript   = makeStageScript(this._stage, this._stageType);
    this._scriptIdx     = 0;
    this._bossAlive     = false;
    this._bossIdx       = -1;

    // ステージクリア演出（非停止：フロート表示のみ）
    this._clearOverlay  = null; // { timer, stage, bonus } | null

    // 都市: alive flag + バフスタック
    this.cities = Array.from({ length: CITY_COUNT }, () => ({
      alive: true,
      buffs: makeCityBuffs(),
    }));

    this.meteors    = [];
    this.missiles   = [];
    this.blasts     = [];
    this.cityBlasts = [];
    this.debris     = [];  // ボス破壊デブリパーティクル

    this._fireCooldown = 0;

    this._bigCharges  = BIG_CHARGES_MAX;
    this._bigRecharge = 0;
    this._bigArmed    = false;

    // ランチャーシステム
    this._launcherSlots  = 2; // 同時発射上限（MULTIで増える、最大5）
    this._selectedCity   = -1; // 手動選択都市インデックス（-1=未選択）

    // スキャッター特殊弾（グローバル残弾数）
    this._scatterAmmo = 0;

    // RAPIDバフ（時間制限、グローバル）
    this._rapidTimer = 0; // >0 = アクティブ（秒カウントダウン）
  }

  _bigBtnRect() { return { x: W / 2 - 48, y: 44, w: 112, h: 28 }; }

  _calcNormalSpd() {
    const frac   = clamp(this._stage / 6, 0, 1);
    const spdMax = METEOR_SPD_MAX + (METEOR_SPD_MAX_LATE - METEOR_SPD_MAX) * frac;
    const base   = METEOR_SPD_MIN + Math.random() * (spdMax - METEOR_SPD_MIN);
    return base * stageSpeedMult(this._stageType);
  }

  _calcFastSpd() {
    const base = FAST_SPD_MIN + Math.random() * (FAST_SPD_MAX - FAST_SPD_MIN);
    return clamp(base * stageSpeedMult(this._stageType) * 0.7, 1, 99);
  }

  // ---- 都市フットプリント当たり判定 ----
  _cityHitTest(x, y) {
    for (let i = 0; i < CITY_COUNT; i++) {
      if (!this.cities[i].alive) continue;
      const cx = CITY_XS[i];
      const cy = GROUND_Y - CITY_H;
      if (x >= cx - 4 && x <= cx + CITY_W + 4 && y >= cy - 4 && y <= cy + CITY_H + 4) {
        return i;
      }
    }
    return -1;
  }

  // ---- 最寄りの生存都市を返す（targetXに対して最も近い発射台）----
  _nearestAliveCity(targetX) {
    let bestIdx  = -1;
    let bestDist = Infinity;
    for (let i = 0; i < CITY_COUNT; i++) {
      if (!this.cities[i].alive) continue;
      const cx = CITY_XS[i] + CITY_W / 2;
      const d  = Math.abs(cx - targetX);
      if (d < bestDist) { bestDist = d; bestIdx = i; }
    }
    return bestIdx;
  }

  // ---- onInput ----
  onInput(action, data) {
    if (this.dead) {
      if (action === 'back') { this.engine.toMenu(); return; }
      if (action === 'tap' || action === 'confirm') { this.enter(); return; }
      return;
    }
    if (action === 'back') { this.engine.toMenu(); return; }

    if (action === 'tap' && data) {
      // BIGボタン
      const b = this._bigBtnRect();
      if (data.x >= b.x && data.x <= b.x + b.w && data.y >= b.y && data.y <= b.y + b.h) {
        this._bigArmed = this._bigArmed ? false : (this._bigCharges > 0);
        this.engine.audio.select();
        return;
      }

      // 都市フットプリントのタップ → 選択
      const cityIdx = this._cityHitTest(data.x, data.y);
      if (cityIdx >= 0) {
        this._selectedCity = (this._selectedCity === cityIdx) ? -1 : cityIdx;
        this.engine.audio.select();
        return;
      }

      // 空へのタップ → 発射
      const big = this._bigArmed;
      this._fireMissile(data.x, data.y, big);
      if (big) this._bigArmed = false;
    }
    if (action === 'confirm') {
      this._bigArmed = this._bigArmed ? false : (this._bigCharges > 0);
    }
  }

  // ---- 同時飛翔上限計算 ----
  _getMissileCap() {
    const isRapid = this._rapidTimer > 0;
    if (isRapid) {
      return Math.min(this._launcherSlots * RAPID_SHOTS_CITY, MISSILES_CAP_RAPID);
    }
    return Math.min(this._launcherSlots, MISSILES_CAP_NORMAL);
  }

  // ---- 発射（クールダウン＋上限チェック） ----
  _fireMissile(tx, ty, big) {
    if (ty >= GROUND_Y) return;
    if (this._fireCooldown > 0) return;
    const activeCount = this.missiles.filter(m => !m.done).length;
    const cap = this._getMissileCap();
    if (activeCount >= cap) return;

    // 発射元都市の決定 — 手動選択があればそれ、なければタップ先に最も近い都市
    let cityIdx = -1;
    if (this._selectedCity >= 0 && this.cities[this._selectedCity] && this.cities[this._selectedCity].alive) {
      cityIdx = this._selectedCity;
      // 手動選択は1発撃ったら解除（次は再選択 or 自動）
      this._selectedCity = -1;
    } else {
      cityIdx = this._nearestAliveCity(tx);
    }
    if (cityIdx < 0) return; // 全都市消滅時は撃てない

    if (big) {
      if (this._bigCharges <= 0) return;
      this._bigCharges--;
    }

    const launchX = CITY_XS[cityIdx] + CITY_W / 2;
    const launchY = GROUND_Y - CITY_H;

    const dx = tx - launchX;
    const dy = ty - launchY;
    const dist = Math.hypot(dx, dy);
    if (dist < 1) return;

    // スキャッター弾かどうか
    const useScatter = !big && this._scatterAmmo > 0;
    if (useScatter) this._scatterAmmo = Math.max(0, this._scatterAmmo - 1);

    this.missiles.push({
      x: launchX, y: launchY,
      tx, ty,
      vx: (dx / dist) * MISSILE_SPD,
      vy: (dy / dist) * MISSILE_SPD,
      done: false,
      big: !!big,
      scatter: useScatter,
      cityIdx,   // 発射元都市（バフ参照用）
    });

    // RAPIDバフ中はクールダウン短縮
    this._fireCooldown = this._rapidTimer > 0 ? RAPID_COOLDOWN : FIRE_COOLDOWN;
    this.engine.audio.move();
  }

  // ---- update ----
  update(dt) {
    if (this.dead) return;

    if (this._fireCooldown > 0) {
      this._fireCooldown = Math.max(0, this._fireCooldown - dt);
    }

    // RAPIDタイマー更新
    if (this._rapidTimer > 0) {
      this._rapidTimer = Math.max(0, this._rapidTimer - dt);
    }

    // ステージクリアオーバーレイのタイマー（ゲームは止まらない）
    if (this._clearOverlay) {
      this._clearOverlay.timer -= dt;
      if (this._clearOverlay.timer <= 0) this._clearOverlay = null;
    }

    this._elapsed += dt;

    // ビッグブラスト補充
    if (this._bigCharges < BIG_CHARGES_MAX) {
      this._bigRecharge += dt;
      if (this._bigRecharge >= BIG_RECHARGE_SEC) {
        this._bigRecharge -= BIG_RECHARGE_SEC;
        this._bigCharges++;
      }
    } else {
      this._bigRecharge = 0;
    }

    // 都市バフ更新
    for (const city of this.cities) {
      if (city.alive) updateCityBuffs(city.buffs, dt);
    }

    // ---- スクリプト式スポーン ----
    if (!this._bossAlive) {
      while (
        this._scriptIdx < this._stageScript.length &&
        this._stageScript[this._scriptIdx].t <= this._elapsed
      ) {
        const ev = this._stageScript[this._scriptIdx];
        this._scriptIdx++;
        if (ev.type === 'boss') {
          this._spawnBoss();
        } else if (ev.type === 'meteor') {
          const cnt = ev.count || 1;
          for (let c = 0; c < cnt; c++) {
            this._spawnMeteor(ev.forceSize, ev.itemChance || 0);
          }
        }
      }
    }

    // ---- ステージクリア判定 ----
    // ボスが倒されて script が終了したら次ステージへ（非停止）
    if (
      !this._bossAlive &&
      this._scriptIdx >= this._stageScript.length &&
      this.meteors.length === 0 &&
      !this._clearOverlay
    ) {
      // 次ステージ開始
      const clearedStage = this._stage;
      const bonus = 100 + clearedStage * 50;
      this.score += bonus;

      this._stage++;
      this._elapsed = 0;
      if (this._stage === 0) {
        this._stageType = 'NORMAL';
      } else {
        const types = STAGE_TYPES.filter(t => t !== 'NORMAL');
        this._stageType = types[(this._stage - 1) % types.length];
      }
      this._stageScript = makeStageScript(this._stage, this._stageType);
      this._scriptIdx   = 0;
      this._bossAlive   = false;
      this._bossIdx     = -1;
      // ミサイル/爆発は引き継ぎ（シームレス）

      // クリアオーバーレイ表示（ゲームは止まらない）
      this._clearOverlay = { timer: 2.8, stage: clearedStage + 1, bonus };

      // クリア音
      this.engine.audio.sequence([
        { freq: 440, dur: 0.08, type: 'square', vol: 0.15 },
        { freq: 660, dur: 0.08, type: 'square', vol: 0.15 },
        { freq: 880, dur: 0.10, type: 'square', vol: 0.18 },
        { freq: 1320, dur: 0.16, type: 'square', vol: 0.18 },
      ]);
    }

    // 隕石移動
    for (let i = this.meteors.length - 1; i >= 0; i--) {
      const m = this.meteors[i];
      if (!m || m.x == null) { this.meteors.splice(i, 1); continue; }
      const dx   = m.tx - m.x;
      const dy   = m.ty - m.y;
      const dist = Math.hypot(dx, dy);

      if (dist < m.spd * dt + 1) {
        // 地面到達
        if (m.boss) {
          this._impactCity(m.tx, m.ty);
          this._impactCity(m.tx, m.ty);
          this._bossAlive = false;
          this._bossIdx   = -1;
        } else if (!m.isItem) {
          this._impactCity(m.tx, m.ty);
        }
        this.meteors.splice(i, 1);
        if (this._bossIdx === i) { this._bossAlive = false; this._bossIdx = -1; }
        else if (this._bossIdx > i) this._bossIdx--;
        continue;
      }
      const ratio = m.spd / dist;
      m.x += dx * ratio * dt;
      m.y += dy * ratio * dt;

      const trailMax = m.fast ? 8 : (m.boss ? 4 : 5);
      m.trail.push({ x: m.x, y: m.y });
      if (m.trail.length > trailMax) m.trail.shift();

      m.rot += (m.fast ? 0.8 : (m.boss ? 0.12 : 0.4)) * dt;

      // ヒットフラッシュタイマーのカウントダウン
      if (m.flashTimer > 0) m.flashTimer = Math.max(0, m.flashTimer - dt);

      // ボス入場フェーズ：上半分が画面に入り終わるまで
      // わずかに横揺れを加えて「舞い降りる」演出（ゆったり浮遊感）
      if (m.boss && m.y < m.r * 0.8) {
        const swayAmp   = 3.5;  // 最大振れ幅 px
        const swayFreq  = 1.1;  // Hz
        // _elapsed を使って時間を参照
        const swayX = swayAmp * Math.sin(this._elapsed * swayFreq * Math.PI * 2);
        m.x = clamp(m.x + swayX * dt, m.r * 0.5, W - m.r * 0.5);
      }
    }

    // ミサイル移動
    for (let i = this.missiles.length - 1; i >= 0; i--) {
      const ms = this.missiles[i];
      if (!ms) { this.missiles.splice(i, 1); continue; }
      if (ms.done) { this.missiles.splice(i, 1); continue; }
      ms.x += ms.vx * dt;
      ms.y += ms.vy * dt;
      const ddx = ms.tx - ms.x;
      const ddy = ms.ty - ms.y;
      if (Math.hypot(ddx, ddy) < MISSILE_SPD * dt * 1.5 + 4) {
        this._spawnBlast(ms.tx, ms.ty, ms.big, false, ms.scatter, ms.cityIdx);
        ms.done = true;
      }
    }

    // 爆発更新 — grow then FADE
    for (let i = this.blasts.length - 1; i >= 0; i--) {
      const b = this.blasts[i];
      if (!b) { this.blasts.splice(i, 1); continue; }

      if (b.growing) {
        b.r += BLAST_GROW_RATE * dt;
        if (b.r >= b.maxR) {
          b.r        = b.maxR;
          b.growing  = false;
          b.fadeTimer = BLAST_FADE_SEC;
        }
      } else {
        b.fadeTimer -= dt;
        b.r = Math.min(b.maxR * 1.05, b.r + 4 * dt);
        if (b.fadeTimer <= 0) {
          this.blasts.splice(i, 1);
          continue;
        }
      }

      // 爆発ヒット判定
      for (let j = this.meteors.length - 1; j >= 0; j--) {
        const m = this.meteors[j];
        if (!m) continue;
        if (Math.hypot(m.x - b.x, m.y - b.y) > b.r + m.r) continue;
        if (m.hitBlastIds.has(b.id)) continue;
        m.hitBlastIds.add(b.id);

        if (m.isItem) {
          this._collectItem(m, b.cityIdx);
          if (this._bossIdx > j) this._bossIdx--;
          this.meteors.splice(j, 1);
          continue;
        }

        m.hp -= b.damage;
        // ダメージを受けたが破壊されない場合はヒットフラッシュを起動
        if (m.hp > 0) {
          m.flashTimer = 0.13; // ~0.13秒間白くフラッシュ
        }
        if (m.hp <= 0) {
          if (m.boss) {
            this.score += BOSS_SCORE_BASE * (this._stage + 1);
            this._bossAlive = false;
            this._bossIdx   = -1;
            // ボス破壊演出
            this._spawnBossShatter(m.x, m.y, m.r);
            m.flashTimer = 0; // 破壊時はフラッシュ不要
            // ボス破壊音（壮大な降下音）
            this.engine.audio.sequence([
              { freq: 880, dur: 0.09, type: 'sawtooth', vol: 0.20 },
              { freq: 660, dur: 0.09, type: 'sawtooth', vol: 0.20 },
              { freq: 440, dur: 0.12, type: 'sawtooth', vol: 0.22 },
              { freq: 280, dur: 0.14, type: 'sawtooth', vol: 0.24 },
              { freq: 160, dur: 0.20, type: 'sawtooth', vol: 0.26 },
              { freq: 80,  dur: 0.30, type: 'sawtooth', vol: 0.28 },
            ]);
            this.engine.audio.bad();
          } else {
            const sizeBonus = Math.ceil(m.maxHp);
            this.score += METEOR_SCORE_BASE * sizeBonus;
            this.engine.audio.good();
          }
          if (this._bossIdx > j) this._bossIdx--;
          this.meteors.splice(j, 1);
        }
      }
    }

    // 都市爆発エフェクト更新
    for (let i = this.cityBlasts.length - 1; i >= 0; i--) {
      const cb = this.cityBlasts[i];
      if (!cb) { this.cityBlasts.splice(i, 1); continue; }
      cb.t -= dt;
      cb.r += 60 * dt;
      if (cb.t <= 0) this.cityBlasts.splice(i, 1);
    }

    // デブリ更新
    for (let i = this.debris.length - 1; i >= 0; i--) {
      const d = this.debris[i];
      if (!d) { this.debris.splice(i, 1); continue; }
      d.x    += d.vx * dt;
      d.y    += d.vy * dt;
      d.vy   += 60 * dt;  // 重力
      d.rot  += d.rotSpd * dt;
      d.life -= dt;
      if (d.life <= 0) { this.debris.splice(i, 1); }
    }

    // ゲームオーバー判定
    if (this.cities.every(c => !c.alive)) {
      this.dead = true;
      this.engine.audio.bad();
      if (this.engine.storage.setHigh(meta.id, this.score)) this.high = this.score;
    }
  }

  // ---- ボス破壊シャッター（デブリ噴射）----
  _spawnBossShatter(cx, cy, r) {
    const debrisCount = 24;
    for (let i = 0; i < debrisCount; i++) {
      const angle = (i / debrisCount) * Math.PI * 2 + Math.random() * 0.4;
      const spd   = 60 + Math.random() * 160;
      const size  = 3 + Math.random() * (r * 0.15);
      const sides = 3 + Math.floor(Math.random() * 4); // 3〜6角形
      this.debris.push({
        x: cx + Math.cos(angle) * r * (0.1 + Math.random() * 0.6),
        y: cy + Math.sin(angle) * r * (0.1 + Math.random() * 0.6),
        vx: Math.cos(angle) * spd,
        vy: Math.sin(angle) * spd - 30,
        rot: Math.random() * Math.PI * 2,
        rotSpd: (Math.random() - 0.5) * 8,
        size: Math.max(2, size),
        sides,
        life: 0.8 + Math.random() * 1.4,
        maxLife: 0.8 + Math.random() * 1.4,
        isBoss: true,
      });
    }
    // 追加の火花（小さな）
    for (let i = 0; i < 32; i++) {
      const angle = Math.random() * Math.PI * 2;
      const spd   = 80 + Math.random() * 220;
      const ml    = 0.4 + Math.random() * 0.8;
      this.debris.push({
        x: cx, y: cy,
        vx: Math.cos(angle) * spd,
        vy: Math.sin(angle) * spd - 20,
        rot: 0, rotSpd: 0,
        size: 1.5 + Math.random() * 2.5,
        sides: 0, // 0 = 円パーティクル
        life: ml, maxLife: ml,
        isBoss: false,
      });
    }
  }

  // ---- 通常隕石スポーン ----
  _spawnMeteor(forceSize, itemChance) {
    const x = 18 + Math.random() * (W - 36);
    const alive = this.cities.map((c, i) => c.alive ? i : -1).filter(i => i >= 0);
    let tx;
    if (alive.length > 0 && Math.random() < 0.7) {
      const idx = alive[Math.floor(Math.random() * alive.length)];
      tx = CITY_XS[idx] + CITY_W / 2 + (Math.random() * 24 - 12);
    } else {
      tx = 18 + Math.random() * (W - 36);
    }
    const ty = GROUND_Y;

    const spawnItem = this._stage >= 1 && Math.random() < (itemChance || 0);

    let r;
    if (forceSize === 'tiny') {
      r = METEOR_R_MIN + Math.random() * (SMALL_R_THRESH - METEOR_R_MIN + 2);
    } else if (forceSize === 'giant') {
      r = GIANT_R_THRESH + Math.random() * (METEOR_R_MAX - GIANT_R_THRESH);
    } else if (Math.random() < 0.12) {
      r = GIANT_R_THRESH + Math.random() * (METEOR_R_MAX - GIANT_R_THRESH);
    } else {
      r = Math.max(METEOR_R_MIN,
        METEOR_R_MIN + Math.random() * Math.random() * (GIANT_R_THRESH - METEOR_R_MIN)
      );
    }

    if (spawnItem) r = 14 + Math.random() * 6;

    const isFast  = !spawnItem && Math.random() < FAST_CHANCE;
    const spd     = isFast ? this._calcFastSpd() : this._calcNormalSpd();
    const maxHp   = spawnItem ? 1 : calcMeteorHP(r);
    const seed    = _nextMeteorSeed++;
    const itemType = spawnItem ? ITEM_TYPES[Math.floor(Math.random() * ITEM_TYPES.length)] : null;

    this.meteors.push({
      x, y: -METEOR_R_MAX - 4,
      tx, ty, spd, r,
      hp: maxHp, maxHp,
      fast: isFast,
      boss: false,
      isItem: spawnItem,
      itemType,
      trail: [],
      rot: Math.random() * Math.PI * 2,
      verts: makeRockVerts(r, seed),
      seed,
      hitBlastIds: new Set(),
      flashTimer: 0, // ヒットフラッシュタイマー（秒）
    });
  }

  // ---- ボス隕石スポーン ----
  _spawnBoss() {
    const r = BOSS_R_MIN + Math.random() * (BOSS_R_MAX - BOSS_R_MIN);
    // ボスは画面中央に配置 — 巨大なので左右にはみ出す（意図的）
    const x  = W / 2;
    const tx = W / 2 + (Math.random() - 0.5) * 40; // 少しランダムな着地点
    const ty = GROUND_Y;
    const spd   = BOSS_SPD_MIN + Math.random() * (BOSS_SPD_MAX - BOSS_SPD_MIN);
    const maxHp = BOSS_HP_BASE + this._stage * BOSS_HP_PER_STAGE;
    const seed  = _nextMeteorSeed++;

    // ボスは画面外上端からスタート（中心が画面上端より r だけ上）
    // → プレイヤーはボスが上からゆっくり舞い降りるのを目撃できる
    const bossEntry = {
      x, y: -r,  // 完全に画面外上端（ y=-r で円全体がオフスクリーン）
      tx, ty, spd, r,
      hp: maxHp, maxHp,
      fast: false,
      boss: true,
      isItem: false,
      itemType: null,
      trail: [],
      rot: Math.random() * Math.PI * 2,
      verts: makeRockVerts(r, seed),
      seed,
      hitBlastIds: new Set(),
      flashTimer: 0, // ヒットフラッシュタイマー（秒）
    };
    this.meteors.push(bossEntry);
    this._bossIdx  = this.meteors.length - 1;
    this._bossAlive = true;

    // ボス登場音
    this.engine.audio.sequence([
      { freq: 200, dur: 0.14, type: 'sawtooth', vol: 0.18 },
      { freq: 160, dur: 0.18, type: 'sawtooth', vol: 0.18 },
      { freq: 120, dur: 0.22, type: 'sawtooth', vol: 0.18 },
    ]);
  }

  // ---- アイテム取得 ----
  // cityIdx: 撃ち落とした爆発の発射元都市
  _collectItem(m, cityIdx) {
    const type = m.itemType;

    if (type === 'MULTI') {
      // ランチャースロット増加（永続、最大5）
      this._launcherSlots = Math.min(this._launcherSlots + 1, 5);
    } else if (type === 'POWER') {
      // 発射元都市のパワーバフを1スタック追加
      const ci = cityIdx >= 0 && this.cities[cityIdx] ? cityIdx : this._nearestAliveCity(m.x);
      if (ci >= 0 && this.cities[ci] && this.cities[ci].alive) {
        this.cities[ci].buffs.power.push({ timer: BUFF_DURATION });
      }
    } else if (type === 'WIDE') {
      // 発射元都市のワイドバフを1スタック追加
      const ci = cityIdx >= 0 && this.cities[cityIdx] ? cityIdx : this._nearestAliveCity(m.x);
      if (ci >= 0 && this.cities[ci] && this.cities[ci].alive) {
        this.cities[ci].buffs.wide.push({ timer: BUFF_DURATION });
      }
    } else if (type === 'SCATTER') {
      // スキャッター特殊弾3発付与（グローバル弾薬）
      this._scatterAmmo += SCATTER_AMMO_PER_PICKUP;
    } else if (type === 'RAPID') {
      // RAPIDバフ：時間制限で連射強化
      this._rapidTimer = RAPID_DURATION;
    }

    // 取得音
    this.engine.audio.sequence([
      { freq: 880, dur: 0.06, type: 'square', vol: 0.16 },
      { freq: 1320, dur: 0.08, type: 'square', vol: 0.18 },
      { freq: 1760, dur: 0.10, type: 'square', vol: 0.20 },
    ]);
  }

  // ---- 爆発スポーン ----
  // cityIdx: 発射元都市インデックス（バフ参照、-1=不明）
  _spawnBlast(x, y, big, isScatter, isScatterShot, cityIdx) {
    // 発射元都市のバフを参照
    const city   = (cityIdx >= 0 && this.cities[cityIdx]) ? this.cities[cityIdx] : null;
    const buffs  = city ? city.buffs : makeCityBuffs();

    const baseR = big
      ? BLAST_GROW_BIG
      : (BLAST_GROW + cityBuffRadiusAdd(buffs));
    const maxR  = Math.max(6, baseR);
    const dmg   = big ? BLAST_DAMAGE_BIG : cityBuffPower(buffs);
    const id    = _nextBlastId++;

    this.blasts.push({
      x, y,
      r: 4,
      maxR,
      growing: true,
      fadeTimer: BLAST_FADE_SEC,
      big: !!big,
      id,
      damage: dmg,
      isScatter: !!isScatter,
      cityIdx: cityIdx >= 0 ? cityIdx : -1,
    });

    if (!isScatter) {
      this.engine.audio.pick();
      if (big) {
        this.engine.audio.sequence([
          { freq: 330, dur: 0.06, type: 'square', vol: 0.18 },
          { freq: 220, dur: 0.12, type: 'sawtooth', vol: 0.16 },
        ]);
      }
      // スキャッター特殊弾：爆発周囲に6個の小爆発を散布
      if (!big && isScatterShot) {
        const count = 6;
        for (let i = 0; i < count; i++) {
          const angle = (i / count) * Math.PI * 2;
          const dist  = 28 + Math.random() * 18;
          const sx = x + Math.cos(angle) * dist;
          const sy = y + Math.sin(angle) * dist;
          if (sy > GROUND_Y - 4) continue;
          this._spawnBlast(sx, sy, false, true, false, cityIdx);
        }
      }
    }
  }

  // ---- 都市ダメージ ----
  _impactCity(ix, iy) {
    let bestDist = Infinity, bestIdx = -1;
    for (let i = 0; i < CITY_COUNT; i++) {
      if (!this.cities[i].alive) continue;
      const cx = CITY_XS[i] + CITY_W / 2;
      const d  = Math.abs(cx - ix);
      if (d < bestDist) { bestDist = d; bestIdx = i; }
    }
    if (bestIdx >= 0 && bestDist < CITY_W * 2.5) {
      this.cities[bestIdx].alive = false;
      // 選択都市が破壊されたらリセット
      if (this._selectedCity === bestIdx) this._selectedCity = -1;
      this.engine.audio.bad();
      this.cityBlasts.push({
        x: CITY_XS[bestIdx] + CITY_W / 2,
        y: GROUND_Y - CITY_H / 2,
        r: 8, t: 0.7,
      });
    }
  }

  // ---- render ----
  render(ctx) {
    const p = P();

    // ---- HUD（x>=52 でBACKボタンを避ける） ----
    const stageLabel = 'ST' + (this._stage + 1);
    this.engine.text(stageLabel, 52, 8, 14, p.mid, 'left');

    if (this._stage >= 1 && this._stageType !== 'NORMAL') {
      this.engine.text(this._stageType, 52, 24, 11, p.warn, 'left');
    }

    this.engine.text('SCORE ' + this.score, W - 12, 8, 14, p.fg, 'right');
    this.engine.text('BEST  ' + this.high,  W - 12, 26, 11, p.dim, 'right');

    const aliveCount = this.cities.filter(c => c.alive).length;
    this.engine.text('CITY ' + aliveCount, 52, 38, 11, p.warn, 'left');

    // ボスHPバー（トップHUDストリップ内、ボスが画面内に入ったときのみ表示）
    this._drawBossHPHud(ctx, p);

    // ビッグブラスト HUD
    this._drawBigChargeHUD(ctx, p);

    // ---- 星空 ----
    this._drawStarfield(ctx, p);

    // ---- 地面 ----
    this.engine.rect(0, GROUND_Y, W, H - GROUND_Y, p.dark);
    this.engine.rect(0, GROUND_Y, W, 2, p.dim);

    // ---- 都市（山シルエット+街並み） ----
    for (let i = 0; i < CITY_COUNT; i++) {
      this._drawCity(ctx, p, i);
    }

    // ---- 都市爆発エフェクト ----
    for (const cb of this.cityBlasts) {
      if (!cb) continue;
      ctx.save();
      ctx.globalAlpha = clamp(cb.t / 0.7, 0, 1) * 0.9;
      ctx.beginPath();
      ctx.arc(cb.x, cb.y, Math.max(1, cb.r), 0, Math.PI * 2);
      ctx.fillStyle = p.bad;
      ctx.fill();
      ctx.restore();
    }

    // ---- ミサイル ----
    for (const ms of this.missiles) {
      if (!ms || ms.done) continue;
      const launchX = CITY_XS[ms.cityIdx] + CITY_W / 2;
      const launchY = GROUND_Y - CITY_H;
      ctx.save();
      ctx.strokeStyle = ms.big ? p.warn : (ms.scatter ? p.hi : p.fg);
      ctx.lineWidth   = ms.big ? 2.5 : 1.5;
      ctx.setLineDash(ms.big ? [6, 3] : (ms.scatter ? [3, 2] : []));
      ctx.beginPath();
      ctx.moveTo(launchX, launchY);
      ctx.lineTo(ms.x, ms.y);
      ctx.stroke();
      ctx.setLineDash([]);
      ctx.beginPath();
      ctx.arc(ms.x, ms.y, ms.big ? 4 : (ms.scatter ? 3 : 2.5), 0, Math.PI * 2);
      ctx.fillStyle = ms.big ? p.warn : (ms.scatter ? p.hi : p.fg);
      ctx.fill();
      ctx.restore();
    }

    // ---- 隕石（岩石ポリゴン） ----
    for (const m of this.meteors) {
      if (!m) continue;

      if (m.isItem) {
        this._drawItemMeteor(ctx, p, m);
        continue;
      }

      const damageFrac = m.maxHp > 1 ? clamp(1 - m.hp / m.maxHp, 0, 1) : 0;
      const bodyColor  = m.boss ? p.warn : (m.fast ? p.hi : p.bad);

      // 軌跡のリング描画は廃止（隕石中央に輪が見える原因だったため）。
      // 高速隕石だけ、細い尾を薄い線で表現する（中央に輪は出さない）。
      if (m.fast && m.trail.length >= 2) {
        ctx.save();
        ctx.globalAlpha = 0.35;
        ctx.strokeStyle = bodyColor;
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(m.trail[0].x, m.trail[0].y);
        for (let t = 1; t < m.trail.length; t++) {
          if (m.trail[t]) ctx.lineTo(m.trail[t].x, m.trail[t].y);
        }
        ctx.stroke();
        ctx.restore();
      }

      // 岩石ポリゴン本体
      if (m.verts && m.verts.length >= 3) {
        const lineW    = clamp(1.8 - damageFrac * 0.8, 0.5, 2.5);
        const bodyAlpha = clamp(1 - damageFrac * 0.4, 0.3, 1);

        // ヒットフラッシュ：ダメージを受けたがまだ生きている場合、白く光らせる
        const flashing = m.flashTimer > 0;
        // フラッシュ強度（0→1でフェードアウト）
        const flashStrength = flashing ? clamp(m.flashTimer / 0.13, 0, 1) : 0;

        ctx.save();
        ctx.globalAlpha = clamp(bodyAlpha, 0, 1);
        ctx.translate(m.x, m.y);
        ctx.rotate(m.rot);

        if (m.boss) {
          ctx.beginPath();
          ctx.moveTo(m.verts[0].dx, m.verts[0].dy);
          for (let vi = 1; vi < m.verts.length; vi++) {
            ctx.lineTo(m.verts[vi].dx, m.verts[vi].dy);
          }
          ctx.closePath();
          // フラッシュ中はボスの塗りも少し白くなる
          ctx.fillStyle = flashing ? '#ffffff' : p.dark;
          ctx.globalAlpha = flashing
            ? clamp(flashStrength * 0.55, 0, 1)
            : clamp(0.65 - damageFrac * 0.2, 0, 1);
          ctx.fill();
          ctx.globalAlpha = clamp(bodyAlpha, 0, 1);
        }

        ctx.beginPath();
        ctx.moveTo(m.verts[0].dx, m.verts[0].dy);
        for (let vi = 1; vi < m.verts.length; vi++) {
          ctx.lineTo(m.verts[vi].dx, m.verts[vi].dy);
        }
        ctx.closePath();

        // フラッシュ中はアウトラインを白/明るい色に切り替え
        if (flashing) {
          ctx.strokeStyle = '#ffffff';
          ctx.lineWidth   = m.boss
            ? clamp(lineW * 2 + flashStrength * 2, 1, 6)
            : clamp(lineW + flashStrength * 1.5, 0.5, 4);
          ctx.globalAlpha = clamp(bodyAlpha * (0.5 + flashStrength * 0.5), 0, 1);
        } else {
          ctx.strokeStyle = bodyColor;
          ctx.lineWidth   = m.boss ? clamp(lineW * 2, 1, 4) : lineW;
        }
        ctx.stroke();

        // ---- ボスのダメージクラック表示 ----
        if (m.boss && damageFrac > 0 && m.verts.length >= 6) {
          this._drawBossCracks(ctx, p, m, damageFrac);
        } else if (!m.boss && damageFrac > 0.3 && m.verts.length >= 6) {
          // 通常隕石の簡易クラック
          ctx.globalAlpha = clamp(damageFrac * 0.5, 0, 1);
          ctx.beginPath();
          const v0 = m.verts[0];
          const v2 = m.verts[2];
          const v4 = m.verts[4];
          ctx.moveTo(v0.dx * 0.5, v0.dy * 0.5);
          ctx.lineTo(v2.dx * 0.5, v2.dy * 0.5);
          ctx.lineTo(v4.dx * 0.5, v4.dy * 0.5);
          ctx.strokeStyle = bodyColor;
          ctx.lineWidth = 0.7;
          ctx.stroke();
        }

        ctx.restore();
        // HP ピップは削除。代わりにヒットフラッシュで被弾を表現する。
      }
    }

    // ---- デブリ（ボス破壊断片）----
    for (const d of this.debris) {
      if (!d) continue;
      const alpha = clamp(d.life / d.maxLife, 0, 1);
      ctx.save();
      ctx.globalAlpha = clamp(alpha * 0.95, 0, 1);
      if (d.sides === 0) {
        // 円パーティクル（火花）
        ctx.beginPath();
        ctx.arc(d.x, d.y, Math.max(1, d.size), 0, Math.PI * 2);
        ctx.fillStyle = d.isBoss ? p.warn : p.bad;
        ctx.fill();
      } else {
        // ポリゴン断片
        ctx.translate(d.x, d.y);
        ctx.rotate(d.rot);
        ctx.beginPath();
        for (let vi = 0; vi < d.sides; vi++) {
          const a = (vi / d.sides) * Math.PI * 2;
          const sr = d.size * (0.6 + 0.4 * Math.sin(vi * 2.3 + d.rot));
          if (vi === 0) ctx.moveTo(Math.cos(a) * sr, Math.sin(a) * sr);
          else          ctx.lineTo(Math.cos(a) * sr, Math.sin(a) * sr);
        }
        ctx.closePath();
        ctx.strokeStyle = p.warn;
        ctx.lineWidth = 1.5;
        ctx.stroke();
        ctx.fillStyle = p.bad;
        ctx.globalAlpha = clamp(alpha * 0.3, 0, 1);
        ctx.fill();
      }
      ctx.restore();
    }

    // ---- 爆発（コースピクセルスペックル：Missile Command 風）----
    // フレームカウンタをインクリメント（render は毎フレーム呼ばれる）
    this._frameCount = (this._frameCount + 1) | 0;

    if (this.blasts.length > 0) {
      // 成長中/フェード中の爆発のみ対象
      const activeBlasts = this.blasts.filter(b => b != null);

      if (activeBlasts.length > 0) {
        drawAllBlastsSpeckle(ctx, activeBlasts, this._frameCount);
      }
    }

    // ---- 左端アクティブアイテムパネル ----
    this._drawActiveItemsPanel(ctx, p);

    // ---- ステージクリアオーバーレイ（非停止：フロート表示のみ）----
    if (this._clearOverlay) {
      const frac  = clamp(this._clearOverlay.timer / 2.8, 0, 1);
      // フェードイン/アウト
      const alpha = frac < 0.2
        ? frac / 0.2
        : frac > 0.8 ? (1 - frac) / 0.2
        : 1;
      ctx.save();
      ctx.globalAlpha = clamp(alpha * 0.88, 0, 1);
      ctx.fillStyle = p.dark;
      ctx.fillRect(0, H / 2 - 70, W, 140);
      ctx.restore();
      ctx.save();
      ctx.globalAlpha = clamp(alpha, 0, 1);
      this.engine.text('STAGE ' + this._clearOverlay.stage + ' CLEAR!', W / 2, H / 2 - 52, 26, p.warn, 'center');
      this.engine.text('BONUS +' + this._clearOverlay.bonus, W / 2, H / 2 - 16, 18, p.hi,   'center');
      this.engine.text('STAGE ' + (this._stage + 1) + ': ' + this._stageType, W / 2, H / 2 + 18, 14, p.mid, 'center');
      ctx.restore();
    }

    // ---- ゲームオーバーオーバーレイ ----
    if (this.dead) {
      this.engine.rect(0, H / 2 - 90, W, 200, p.dark);
      this.engine.stroke(0, H / 2 - 90, W, 200, p.bad, 2);
      this.engine.text('GAME OVER', W / 2, H / 2 - 78, 32, p.bad, 'center');
      this.engine.text('SCORE  ' + this.score, W / 2, H / 2 - 32, 20, p.fg, 'center');
      this.engine.text('BEST   ' + this.high,  W / 2, H / 2 - 4,  16, p.dim, 'center');
      this.engine.text('TAP TO RETRY', W / 2, H / 2 + 38, 16, p.mid, 'center');
      this.engine.text('BACK: MENU',   W / 2, H / 2 + 62, 13, p.dim, 'center');
    }

    // ---- クールダウンインジケータ（選択都市付近に表示）----
    if (this._fireCooldown > 0 && !this.dead) {
      const coolRef = this._rapidTimer > 0 ? RAPID_COOLDOWN : FIRE_COOLDOWN;
      const frac    = clamp(1 - this._fireCooldown / coolRef, 0, 1);
      const barW    = 28;
      // 選択都市がある場合はその上、なければ画面中央下
      let barX, barY;
      if (this._selectedCity >= 0 && this.cities[this._selectedCity] && this.cities[this._selectedCity].alive) {
        barX = CITY_XS[this._selectedCity] + (CITY_W - barW) / 2;
        barY = GROUND_Y - CITY_H - 10;
      } else {
        barX = W / 2 - barW / 2;
        barY = GROUND_Y - CITY_H - 10;
      }
      ctx.save();
      ctx.fillStyle = p.dark;
      ctx.fillRect(barX, barY, barW, 3);
      ctx.fillStyle = p.mid;
      ctx.fillRect(barX, barY, Math.max(0, barW * frac), 3);
      ctx.restore();
    }
  }

  // ---- ボスHPバー（トップHUDストリップ内） ----
  // ボスが画面内に入ったとき（boss.y + boss.r > 0）のみ表示
  _drawBossHPHud(ctx, p) {
    if (!this._bossAlive || this._bossIdx < 0) return;
    const boss = this.meteors[this._bossIdx];
    if (!boss) return;

    // ボスが画面内に入っていなければ表示しない（バグ修正）
    if (boss.y + boss.r <= 0) return;

    const hpFrac     = clamp(boss.hp / boss.maxHp, 0, 1);
    const damageFrac = 1 - hpFrac;

    // トップHUDストリップ内に細いバーを引く（y=52〜58 あたり）
    const barX = 52;
    const barY = 52;
    const barW = W - barX - 8;
    const barH = 5;

    ctx.save();
    // 背景
    ctx.fillStyle = p.dark;
    ctx.fillRect(barX, barY, barW, barH);
    // HP残量
    const fillColor = damageFrac > 0.6 ? p.bad : p.warn;
    ctx.fillStyle = fillColor;
    ctx.fillRect(barX, barY, Math.max(0, barW * hpFrac), barH);
    // 枠
    ctx.strokeStyle = p.dim;
    ctx.lineWidth = 1;
    ctx.strokeRect(barX, barY, barW, barH);
    ctx.restore();

    // "BOSS" ラベル + HP数値
    this.engine.text('BOSS', barX, barY - 14, 11, p.warn, 'left');
    this.engine.text(boss.hp + '/' + boss.maxHp, barX + barW, barY - 14, 11, p.dim, 'right');
  }

  // ---- ボスクラック描画（ダメージ可視化） ----
  // ctx はボス中心に translate + rotate 済みの状態で呼ばれる
  _drawBossCracks(ctx, p, m, damageFrac) {
    if (!m.verts || m.verts.length < 6) return;
    const verts = m.verts;
    const n     = verts.length;
    const r     = m.r;

    ctx.save();
    ctx.strokeStyle = p.dim;

    // HP残量に応じてクラックの本数と長さが増える（閾値3段階）
    const phase1 = damageFrac > 0.25; // 25%ダメージ
    const phase2 = damageFrac > 0.50; // 50%ダメージ
    const phase3 = damageFrac > 0.75; // 75%ダメージ

    if (phase1) {
      // クラック1: 中心から頂点0と頂点2を結ぶ線
      ctx.globalAlpha = clamp(damageFrac * 0.65, 0, 1);
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.moveTo(verts[0].dx * 0.1, verts[0].dy * 0.1);
      ctx.lineTo(verts[0].dx * 0.85, verts[0].dy * 0.85);
      ctx.moveTo(verts[Math.floor(n / 3)].dx * 0.15, verts[Math.floor(n / 3)].dy * 0.15);
      ctx.lineTo(verts[Math.floor(n / 3)].dx * 0.80, verts[Math.floor(n / 3)].dy * 0.80);
      ctx.strokeStyle = p.warn;
      ctx.stroke();
    }

    if (phase2) {
      // クラック2: 頂点同士を繋ぐ斜め線（ひびが広がる）
      ctx.globalAlpha = clamp((damageFrac - 0.5) * 2 * 0.7, 0, 1);
      ctx.lineWidth = 2.0;
      ctx.strokeStyle = p.bad;
      ctx.beginPath();
      const v1 = verts[1];
      const v4 = verts[Math.min(4, n - 1)];
      const v6 = verts[Math.min(6, n - 1)];
      ctx.moveTo(v1.dx * 0.9, v1.dy * 0.9);
      ctx.lineTo(v4.dx * 0.6, v4.dy * 0.6);
      ctx.lineTo(v6.dx * 0.85, v6.dy * 0.85);
      ctx.stroke();
      // 内部亀裂
      ctx.globalAlpha = clamp((damageFrac - 0.5) * 1.4 * 0.5, 0, 1);
      ctx.lineWidth = 1;
      ctx.strokeStyle = p.dim;
      ctx.beginPath();
      ctx.moveTo(-r * 0.25, -r * 0.1);
      ctx.lineTo(r * 0.4, r * 0.35);
      ctx.moveTo(r * 0.1, -r * 0.3);
      ctx.lineTo(-r * 0.35, r * 0.2);
      ctx.stroke();
    }

    if (phase3) {
      // クラック3: 大きな分裂線（ほぼ崩壊状態）
      ctx.globalAlpha = clamp((damageFrac - 0.75) * 4 * 0.85, 0, 1);
      ctx.lineWidth = 3;
      ctx.strokeStyle = p.bad;
      ctx.beginPath();
      ctx.moveTo(-r * 0.8, -r * 0.2);
      ctx.lineTo(r * 0.6, r * 0.5);
      ctx.moveTo(r * 0.7, -r * 0.5);
      ctx.lineTo(-r * 0.5, r * 0.6);
      ctx.stroke();
      // 欠けたチャンクの輪郭（崩れたエッジ）
      ctx.globalAlpha = clamp((damageFrac - 0.75) * 3 * 0.5, 0, 1);
      ctx.lineWidth = 1.5;
      ctx.strokeStyle = p.warn;
      ctx.setLineDash([4, 3]);
      ctx.beginPath();
      const cv = verts[Math.floor(n * 0.6)];
      ctx.arc(cv.dx * 0.7, cv.dy * 0.7, r * 0.18, 0, Math.PI * 2);
      ctx.stroke();
      ctx.setLineDash([]);
    }

    ctx.restore();
  }

  // ---- 左端アクティブアイテムパネル ----
  // BACKボタン（y:8..44）を避けて y=52 から下へ縦並び
  _drawActiveItemsPanel(ctx, p) {
    const panelX  = 2;   // 左端から
    const barW    = 36;  // カウントダウンバーの幅
    const barH    = 4;
    const rowH    = 18;  // 1行の高さ
    let   rowY    = 58;  // 開始Y（BACKボタン下 + 少し余白）

    const labelX  = panelX;
    const barX    = panelX;

    // ---- SCATTERの残弾 ----
    if (this._scatterAmmo > 0) {
      ctx.save();
      // ラベル（短い全単語）
      this.engine.text('SCAT', labelX, rowY, 8, p.hi, 'left');
      // ドット状の残弾表示
      for (let i = 0; i < Math.min(this._scatterAmmo, 9); i++) {
        ctx.beginPath();
        ctx.arc(panelX + 28 + i * 5, rowY + 4, 2, 0, Math.PI * 2);
        ctx.fillStyle = p.hi;
        ctx.fill();
      }
      ctx.restore();
      rowY += rowH;
    }

    // ---- ランチャースロット数（MULTIで増加） ----
    if (this._launcherSlots > 2) {
      ctx.save();
      this.engine.text('SLOTS', labelX, rowY, 8, p.mid, 'left');
      for (let i = 0; i < this._launcherSlots; i++) {
        ctx.beginPath();
        ctx.arc(panelX + 32 + i * 5, rowY + 4, 2, 0, Math.PI * 2);
        ctx.fillStyle = i < this._launcherSlots ? p.mid : p.dark;
        ctx.fill();
      }
      ctx.restore();
      rowY += rowH;
    }

    // ---- RAPIDバフ（タイマー）----
    if (this._rapidTimer > 0) {
      const frac = clamp(this._rapidTimer / RAPID_DURATION, 0, 1);
      ctx.save();
      this.engine.text('RAPID', labelX, rowY, 8, p.warn, 'left');
      // カウントダウンバー
      ctx.fillStyle = p.dark;
      ctx.fillRect(barX + 32, rowY + 4, barW, barH);
      ctx.fillStyle = p.warn;
      ctx.fillRect(barX + 32, rowY + 4, Math.max(0, barW * frac), barH);
      // 秒数
      this.engine.text(Math.ceil(this._rapidTimer) + 's', barX + 32 + barW + 2, rowY, 8, p.warn, 'left');
      ctx.restore();
      rowY += rowH;
    }

    // ---- POWERバフ（都市別タイマー）----
    for (let ci = 0; ci < CITY_COUNT; ci++) {
      const city = this.cities[ci];
      if (!city || !city.alive || !city.buffs.power.length) continue;
      // 最大タイマー（最も長いもの）を代表として表示
      const maxT = Math.max(...city.buffs.power.map(b => b.timer));
      const frac = clamp(maxT / BUFF_DURATION, 0, 1);
      ctx.save();
      this.engine.text('PWR' + (ci + 1), labelX, rowY, 8, p.warn, 'left');
      ctx.fillStyle = p.dark;
      ctx.fillRect(barX + 28, rowY + 4, barW - 4, barH);
      ctx.fillStyle = p.warn;
      ctx.fillRect(barX + 28, rowY + 4, Math.max(0, (barW - 4) * frac), barH);
      ctx.restore();
      rowY += rowH;
      if (rowY > GROUND_Y - 30) break;
    }

    // ---- WIDEバフ（都市別タイマー）----
    for (let ci = 0; ci < CITY_COUNT; ci++) {
      const city = this.cities[ci];
      if (!city || !city.alive || !city.buffs.wide.length) continue;
      const maxT = Math.max(...city.buffs.wide.map(b => b.timer));
      const frac = clamp(maxT / BUFF_DURATION, 0, 1);
      ctx.save();
      this.engine.text('WIDE' + (ci + 1), labelX, rowY, 8, p.hi, 'left');
      ctx.fillStyle = p.dark;
      ctx.fillRect(barX + 28, rowY + 4, barW - 4, barH);
      ctx.fillStyle = p.hi;
      ctx.fillRect(barX + 28, rowY + 4, Math.max(0, (barW - 4) * frac), barH);
      ctx.restore();
      rowY += rowH;
      if (rowY > GROUND_Y - 30) break;
    }
  }

  // ---- アイテム隕石の描画 ----
  _drawItemMeteor(ctx, p, m) {
    if (!m.verts || m.verts.length < 3) return;
    const pulse = 0.75 + 0.25 * Math.sin(this._elapsed * 5.0);

    ctx.save();
    ctx.globalAlpha = clamp(pulse, 0, 1);
    ctx.translate(m.x, m.y);
    ctx.rotate(m.rot);

    ctx.beginPath();
    ctx.moveTo(m.verts[0].dx, m.verts[0].dy);
    for (let vi = 1; vi < m.verts.length; vi++) {
      ctx.lineTo(m.verts[vi].dx, m.verts[vi].dy);
    }
    ctx.closePath();
    ctx.strokeStyle = p.hi;
    ctx.lineWidth = 2.5;
    ctx.stroke();
    ctx.fillStyle = p.hi;
    ctx.globalAlpha = clamp(pulse * 0.12, 0, 1);
    ctx.fill();

    ctx.restore();

    ctx.save();
    ctx.globalAlpha = clamp(pulse, 0, 1);
    const label = m.itemType ? m.itemType[0] : '?';
    this.engine.text(label, m.x, m.y - 6, 13, p.warn, 'center');
    ctx.restore();
  }

  // ---- ビッグブラスト HUD ----
  _drawBigChargeHUD(ctx, p) {
    const baseX = W / 2 - 40;
    const baseY = 60;
    const b = this._bigBtnRect();
    if (this._bigArmed) {
      this.engine.stroke(b.x, b.y, b.w, b.h, p.hi, 2);
      this.engine.text('TAP SKY', b.x + b.w + 6, baseY, 11, p.hi, 'left');
    }
    this.engine.text('BIG:', baseX, baseY, 13, this._bigArmed ? p.hi : p.dim, 'left');
    for (let i = 0; i < BIG_CHARGES_MAX; i++) {
      const cx = baseX + 44 + i * 18;
      const cy = baseY + 6;
      ctx.save();
      ctx.beginPath();
      ctx.arc(cx, cy, 6, 0, Math.PI * 2);
      if (i < this._bigCharges) {
        ctx.fillStyle = p.warn;
        ctx.fill();
      } else {
        ctx.strokeStyle = p.dim;
        ctx.lineWidth = 1.5;
        ctx.stroke();
      }
      ctx.restore();
    }
    if (this._bigCharges < BIG_CHARGES_MAX) {
      const gaugeX = baseX;
      const gaugeY = baseY + 16;
      const gaugeW = 96;
      const frac   = clamp(this._bigRecharge / BIG_RECHARGE_SEC, 0, 1);
      this.engine.rect(gaugeX, gaugeY, gaugeW, 4, p.dark);
      this.engine.rect(gaugeX, gaugeY, Math.floor(gaugeW * frac), 4, p.warn);
    }
  }

  // ---- 星空 ----
  _drawStarfield(ctx, p) {
    ctx.save();
    ctx.fillStyle = p.dim;
    const stars = [
      [30,80],[90,55],[150,100],[220,60],[280,90],[340,70],
      [60,140],[130,170],[200,130],[260,155],[320,120],
      [45,210],[110,240],[180,200],[250,220],[315,180],
      [70,300],[160,280],[230,310],[300,290],
    ];
    for (const [sx, sy] of stars) {
      ctx.beginPath();
      ctx.arc(sx, sy, 1, 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.restore();
  }

  // ---- 都市（山シルエット＋ワイヤーフレーム街並み）----
  _drawCity(ctx, p, idx) {
    const ox = CITY_XS[idx];
    const oy = GROUND_Y - CITY_H;
    const city = this.cities[idx];
    const isSelected = (this._selectedCity === idx && city.alive);

    if (!city.alive) {
      // 瓦礫（ランダムな小石ブロック）
      ctx.save();
      ctx.strokeStyle = p.dim;
      ctx.lineWidth = 1;
      // 瓦礫を簡易描画（固定パターン）
      const rubble = [
        [0, CITY_H - 4, 8, 4],
        [10, CITY_H - 6, 10, 6],
        [22, CITY_H - 3, 6, 3],
        [4, CITY_H - 8, 6, 3],
        [16, CITY_H - 9, 8, 4],
      ];
      ctx.fillStyle = p.dark;
      for (const [rx, ry, rw, rh] of rubble) {
        ctx.fillRect(ox + rx, oy + ry, rw, rh);
        ctx.strokeRect(ox + rx, oy + ry, rw, rh);
      }
      // 煙（小さな×印）
      ctx.strokeStyle = p.bad;
      ctx.lineWidth = 1.5;
      const mx = ox + CITY_W / 2, my = oy + CITY_H / 2 - 4;
      ctx.beginPath(); ctx.moveTo(mx - 5, my - 5); ctx.lineTo(mx + 5, my + 5); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(mx + 5, my - 5); ctx.lineTo(mx - 5, my + 5); ctx.stroke();
      ctx.restore();
      return;
    }

    // 選択ハイライト（グロー枠）
    if (isSelected) {
      ctx.save();
      ctx.strokeStyle = p.hi;
      ctx.lineWidth = 2;
      ctx.setLineDash([4, 2]);
      ctx.strokeRect(ox - 3, oy - 3, CITY_W + 6, CITY_H + 3);
      ctx.setLineDash([]);
      ctx.restore();
    }

    // 山と街並みシルエット（ワイヤーフレーム）
    const profile = CITY_PROFILES[idx];
    if (profile && profile.length >= 3) {
      ctx.save();
      ctx.translate(ox, oy);

      // フィル（薄暗く）
      ctx.beginPath();
      ctx.moveTo(profile[0].x, profile[0].y);
      for (let i = 1; i < profile.length; i++) {
        ctx.lineTo(profile[i].x, profile[i].y);
      }
      ctx.closePath();
      ctx.fillStyle = p.dark;
      ctx.globalAlpha = 0.85;
      ctx.fill();

      // アウトライン
      ctx.globalAlpha = 1.0;
      ctx.beginPath();
      ctx.moveTo(profile[0].x, profile[0].y);
      for (let i = 1; i < profile.length; i++) {
        ctx.lineTo(profile[i].x, profile[i].y);
      }
      ctx.closePath();
      ctx.strokeStyle = isSelected ? p.hi : p.mid;
      ctx.lineWidth   = isSelected ? 1.8 : 1.2;
      ctx.stroke();

      ctx.restore();
    }

    // バフ状態（上部に小ドット）
    const buffs = city.buffs;
    let dotX = ox;
    const dotY = oy - 6;
    for (let k = 0; k < buffs.power.length; k++) {
      ctx.save();
      ctx.beginPath();
      ctx.arc(dotX + 3, dotY, 2.5, 0, Math.PI * 2);
      ctx.fillStyle = p.warn;
      ctx.fill();
      ctx.restore();
      dotX += 7;
    }
    for (let k = 0; k < buffs.wide.length; k++) {
      ctx.save();
      ctx.beginPath();
      ctx.arc(dotX + 3, dotY, 2.5, 0, Math.PI * 2);
      ctx.fillStyle = p.hi;
      ctx.fill();
      ctx.restore();
      dotX += 7;
    }

    // 発射位置マーカー（小三角形）
    ctx.save();
    const mx  = ox + CITY_W / 2;
    const mby = oy - 1;
    ctx.fillStyle = isSelected ? p.hi : p.fg;
    ctx.globalAlpha = isSelected ? 1.0 : 0.5;
    ctx.beginPath();
    ctx.moveTo(mx, mby - 6);
    ctx.lineTo(mx - 3, mby);
    ctx.lineTo(mx + 3, mby);
    ctx.closePath();
    ctx.fill();
    ctx.restore();
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/lander.js ----
(function(){
// LANDER: Control attitude with RCS thrusters and soft-land on the lunar surface.
// Reaction-thruster convention (physically correct):
//   LEFT  button (x < 120): right-side thruster fires RIGHT -> reaction pushes nose LEFT  -> craft rotates CW  (omega +)
//   RIGHT button (x > 240): left-side thruster fires LEFT  -> reaction pushes nose RIGHT -> craft rotates CCW (omega -)
//   THRUST button (center): main engine fires along craft's up-axis.
// Safe landing on the pad = STAGE CLEAR. Crash = GAME OVER.

const meta = {
  id: 'lander',
  title: 'LANDER',
  desc: 'Attitude control: soft-land on the lunar surface',
  glyph: '^',
};

// ---- Physics tuning constants ----
// GRAVITY_BASE: Stage-1 gravity in px/s^2. ゆっくりとした降下で余裕のある操作感。
// THRUST_ACCEL: メインエンジン加速度。明確に降下を止められる適度な推力。
// ANG_ACCEL: RCS回転加速度。慎重な姿勢制御のため抑え目。
// ANG_DAMP: 角速度の減衰。パイロットが姿勢を安定させやすくする。
// RCS_DRIFT: サイドジェットの横方向ドリフト量（px/s^2）。ジェット排気の反作用。
const GRAVITY_BASE      = 0.25;  // px/s^2 — ステージ1はさらにゆっくりとした降下（旧値0.35）
const THRUST_ACCEL      = 5.2;   // px/s^2 — 明確に降下を止められる推力（旧値3.5）。保持すれば確実に上昇。
const ANG_ACCEL         = 28.0;  // deg/s^2 — 慎重な姿勢変更（旧値40.0）
const ANG_DAMP          = 0.82;  // 角速度減衰（旧値0.88、より強い減衰で安定しやすく）
const RCS_DRIFT         = 2.5;   // px/s^2 — サイドジェット横ドリフト（排気反作用）
// NO VEL_DAMP — 並進運動はニュートン力学（減衰なし）
const FUEL_MAX          = 100;
const FUEL_RATE_MAIN    = 5;     // 燃料消費（主エンジン）
const FUEL_RATE_RCS     = 1.5;   // 燃料消費（RCS）

// ---- Landing tolerance constants ----
// 成功着陸の許容値（緩め）。ここを下回れば即成功。
const SAFE_VY           = 22;    // px/s 垂直速度上限（旧値14）
const SAFE_VX           = 13;    // px/s 水平速度上限（旧値8）
const SAFE_ANGLE        = 28;    // deg  傾き上限（旧値18）
const SAFE_OMEGA        = 20;    // deg/s 角速度上限（旧値12）

// バウンス許容値（SAFE_*を超えてもここを下回ればバウンスで再チャンス）。
// BOUNCE_*はSAFE_*より大きな値。接触速度が低ければ「弾んで落ち着く」挙動。
const BOUNCE_VY         = 45;    // px/s 垂直速度上限（これ以上は即クラッシュ）
const BOUNCE_VX         = 26;    // px/s 水平速度上限（これ以上は即クラッシュ）
const BOUNCE_ANGLE      = 55;    // deg  傾き上限（これ以上は即クラッシュ）
const BOUNCE_OMEGA      = 40;    // deg/s 角速度上限（これ以上は即クラッシュ）

// バウンス後の速度反発係数（着地面との反射）
const BOUNCE_RESTITUTION = 0.28; // 垂直速度の残存率（0=完全吸収, 1=完全弾性）
const BOUNCE_FRICTION    = 0.55; // 水平速度の残存率（摩擦）
const BOUNCE_ANG_DAMP    = 0.45; // バウンス後の角速度残存率
// バウンスで着陸成功とみなす速度しきい値（バウンス後にこれ以下になったら成功）
const BOUNCE_SETTLE_VY   = 6;    // px/s
const PAD_W_BASE        = 54;
const TERRAIN_SEGS      = 18;
const LANDER_START_Y    = 90;
const GUIDE_THRESHOLD   = 30;    // ON COURSEとみなす誘導線からの距離(px)
const GUIDE_PTS         = 32;

// Control zones (logical coordinates 0..360)
const ZONE_L_MAX  = 120;  // left button: x < ZONE_L_MAX
const ZONE_R_MIN  = 240;  // right button: x > ZONE_R_MIN
const CONTROL_Y_MIN = 52; // ignore pointer input above this Y (BACK button zone)

// Bottom button bar geometry
const BTN_Y   = H - 80;  // top of button bar
const BTN_H   = 80;       // height of button bar

// ---- Stage difficulty scaling ----
// Stage 1: low gravity, no obstacles.
// Stage 2+: gravity increases per stage; floating obstacles added and multiplied.
function stageParams(stage) {
  const s = Math.min(stage, 8);
  return {
    // gravity increases ~15% per stage beyond stage 1
    gravity:      GRAVITY_BASE * (1 + (s - 1) * 0.15),
    padW:         Math.max(24, PAD_W_BASE - (s - 1) * 4),
    stageBonus:   s * 50,
    // obstacles: 0 in stage 1, then 2 + (s-2) extras per stage
    obstacleCount: s <= 1 ? 0 : 2 + (s - 2),
    // obstacle drift speed scales with stage
    obstacleSpeed: 12 + (s - 1) * 4,
  };
}

// ---- Terrain generation ----
function buildTerrain(padW) {
  const segW    = W / TERRAIN_SEGS;
  const FLOOR_Y   = 608;
  const FLOOR_MIN = 525;
  const pts       = [];

  // Pick one random segment for the landing pad
  const available = [];
  for (let i = 2; i < TERRAIN_SEGS - 3; i++) available.push(i);
  const padSeg = available[Math.floor(Math.random() * available.length)];

  for (let i = 0; i <= TERRAIN_SEGS; i++) {
    const x = i * segW;
    let y;
    if (i === 0 || i === TERRAIN_SEGS) {
      y = FLOOR_Y;
    } else {
      y = FLOOR_MIN + Math.random() * (FLOOR_Y - FLOOR_MIN);
    }
    pts.push({ x, y });
  }

  // Flatten the pad segment
  const midX  = (padSeg + 0.5) * segW;
  const flatY = FLOOR_MIN + 20 + Math.random() * 50;
  const lx    = midX - padW / 2;
  pts[padSeg].y     = flatY;
  pts[padSeg + 1].y = flatY;
  if (padSeg > 0)                  pts[padSeg - 1].y = (pts[padSeg - 1].y + flatY) / 2;
  if (padSeg + 2 <= TERRAIN_SEGS)  pts[padSeg + 2].y = (pts[padSeg + 2].y + flatY) / 2;

  const pad = { x: lx, y: flatY, w: padW };
  return { pts, pad };
}

// ---- Stars (background) ----
function buildStars(count) {
  const stars = [];
  for (let i = 0; i < count; i++) {
    stars.push({
      x: Math.random() * W,
      y: 20 + Math.random() * 460,
      r: Math.random() < 0.2 ? 2 : 1,
    });
  }
  return stars;
}

// ---- Descent trajectory guide (parabolic from start to pad center) ----
function buildGuide(startX, startY, pad, numPts) {
  const targetX = pad.x + pad.w / 2;
  const targetY = pad.y;
  const pts     = [];
  for (let i = 0; i <= numPts; i++) {
    const t = i / numPts;
    pts.push({
      x: startX + (targetX - startX) * t,
      y: startY + (targetY - startY) * (t * t),
    });
  }
  return pts;
}

// ---- Floating obstacles (stages 2+) ----
// Obstacles drift horizontally. They appear in the mid-descent zone (y 150-480)
// and bounce off the left/right walls. Touching one = crash.
function buildObstacles(count, speed) {
  const obs = [];
  if (count <= 0) return obs;
  for (let i = 0; i < count; i++) {
    // Spread evenly through descent zone, avoid spawning right at the start
    const yBand   = 150 + (i / count) * 300 + Math.random() * 60;
    const vxSign  = Math.random() < 0.5 ? 1 : -1;
    const r       = 10 + Math.floor(Math.random() * 8); // radius 10-17
    obs.push({
      x:  30 + Math.random() * (W - 60),
      y:  Math.max(150, Math.min(480, yBand)),
      vx: (speed * 0.6 + Math.random() * speed * 0.8) * vxSign,
      r,
    });
  }
  return obs;
}

class Game extends Scene {

  enter() {
    this.high       = (this.engine.storage.getHigh(meta.id) || 0);
    this.totalScore = 0;
    this.stage      = 1;
    this.state      = 'play';
    this._initStage();
  }

  // ---- Initialize one stage ----
  _initStage() {
    this.state    = 'play';
    this.fuel     = FUEL_MAX;
    this.angle    = (Math.random() - 0.5) * 8;  // tiny initial tilt (degrees)
    this.omega    = 0;                           // angular velocity (deg/s)
    this.x        = W / 2 + (Math.random() - 0.5) * 50;
    this.y        = LANDER_START_Y;
    this.vx       = (Math.random() - 0.5) * 4;  // near-zero initial horizontal speed
    this.vy       = 2;                           // slow initial downward speed

    this._thrustMain = false;
    this._thrustRcsL = false;
    this._thrustRcsR = false;

    const sp       = stageParams(this.stage);
    this._gravity  = sp.gravity;
    this._padW     = sp.padW;

    const terrain     = buildTerrain(this._padW);
    this.terrainPts   = terrain.pts;
    this.pad          = terrain.pad;
    this.stars        = this.stars || buildStars(40);

    this.guidePts = buildGuide(this.x, this.y, this.pad, GUIDE_PTS);

    this._guideDevTotal = 0;
    this._guideDevCount = 0;
    this._stageScore    = 0;
    this._guideBonus    = 0;
    this.particles      = [];

    // バウンス状態フラグ（マージナル着地後に弾んでいる最中）
    this._bouncing = false;

    // ON COURSEポップインジケーター用タイマー
    this._onCourseTime = 0;   // ON COURSE状態の累積時間(秒)
    this._onCoursePulse = 0;  // 点滅アニメーション用位相(秒)

    // Floating obstacles (stage 2+)
    this.obstacles = buildObstacles(sp.obstacleCount, sp.obstacleSpeed);

    this._keys = this._keys || { left: false, right: false, up: false };
  }

  // ---- Distance to nearest guide point ----
  _distToGuide(x, y) {
    let minDist = Infinity;
    const pts = this.guidePts;
    if (!pts) return Infinity;
    for (let i = 0; i < pts.length; i++) {
      const dx = x - pts[i].x;
      const dy = y - pts[i].y;
      const d  = Math.sqrt(dx * dx + dy * dy);
      if (d < minDist) minDist = d;
    }
    return minDist;
  }

  // ---- Keyboard discrete input ----
  onInput(action, data) {
    if (this.state === 'cleared') {
      if (action === 'tap' || action === 'confirm') {
        this.stage += 1;
        this._initStage();
      }
      if (action === 'back') { this.engine.toMenu(); }
      return;
    }
    if (this.state === 'gameover') {
      if (action === 'tap' || action === 'confirm') {
        this.totalScore = 0;
        this.stage      = 1;
        this._initStage();
      }
      if (action === 'back') { this.engine.toMenu(); }
      return;
    }
    if (action === 'back') { this.engine.toMenu(); return; }

    if (this._keys) {
      if (action === 'left')    this._keys.left  = true;
      if (action === 'right')   this._keys.right = true;
      if (action === 'up')      this._keys.up    = true;
      if (action === 'confirm') this._keys.up    = true;
    }
  }

  // ---- Per-frame logic ----
  update(dt) {
    if (typeof dt !== 'number' || dt <= 0 || dt > 0.1) dt = 0.016;

    if (this.state !== 'play') {
      this._updateParticles(dt);
      if (this._keys) { this._keys.left = false; this._keys.right = false; this._keys.up = false; }
      return;
    }

    const ptr = this.engine.pointer;

    // ---- Read control inputs ----
    // Pointer press-and-hold in the bottom button bar (y > BTN_Y) is the primary control.
    // Top strip y < CONTROL_Y_MIN is ignored to avoid conflicting with the BACK button.
    this._thrustMain = false;
    this._thrustRcsL = false;
    this._thrustRcsR = false;

    if (ptr.down && ptr.y > CONTROL_Y_MIN) {
      if (ptr.x < ZONE_L_MAX) {
        // LEFT button pressed
        this._thrustRcsL = true;
      } else if (ptr.x > ZONE_R_MIN) {
        // RIGHT button pressed
        this._thrustRcsR = true;
      } else {
        // CENTER: main engine
        this._thrustMain = true;
      }
    }

    // Keyboard (one-shot pulse per frame)
    if (this._keys) {
      if (this._keys.left)  this._thrustRcsL = true;
      if (this._keys.right) this._thrustRcsR = true;
      if (this._keys.up)    this._thrustMain  = true;
      this._keys.left  = false;
      this._keys.right = false;
      this._keys.up    = false;
    }

    // ---- RCS attitude jets — reaction-thruster convention ----
    // Physical convention: the nozzle FIRES toward the button side; Newton's 3rd law
    // pushes the craft nose the OPPOSITE way.
    //
    // LEFT button  -> left-side nozzle fires leftward -> nose pushed RIGHT -> CW rotation
    //   omega += ANG_ACCEL * dt  (positive omega -> angle increases -> ctx.rotate(+rad) -> CW on screen)
    //
    // RIGHT button -> right-side nozzle fires rightward -> nose pushed LEFT -> CCW rotation
    //   omega -= ANG_ACCEL * dt  (negative omega -> angle decreases -> ctx.rotate(-rad) -> CCW on screen)
    //
    // サイドジェット横ドリフト（排気反作用）:
    //   LEFT  button -> 左ノズルが左に排気 -> 機体が右にドリフト (vx += RCS_DRIFT * dt)
    //   RIGHT button -> 右ノズルが右に排気 -> 機体が左にドリフト (vx -= RCS_DRIFT * dt)
    //
    // Keyboard: ArrowLeft maps to _thrustRcsL (same CW convention).
    //           ArrowRight maps to _thrustRcsR (same CCW convention).
    if (this._thrustRcsL && this.fuel > 0) {
      this.omega += ANG_ACCEL * dt;         // CW: nose tilts RIGHT
      this.vx    += RCS_DRIFT * dt;         // 左ノズル排気反作用 -> 右ドリフト
      this.fuel   = Math.max(0, this.fuel - FUEL_RATE_RCS * dt);
    }
    if (this._thrustRcsR && this.fuel > 0) {
      this.omega -= ANG_ACCEL * dt;         // CCW: nose tilts LEFT
      this.vx    -= RCS_DRIFT * dt;         // 右ノズル排気反作用 -> 左ドリフト
      this.fuel   = Math.max(0, this.fuel - FUEL_RATE_RCS * dt);
    }

    // ---- Angular damping (mild drag so craft can be stabilized) ----
    this.omega *= Math.pow(ANG_DAMP, dt);

    // ---- Integrate omega -> angle ----
    this.angle += this.omega * dt;
    // Normalize to -180..180
    this.angle  = ((this.angle + 180) % 360 + 360) % 360 - 180;

    // ---- Main engine: thrust along craft's NOSE (up-axis), i.e. opposite the exhaust ----
    // 描画は ctx.translate(x,y); ctx.rotate(rad) で機体ローカルの上(0,-1)を回す。
    // 回転後のワールド上方向(機首) = (sin(rad), -cos(rad))。推進はこの機首方向に働く。
    //   angle=0   -> (0,-1)  : まっすぐ上昇
    //   angle=+90 -> (1, 0)  : 機首が3時 -> 3時方向へ移動（排気は9時）
    //   angle=-90 -> (-1,0)  : 機首が9時 -> 9時方向へ移動
    // ※以前は vx の符号が逆で、傾くと排気側（逆方向）へ押していた不具合を修正。
    if (this._thrustMain && this.fuel > 0) {
      const rad = this.angle * Math.PI / 180;
      this.vx  += ( Math.sin(rad)) * THRUST_ACCEL * dt;
      this.vy  += (-Math.cos(rad)) * THRUST_ACCEL * dt;
      this.fuel = Math.max(0, this.fuel - FUEL_RATE_MAIN * dt);
    }

    // ---- Gravity (straight down = +Y in canvas) ----
    // NO translational damping. Purely Newtonian: only gravity and engine thrust change velocity.
    this.vy += this._gravity * dt;

    // ---- Position update ----
    this.x += this.vx * dt;
    this.y += this.vy * dt;

    // ---- Horizontal clamp (weak bounce at edges) ----
    const PAD = 14;
    if (this.x < PAD)     { this.x = PAD;     this.vx =  Math.abs(this.vx) * 0.3; }
    if (this.x > W - PAD) { this.x = W - PAD; this.vx = -Math.abs(this.vx) * 0.3; }
    // Top clamp
    if (this.y < 60) { this.y = 60; this.vy = Math.max(0, this.vy); }

    // ---- Guide deviation tracking (upper half only) ----
    // 誘導線からの偏差を累積。スコアリングに使用。
    const guideDist = this._distToGuide(this.x, this.y);
    if (this.y < 420) {
      this._guideDevTotal += guideDist;
      this._guideDevCount += 1;
    }

    // ---- ON COURSE pulse timer update ----
    if (guideDist <= GUIDE_THRESHOLD && this.state === 'play') {
      this._onCourseTime  += dt;
      this._onCoursePulse += dt;
    } else {
      // 誘導線を外れたらタイマーリセット（点滅は停止）
      this._onCourseTime  = 0;
      this._onCoursePulse = 0;
    }

    // ---- Update floating obstacles (stages 2+) ----
    if (this.obstacles && this.obstacles.length > 0) {
      for (const ob of this.obstacles) {
        ob.x += ob.vx * dt;
        // Bounce off walls
        if (ob.x - ob.r < 0)     { ob.x = ob.r;     ob.vx = Math.abs(ob.vx); }
        if (ob.x + ob.r > W)     { ob.x = W - ob.r; ob.vx = -Math.abs(ob.vx); }
      }
      // Check collision with lander (circle vs. point, craft body ~16x18 -> use 14px radius)
      const craftR = 14;
      for (const ob of this.obstacles) {
        const dx = this.x - ob.x;
        const dy = this.y - ob.y;
        if (Math.sqrt(dx * dx + dy * dy) < craftR + ob.r) {
          // Hit an obstacle — crash
          this._explode();
          this.engine.audio.bad();
          this.totalScore += Math.round((this.fuel || 0) * 2);
          if (this.totalScore > this.high) {
            this.high = this.totalScore;
            this.engine.storage.setHigh(meta.id, this.high);
          }
          this.state = 'gameover';
          return;
        }
      }
    }

    // ---- Terrain collision ----
    this._checkCollision();
  }

  // ---- Collision & landing check ----
  // 着地判定の優先順位:
  //   1. パッドの外に接触 -> 即クラッシュ
  //   2. パッド上 + SAFE_*以内 -> 即成功
  //   3. パッド上 + BOUNCE_*以内 (マージナル) -> バウンス。次フレームで再判定。
  //      バウンス後にvy <= BOUNCE_SETTLE_VYになれば成功として処理。
  //   4. パッド上 + BOUNCE_*超え (高速/大傾き) -> 即クラッシュ
  _checkCollision() {
    const terrainY = this._terrainYAt(this.x);
    const footY    = this.y + 16;

    if (footY < terrainY) return;

    const onPad    = (this.x >= this.pad.x && this.x <= this.pad.x + this.pad.w);
    const absVy    = Math.abs(this.vy);
    const absVx    = Math.abs(this.vx);
    const absAngle = Math.abs(((this.angle + 180) % 360 + 360) % 360 - 180);
    const absOmega = Math.abs(this.omega);

    // パッド外接触 -> クラッシュ（地形 or 障害物）
    if (!onPad) {
      this._doCrash();
      return;
    }

    // バウンス中の「静定チェック」: 前フレームのバウンスで速度が十分落ちていれば成功
    if (this._bouncing) {
      // vy が低ければ着地成功として扱う
      if (absVy <= BOUNCE_SETTLE_VY && absVx <= SAFE_VX && absAngle <= SAFE_ANGLE) {
        this._bouncing = false;
        this._doSuccess(absAngle, absOmega);
        return;
      }
      // バウンス後もまだ速すぎる/傾きすぎ -> クラッシュ
      if (absVy > BOUNCE_VY || absVx > BOUNCE_VX || absAngle > BOUNCE_ANGLE) {
        this._bouncing = false;
        this._doCrash();
        return;
      }
      // まだ接触中だがゆっくりと落ち着いている -> もう一度バウンス処理
    }

    // ---- 即成功ウィンドウ（SAFE_* 以内）----
    const safeLand = absVy <= SAFE_VY &&
                     absVx <= SAFE_VX &&
                     absAngle <= SAFE_ANGLE &&
                     absOmega <= SAFE_OMEGA;

    if (safeLand) {
      this._bouncing = false;
      this._doSuccess(absAngle, absOmega);
      return;
    }

    // ---- マージナル着地ウィンドウ（BOUNCE_* 以内）-> バウンス ----
    // 速度・角度が「そこそこ許容範囲」なら物理的に弾ませる。
    // 機体が大きく傾いていると、倒れた側のレッグが食い込んでより強く弾む。
    const canBounce = absVy <= BOUNCE_VY &&
                      absVx <= BOUNCE_VX &&
                      absAngle <= BOUNCE_ANGLE &&
                      absOmega <= BOUNCE_OMEGA;

    if (canBounce) {
      // クラフトを地面面上に押し戻す
      this.y = terrainY - 16;

      // 傾きが大きいほどバウンス反発が強くなる（物理的: 傾いた着地は不均一な接触）
      const tiltFactor = 1.0 + (absAngle / BOUNCE_ANGLE) * 0.5;  // 1.0 〜 1.5 倍
      this.vy    = -Math.abs(this.vy) * BOUNCE_RESTITUTION * tiltFactor;
      this.vx   *= BOUNCE_FRICTION;
      this.omega *= BOUNCE_ANG_DAMP;

      // 傾いた着地は機体を少し起き直させる（着地衝撃で揺れが収まる方向）
      const tipCorrection = -this.angle * 0.15;
      this.omega += tipCorrection;

      this._bouncing = true;
      // バウンス音（軽いクリック）
      this.engine.audio.beep && this.engine.audio.beep(200, 0.07, 'square', 0.10);
      return;
    }

    // ---- BOUNCE_* 超え -> 即クラッシュ ----
    this._bouncing = false;
    this._doCrash();
  }

  // ---- 着地成功処理 ----
  _doSuccess(absAngle, absOmega) {
    const terrainY = this._terrainYAt(this.x);
    // 速度ゼロにする前にボーナス計算用の値を保存
    const landVy = Math.abs(this.vy || 0);
    const landVx = Math.abs(this.vx || 0);
    this.y  = terrainY - 16;
    this.vx = 0; this.vy = 0; this.omega = 0;

    const sp        = stageParams(this.stage);
    const fuelBonus = Math.round((this.fuel || 0) * 10);

    // 着地精度ボーナス: 速度・姿勢が安全値を下回るほど高得点（landing時の実速度を使用）
    const softBonus = Math.round(Math.max(0, SAFE_VY - landVy) * 8);
    const horzBonus = Math.round(Math.max(0, SAFE_VX - landVx) * 6);
    const uprBonus  = Math.round(Math.max(0, SAFE_ANGLE - (absAngle || 0)) * 5);
    const omgBonus  = Math.round(Math.max(0, SAFE_OMEGA - (absOmega || 0)) * 4);

    // 軌道追従ボーナス: 誘導線を忠実にたどるほど高得点（最大400点）
    let guideBonus = 0;
    if (this._guideDevCount > 0) {
      const avgDev = this._guideDevTotal / this._guideDevCount;
      guideBonus = Math.round(Math.max(0, 400 - avgDev * (400 / 60)));
    }
    this._guideBonus  = guideBonus;
    this._stageScore  = fuelBonus + softBonus + horzBonus + uprBonus + omgBonus + guideBonus + sp.stageBonus;
    this.totalScore  += this._stageScore;

    if (this.totalScore > this.high) {
      this.high = this.totalScore;
      this.engine.storage.setHigh(meta.id, this.high);
    }

    this.engine.audio.good();
    this.state = 'cleared';
  }

  // ---- クラッシュ処理 ----
  _doCrash() {
    this._explode();
    this.engine.audio.bad();

    this.totalScore += Math.round((this.fuel || 0) * 2);

    if (this.totalScore > this.high) {
      this.high = this.totalScore;
      this.engine.storage.setHigh(meta.id, this.high);
    }

    this.state = 'gameover';
  }

  // ---- Explosion particles ----
  _explode() {
    this.particles = [];
    for (let i = 0; i < 28; i++) {
      const spd = 20 + Math.random() * 60;
      const dir = Math.random() * Math.PI * 2;
      this.particles.push({
        x:    this.x,
        y:    this.y,
        vx:   Math.cos(dir) * spd,
        vy:   Math.sin(dir) * spd - 25,
        life: 0.7 + Math.random() * 1.0,
        max:  1.7,
      });
    }
  }

  _updateParticles(dt) {
    if (!this.particles) return;
    for (const pt of this.particles) {
      pt.x    += pt.vx * dt;
      pt.y    += pt.vy * dt;
      pt.vy   += (this._gravity || GRAVITY_BASE) * dt;
      pt.life -= dt;
    }
    this.particles = this.particles.filter(pt => pt.life > 0);
  }

  // ---- Linear interpolation of terrain Y at given X ----
  _terrainYAt(x) {
    const pts = this.terrainPts;
    if (!pts || pts.length < 2) return H;
    for (let i = 0; i < pts.length - 1; i++) {
      if (x >= pts[i].x && x <= pts[i + 1].x) {
        const t = (x - pts[i].x) / (pts[i + 1].x - pts[i].x);
        return pts[i].y + t * (pts[i + 1].y - pts[i].y);
      }
    }
    return H;
  }

  // ---- Main render ----
  render(ctx) {
    const p = P();

    // Stars
    if (this.stars) {
      for (const s of this.stars) {
        ctx.fillStyle = s.r > 1 ? p.dim : p.dark;
        ctx.fillRect(s.x, s.y, s.r, s.r);
      }
    }

    // Descent trajectory guide (常に描画)
    this._drawGuide(ctx);

    // Floating obstacles (stages 2+)
    this._drawObstacles(ctx);

    // Terrain
    if (this.terrainPts && this.terrainPts.length > 0) {
      ctx.fillStyle = p.dark;
      ctx.beginPath();
      ctx.moveTo(0, H);
      for (const pt of this.terrainPts) ctx.lineTo(pt.x, pt.y);
      ctx.lineTo(W, H);
      ctx.closePath();
      ctx.fill();

      ctx.strokeStyle = p.dim;
      ctx.lineWidth   = 2;
      ctx.beginPath();
      for (let i = 0; i < this.terrainPts.length; i++) {
        const pt = this.terrainPts[i];
        if (i === 0) ctx.moveTo(pt.x, pt.y);
        else         ctx.lineTo(pt.x, pt.y);
      }
      ctx.stroke();
    }

    // Landing pad
    if (this.pad) {
      const pd = this.pad;
      ctx.fillStyle = p.fg;
      ctx.fillRect(pd.x, pd.y, pd.w, 4);
      ctx.fillStyle = p.mid;
      ctx.fillRect(pd.x,            pd.y, 4, 10);
      ctx.fillRect(pd.x + pd.w - 4, pd.y, 4, 10);
      // Flag pole
      ctx.fillStyle = p.mid;
      ctx.fillRect(pd.x + pd.w / 2 - 1, pd.y - 22, 2, 22);
      ctx.fillStyle = p.warn;
      ctx.fillRect(pd.x + pd.w / 2 + 1, pd.y - 20, 12, 9);
      this.engine.text('PAD', pd.x + pd.w / 2, pd.y - 38, 10, p.mid, 'center');
    }

    // Explosion particles
    if (this.particles) {
      for (const pt of this.particles) {
        const t = Math.max(0, Math.min(1, pt.life / (pt.max || 1.7)));
        ctx.fillStyle = t > 0.5 ? p.warn : p.bad;
        const r = Math.max(1, Math.round(t * 4));
        ctx.fillRect(pt.x - r / 2, pt.y - r / 2, r, r);
      }
    }

    // Lander craft
    if (this.state !== 'gameover' || (this.particles && this.particles.length > 0)) {
      if (this.state === 'play' || this.state === 'cleared') {
        this._drawLander(ctx, this.x, this.y, this.angle);
      }
    }

    // HUD
    this._drawHUD(ctx);

    // Bottom button controls
    this._drawButtons(ctx);

    // Result overlays
    if (this.state === 'cleared') {
      this._drawClearScreen(ctx);
    } else if (this.state === 'gameover') {
      this._drawGameOver(ctx);
    }
  }

  // ---- Floating obstacles ----
  _drawObstacles(ctx) {
    if (!this.obstacles || this.obstacles.length === 0) return;
    const p = P();
    for (const ob of this.obstacles) {
      // Draw as a jagged rock/asteroid (octagon-ish)
      ctx.save();
      ctx.translate(ob.x, ob.y);
      ctx.fillStyle   = p.dark;
      ctx.strokeStyle = p.bad;
      ctx.lineWidth   = 2;
      ctx.beginPath();
      const sides = 7;
      for (let i = 0; i < sides; i++) {
        // Slightly irregular radius for rock feel
        const jitter = 0.75 + (((i * 37 + 13) % 7) / 7) * 0.5;
        const angle  = (i / sides) * Math.PI * 2;
        const rx     = Math.cos(angle) * ob.r * jitter;
        const ry     = Math.sin(angle) * ob.r * jitter;
        if (i === 0) ctx.moveTo(rx, ry);
        else         ctx.lineTo(rx, ry);
      }
      ctx.closePath();
      ctx.fill();
      ctx.stroke();
      // Small warning highlight
      ctx.fillStyle   = p.warn;
      ctx.globalAlpha = Math.max(0, Math.min(1, 0.55));
      ctx.fillRect(-2, -2, 4, 4);
      ctx.globalAlpha = 1;
      ctx.restore();
    }
  }

  // ---- Descent trajectory guide ----
  // 常に描画: 誘導線は常にはっきり見えるようにする。
  // ON COURSE時: 明るく太く、機体周辺に円形マーカー＋上部テキスト表示＋パルス点滅。
  // OFF COURSE時: dim色で細いが消えない（0.55 alpha）。
  _drawGuide(ctx) {
    const p   = P();
    const pts = this.guidePts;
    if (!pts || pts.length < 2) return;

    const dist     = (this.state === 'play')
      ? this._distToGuide(this.x, this.y)
      : Infinity;
    const onCourse = (dist <= GUIDE_THRESHOLD);

    // ON COURSEパルス: sin波で輝度を変調（1Hzで点滅）
    // _onCoursePulseはupdateで加算され、sin計算で[0..1]の輝度係数に変換
    const pulse = onCourse
      ? (0.7 + 0.3 * Math.sin(((this._onCoursePulse || 0) * Math.PI * 2) * 1.5))
      : 1.0;

    // ガイドライン描画（常に表示）
    ctx.save();
    if (onCourse) {
      // ON COURSE: 明るく太い実線
      ctx.globalAlpha = Math.max(0, Math.min(1, 0.85 * pulse));
      ctx.strokeStyle = p.hi;
      ctx.lineWidth   = 2.5;
      ctx.setLineDash([6, 4]);
    } else {
      // OFF COURSE: 常に見える薄い点線（消えない）
      ctx.globalAlpha = Math.max(0, Math.min(1, 0.55));
      ctx.strokeStyle = p.warn;
      ctx.lineWidth   = 1;
      ctx.setLineDash([4, 8]);
    }
    ctx.beginPath();
    ctx.moveTo(pts[0].x, pts[0].y);
    for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
    ctx.stroke();
    ctx.setLineDash([]);

    // Diamond marker at target
    const last = pts[pts.length - 1];
    ctx.fillStyle   = onCourse ? p.hi : p.warn;
    ctx.globalAlpha = Math.max(0, Math.min(1, onCourse ? 0.9 * pulse : 0.5));
    ctx.beginPath();
    ctx.moveTo(last.x,     last.y - 8);
    ctx.lineTo(last.x + 7, last.y);
    ctx.lineTo(last.x,     last.y + 8);
    ctx.lineTo(last.x - 7, last.y);
    ctx.closePath();
    ctx.fill();
    ctx.restore();

    // ON COURSEポップインジケーター（機体周辺＋テキスト）
    if (onCourse && this.state === 'play') {
      this._drawOnCourseIndicator(ctx, pulse);
    }
  }

  // ---- ON COURSE pop indicator ----
  // 機体周辺の明るいリング＋上部のテキストバナー。
  // パルス点滅で「今乗っている」ことを明確に伝える。
  _drawOnCourseIndicator(ctx, pulse) {
    if (typeof pulse !== 'number') pulse = 1;
    const p = P();

    // 機体周囲のハローリング（スケールパルス）
    const ringR = 22 + 4 * Math.sin(((this._onCoursePulse || 0) * Math.PI * 2) * 1.5);
    ctx.save();
    ctx.globalAlpha  = Math.max(0, Math.min(1, 0.6 * pulse));
    ctx.strokeStyle  = p.hi;
    ctx.lineWidth    = 2.5;
    ctx.beginPath();
    ctx.arc(this.x, this.y, ringR, 0, Math.PI * 2);
    ctx.stroke();

    // 内側の小さなドット（中心確認マーカー）
    ctx.globalAlpha = Math.max(0, Math.min(1, 0.8 * pulse));
    ctx.fillStyle   = p.hi;
    ctx.beginPath();
    ctx.arc(this.x, this.y, 3, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // 上部テキストバナー（HUDエリアの直下）
    ctx.save();
    ctx.globalAlpha = Math.max(0, Math.min(1, pulse));
    this.engine.text('ON COURSE', W / 2, 72, 13, p.hi, 'center');
    ctx.restore();
  }

  // ---- Lander craft with 4 RCS nozzles ----
  // Rotation math (ctx.rotate convention):
  //   ctx.rotate(+rad) = clockwise (CW) on screen
  //   ctx.rotate(-rad) = counter-clockwise (CCW) on screen
  //
  //   omega > 0 -> angle increases -> ctx.rotate(+rad) -> CW on screen (nose tilts RIGHT)
  //   omega < 0 -> angle decreases -> ctx.rotate(-rad) -> CCW on screen (nose tilts LEFT)
  //
  //   LEFT  button -> omega += -> CW  (nose tilts right)   LEFT nozzle fires left -> reaction right
  //   RIGHT button -> omega -= -> CCW (nose tilts left)   RIGHT nozzle fires right -> reaction left
  //
  // The FLAME is drawn on the FIRING nozzle side, consistent with actual exhaust direction.
  _drawLander(ctx, x, y, angleDeg) {
    const p   = P();
    if (typeof x !== 'number' || typeof y !== 'number') return;
    const rad = ((angleDeg || 0) * Math.PI / 180);

    ctx.save();
    ctx.translate(x, y);
    ctx.rotate(rad);  // positive rad = CW on canvas; negative = CCW

    // Main engine flame (bottom nozzle, fires downward in body space)
    if (this._thrustMain && this.fuel > 0) {
      const fl = 10 + Math.random() * 10;
      ctx.fillStyle = p.warn;
      ctx.beginPath();
      ctx.moveTo(-6, 9);
      ctx.lineTo(0,  9 + fl);
      ctx.lineTo(6,  9);
      ctx.closePath();
      ctx.fill();
      ctx.fillStyle = p.hi;
      ctx.beginPath();
      ctx.moveTo(-3, 9);
      ctx.lineTo(0,  9 + fl * 0.5);
      ctx.lineTo(3,  9);
      ctx.closePath();
      ctx.fill();
    }

    // Body
    ctx.fillStyle   = p.mid;
    ctx.fillRect(-8, -10, 16, 18);
    ctx.strokeStyle = p.fg;
    ctx.lineWidth   = 1.5;
    ctx.strokeRect(-8, -10, 16, 18);

    // Cabin window
    ctx.fillStyle = p.hi;
    ctx.fillRect(-4, -8, 8, 7);

    // Left landing leg
    ctx.strokeStyle = p.mid;
    ctx.lineWidth   = 2;
    ctx.beginPath(); ctx.moveTo(-7, 8);   ctx.lineTo(-14, 16); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(-14, 16); ctx.lineTo(-18, 16); ctx.stroke();

    // Right landing leg
    ctx.beginPath(); ctx.moveTo(7, 8);    ctx.lineTo(14, 16);  ctx.stroke();
    ctx.beginPath(); ctx.moveTo(14, 16);  ctx.lineTo(18, 16);  ctx.stroke();

    // Main engine nozzle (bottom center)
    ctx.fillStyle = p.dark;
    ctx.fillRect(-5, 9, 10, 5);
    ctx.strokeStyle = (this._thrustMain && this.fuel > 0) ? p.warn : p.dim;
    ctx.lineWidth   = 1;
    ctx.strokeRect(-5, 9, 10, 5);

    // LEFT RCS nozzle (body left side, upper area)
    // LEFT button fires LEFT nozzle to the LEFT. Reaction: nose goes RIGHT = CW = omega +.
    // Flame jets LEFT from left nozzle.
    ctx.fillStyle = p.dark;
    ctx.fillRect(-12, -6, 4, 4);
    if (this._thrustRcsL && this.fuel > 0) {
      ctx.fillStyle = p.warn;
      ctx.beginPath();
      ctx.moveTo(-12, -4);
      ctx.lineTo(-12 - (5 + Math.random() * 5), -2);
      ctx.lineTo(-12, -6 + 1);
      ctx.closePath();
      ctx.fill();
    }
    ctx.strokeStyle = (this._thrustRcsL && this.fuel > 0) ? p.warn : p.dim;
    ctx.lineWidth   = 0.8;
    ctx.strokeRect(-12, -6, 4, 4);

    // RIGHT RCS nozzle (body right side, upper area)
    // RIGHT button fires RIGHT nozzle to the RIGHT. Reaction: nose goes LEFT = CCW = omega -.
    // Flame jets RIGHT from right nozzle.
    ctx.fillStyle = p.dark;
    ctx.fillRect(8, -6, 4, 4);
    if (this._thrustRcsR && this.fuel > 0) {
      ctx.fillStyle = p.warn;
      ctx.beginPath();
      ctx.moveTo(12, -4);
      ctx.lineTo(12 + (5 + Math.random() * 5), -2);
      ctx.lineTo(12, -6 + 1);
      ctx.closePath();
      ctx.fill();
    }
    ctx.strokeStyle = (this._thrustRcsR && this.fuel > 0) ? p.warn : p.dim;
    ctx.lineWidth   = 0.8;
    ctx.strokeRect(8, -6, 4, 4);

    // Top attitude nozzle (visual reference)
    ctx.fillStyle   = p.dark;
    ctx.fillRect(-3, -14, 6, 4);
    ctx.strokeStyle = p.dim;
    ctx.lineWidth   = 0.8;
    ctx.strokeRect(-3, -14, 6, 4);

    ctx.restore();
  }

  // ---- HUD (top area, x >= 52 to clear the BACK button) ----
  _drawHUD(ctx) {
    const p = P();

    this.engine.text('LANDER', 52, 8, 16, p.fg, 'left');
    this.engine.text('ST.' + this.stage, 52, 26, 12, p.mid, 'left');
    this.engine.text('HI ' + (this.high || 0),      W - 8, 8,  12, p.dim, 'right');
    this.engine.text('TOT ' + this.totalScore,       W - 8, 22, 12, p.mid, 'right');

    // Fuel bar
    const bx = 52, by = 44, bw = 110, bh = 10;
    this.engine.rect(bx, by, bw, bh, p.dark);
    const fr   = Math.max(0, Math.min(1, (this.fuel || 0) / FUEL_MAX));
    const fclr = fr > 0.4 ? p.mid : fr > 0.15 ? p.warn : p.bad;
    if (fr > 0) this.engine.rect(bx, by, Math.round(bw * fr), bh, fclr);
    this.engine.stroke(bx, by, bw, bh, p.dim, 1);
    this.engine.text('FUEL', bx + bw + 4, by, 10, p.dim, 'left');

    if (this.state !== 'play') return;

    // Vertical speed
    const vy    = this.vy || 0;
    const vyclr = Math.abs(vy) <= SAFE_VY ? p.mid : Math.abs(vy) <= SAFE_VY * 1.6 ? p.warn : p.bad;
    this.engine.text('VY ' + Math.round(vy), W - 8, 38, 11, vyclr, 'right');

    // Horizontal speed
    const vx    = this.vx || 0;
    const vxclr = Math.abs(vx) <= SAFE_VX ? p.mid : Math.abs(vx) <= SAFE_VX * 2 ? p.warn : p.bad;
    this.engine.text('VX ' + Math.round(vx), W - 8, 52, 11, vxclr, 'right');

    // Angle
    const ang    = this.angle || 0;
    const absAng = Math.abs(((ang + 180) % 360 + 360) % 360 - 180);
    const aclr   = absAng <= SAFE_ANGLE ? p.mid : absAng <= SAFE_ANGLE * 2 ? p.warn : p.bad;
    this.engine.text('A ' + Math.round(ang) + '°', 52, 58, 11, aclr, 'left');

    // Angular velocity
    const om    = this.omega || 0;
    const omclr = Math.abs(om) <= SAFE_OMEGA ? p.mid : Math.abs(om) <= SAFE_OMEGA * 2 ? p.warn : p.bad;
    this.engine.text('ω ' + Math.round(om), W - 8, 66, 11, omclr, 'right');
  }

  // ---- Bottom button bar ----
  // Label convention (reaction-thruster):
  //   LEFT  button -> fires left nozzle -> nose tilts RIGHT (CW)
  //   RIGHT button -> fires right nozzle -> nose tilts LEFT (CCW)
  // Labels reflect the NOSE direction for clarity to the player.
  _drawButtons(ctx) {
    const p = P();

    const BW = 120;
    const bY = BTN_Y;
    const bH = BTN_H;

    const drawBtn = (bx, label, sublabel, active) => {
      ctx.fillStyle = active ? p.dim : p.dark;
      ctx.fillRect(bx, bY, BW, bH);

      ctx.strokeStyle = active ? p.hi : p.dim;
      ctx.lineWidth   = active ? 2.5 : 1.5;
      ctx.strokeRect(bx + 1, bY + 1, BW - 2, bH - 2);

      if (active) {
        ctx.fillStyle = p.hi;
        ctx.globalAlpha = Math.max(0, Math.min(1, 0.25));
        ctx.fillRect(bx + 2, bY + 2, BW - 4, 6);
        ctx.globalAlpha = 1;
      }

      const labelColor = active ? p.hi : p.fg;
      this.engine.text(label,    bx + BW / 2, bY + bH / 2 - 14, 13, labelColor, 'center');
      if (sublabel) {
        this.engine.text(sublabel, bx + BW / 2, bY + bH / 2 + 2,  10, active ? p.warn : p.dim, 'center');
      }
    };

    // LEFT button: nose tilts right (CW)    RIGHT button: nose tilts left (CCW)
    drawBtn(0,   '◄ TILT R',  'NOSE RIGHT', this._thrustRcsL);
    drawBtn(120, 'THRUST',    null,          this._thrustMain);
    drawBtn(240, 'TILT L ►', 'NOSE LEFT',  this._thrustRcsR);

    // Dividers
    ctx.strokeStyle = p.dim;
    ctx.lineWidth   = 1;
    ctx.beginPath(); ctx.moveTo(120, bY); ctx.lineTo(120, H); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(240, bY); ctx.lineTo(240, H); ctx.stroke();
  }

  // ---- Stage Clear overlay ----
  _drawClearScreen(ctx) {
    const p  = P();
    const cx = W / 2;
    const cy = H / 2;

    ctx.save();
    ctx.globalAlpha = Math.max(0, Math.min(1, 0.92));
    this.engine.rect(20, cy - 130, W - 40, 270, p.dark);
    this.engine.stroke(20, cy - 130, W - 40, 270, p.mid, 2);
    ctx.restore();

    this.engine.text('STAGE CLEAR!',                cx, cy - 116, 24, p.hi,   'center');
    this.engine.text('ST.' + this.stage + ' COMPLETE', cx, cy - 86, 13, p.mid, 'center');

    this.engine.text('STAGE SCORE',                 cx, cy - 62,  12, p.dim,  'center');
    this.engine.text('+' + (this._stageScore || 0), cx, cy - 46,  20, p.fg,   'center');
    this.engine.text('GUIDE BONUS +' + (this._guideBonus || 0), cx, cy - 22, 11, p.warn, 'center');

    ctx.strokeStyle = p.dim;
    ctx.lineWidth   = 1;
    ctx.beginPath(); ctx.moveTo(40, cy + 4); ctx.lineTo(W - 40, cy + 4); ctx.stroke();

    this.engine.text('TOTAL SCORE',                 cx, cy + 14,  12, p.dim,  'center');
    this.engine.text('' + this.totalScore,          cx, cy + 30,  24, p.hi,   'center');
    this.engine.text('BEST ' + (this.high || 0),    cx, cy + 60,  14, p.mid,  'center');

    this.engine.text('TAP → STAGE ' + (this.stage + 1), cx, cy + 90, 14, p.fg,  'center');
    this.engine.text('BACK → MENU', cx, cy + 110, 11, p.dim, 'center');
  }

  // ---- Game Over overlay ----
  _drawGameOver(ctx) {
    const p  = P();
    const cx = W / 2;
    const cy = H / 2;

    ctx.save();
    ctx.globalAlpha = Math.max(0, Math.min(1, 0.92));
    this.engine.rect(20, cy - 120, W - 40, 250, p.dark);
    this.engine.stroke(20, cy - 120, W - 40, 250, p.bad, 2);
    ctx.restore();

    this.engine.text('GAME OVER',               cx, cy - 106, 28, p.bad,  'center');
    this.engine.text('CRASHED! ST.' + this.stage, cx, cy - 74, 13, p.warn, 'center');

    ctx.strokeStyle = p.dim;
    ctx.lineWidth   = 1;
    ctx.beginPath(); ctx.moveTo(40, cy - 54); ctx.lineTo(W - 40, cy - 54); ctx.stroke();

    this.engine.text('FINAL SCORE',             cx, cy - 40,  12, p.dim,  'center');
    this.engine.text('' + this.totalScore,       cx, cy - 24,  26, p.fg,   'center');

    ctx.beginPath(); ctx.moveTo(40, cy + 8); ctx.lineTo(W - 40, cy + 8); ctx.stroke();

    this.engine.text('BEST',                    cx, cy + 18,  11, p.dim,  'center');
    this.engine.text('' + (this.high || 0),     cx, cy + 34,  22, p.hi,   'center');

    this.engine.text('TAP TO RETRY',            cx, cy + 68,  14, p.fg,   'center');
    this.engine.text('BACK → MENU',        cx, cy + 88,  11, p.dim,  'center');
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/main.js (bootstrap) ----
// エントリポイント。エンジンを起動し、全ゲームを登録してメニューを表示する。

// 各ゲーム（meta + Game）。新しいゲームはここに import を1行足すだけで追加できる。

const GAMES = __games;
window.addEventListener('load', () => {
  const canvas = document.getElementById('screen');
  const engine = new Engine(canvas);

  // メニュー／ゲーム間の遷移ヘルパーをエンジンに生やす
  engine.toMenu = () => engine.changeScene(new MenuScene(engine, GAMES));
  engine.startGame = (g) => engine.changeScene(new g.Game(engine));

  engine.start(new MenuScene(engine, GAMES));
});

})();
